/* AUTO-GENERATED — New Hampshire Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["NH"] = {"code":"NH","name":"New Hampshire","agency":"New Hampshire DMV","agencyShort":"DMV","handbook":"https://www.dmv.nh.gov/drivers-licensenon-driver-ids/commercial-driver-licenses","links":{},"en":[{"q":"On the ways of New Hampshire, what is the maximum width of a vehicle, including its load, before an over-dimension permit is required?","options":["96 inches","102 inches","108 inches","114 inches"],"answer":1,"explanation":"New Hampshire RSA 266:12 prohibits driving any vehicle whose width including load exceeds 102 inches (8 feet 6 inches). This matches the federal standard for the National Network. Source: NH RSA 266:12 Width; NH CDL Manual.","handbook":"","hbref":""},{"q":"What is the maximum height, including load, of a standard vehicle (not transporting manufactured housing) allowed on New Hampshire ways without a permit?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"answer":2,"explanation":"New Hampshire RSA 266:10 states no vehicle (except one transporting manufactured housing or modular buildings) whose total height including load is greater than 13 feet 6 inches may be driven on the ways of the state. Source: NH RSA 266:10 Height.","handbook":"","hbref":""},{"q":"In New Hampshire, what is the maximum length of a semi-trailer in a truck-tractor/semi-trailer combination operating without a permit?","options":["48 feet","50 feet","53 feet","57 feet"],"answer":2,"explanation":"New Hampshire RSA 266:11 permits a semi-trailer up to 53 feet in a truck-tractor and single semi-trailer combination (trailers over 48 feet have added kingpin and rear-protection requirements). Source: NH RSA 266:11 Length.","handbook":"","hbref":""},{"q":"Under New Hampshire law, what is the maximum gross vehicle weight (including all law-enforcement tolerances) for a combination vehicle with five or more axles operating without an overweight permit?","options":["73,280 pounds","80,000 pounds","84,000 pounds","90,000 pounds"],"answer":1,"explanation":"New Hampshire caps the maximum gross weight for a 5-or-more-axle combination at 80,000 pounds including all law-enforcement tolerances, consistent with the federal limit. Source: NH RSA 266:18 / 266:18-a.","handbook":"","hbref":""},{"q":"What is the maximum single-axle weight allowed on New Hampshire's Interstate and Defense Highway System without a permit?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"answer":1,"explanation":"On the Interstate and Defense Highway System, New Hampshire RSA 266:18 limits a single axle to 20,000 pounds, matching the federal Interstate standard. (Higher figures like 22,400 lb apply only to certain non-Interstate configurations.) Source: NH RSA 266:18.","handbook":"","hbref":""},{"q":"On New Hampshire's Interstate and Defense Highway System, what is the maximum weight allowed on a tandem axle?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"New Hampshire RSA 266:18 limits a tandem axle to 34,000 pounds on the Interstate and Defense Highway System, the same as the federal standard. Source: NH RSA 266:18.","handbook":"","hbref":""},{"q":"New Hampshire's overweight enforcement uses a weight-distribution formula relating gross weight to axle spacing and number of axles. This formula is commonly known as the:","options":["Federal bridge formula","Kingpin setback formula","Gross combination rating formula","Tare weight formula"],"answer":0,"explanation":"New Hampshire RSA 266:18 incorporates the federal bridge formula W = 500[LN/(N-1) + 12N + 36], where W is gross weight on a group of axles, L is the distance between extreme axles, and N is the number of axles. Source: NH RSA 266:18.","handbook":"","hbref":""},{"q":"In the New Hampshire bridge formula W = 500[LN/(N-1) + 12N + 36], what does the variable 'N' represent?","options":["The number of axles in the group","The net weight of the load","The number of trailers","The nominal tire width"],"answer":0,"explanation":"In the bridge formula adopted by New Hampshire (RSA 266:18), N equals the number of axles in the group under consideration; L is the distance in feet between the extreme axles, and W is the resulting allowable gross weight. Source: NH RSA 266:18.","handbook":"","hbref":""},{"q":"Triple-trailer truck combinations on the ways of New Hampshire are:","options":["Allowed only on Interstates","Allowed with an annual permit","Prohibited","Allowed at night only"],"answer":2,"explanation":"New Hampshire RSA 266:11-b prohibits the operation of triple-trailer trucks on the ways of the state. Source: NH RSA 266:11-b Triple Trailer Trucks Prohibited.","handbook":"","hbref":""},{"q":"A carrier needs to move a load that exceeds New Hampshire's legal size or weight limits. Which agency issues the required oversize/overweight permit?","options":["The local town road agent","The New Hampshire Department of Transportation","The Federal Motor Carrier Safety Administration","The county sheriff's office"],"answer":1,"explanation":"Oversize/overweight (OSOW) permits in New Hampshire are issued by the NH Department of Transportation through its permit office (applications online, in person at 7 Hazen Drive, Concord, or by phone). Source: NHDOT Permits / OSOW Permit Office.","handbook":"","hbref":""},{"q":"An oversize or overweight load in New Hampshire is generally permitted to travel during which hours?","options":["24 hours a day, any day","One-half hour before sunrise to one-half hour after sunset, Monday through Friday","Only between 9:00 p.m. and 5:00 a.m. daily","Weekends only, to avoid commuter traffic"],"answer":1,"explanation":"Under NHDOT OSOW permit rules, oversize/overweight loads may generally travel from one-half hour before sunrise to one-half hour after sunset, Monday through Friday, with weekend and holiday travel of overdimensional loads not allowed. Source: NHDOT OSOW Permit travel restrictions.","handbook":"","hbref":""},{"q":"What is the maximum length, including front and rear bumpers, of a single-unit vehicle or bus on New Hampshire ways without a permit?","options":["40 feet","45 feet","48 feet","53 feet"],"answer":1,"explanation":"New Hampshire RSA 266:11 limits a single-unit vehicle or bus to 45 feet including front and rear bumpers. Source: NH RSA 266:11 Length.","handbook":"","hbref":""},{"q":"When a vehicle is transporting manufactured housing or modular buildings in New Hampshire, the maximum allowable height is:","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"answer":2,"explanation":"New Hampshire RSA 266:10 allows a maximum height of 14 feet 6 inches for vehicles transporting manufactured housing or modular buildings; loads exceeding 13 feet 6 inches require a non-police escort. Source: NH RSA 266:10 Height.","handbook":"","hbref":""},{"q":"On New Hampshire's non-Interstate (general) highway system, a single axle on a 3-axle single-unit vehicle may carry a maximum of:","options":["18,000 pounds","20,000 pounds","22,400 pounds","25,000 pounds"],"answer":2,"explanation":"New Hampshire RSA 266:18-a permits up to 22,400 pounds per axle on 3-axle single-unit vehicles (and other vehicles with axles 10 feet or more apart) on the non-Interstate general highway system, which is higher than the 20,000-pound Interstate limit. Source: NH RSA 266:18-a.","handbook":"","hbref":""},{"q":"For a truck-tractor and single semi-trailer combination with four or more axles carrying raw forestry products in New Hampshire, the maximum weight on a tandem axle is increased to:","options":["34,000 pounds","36,000 pounds","40,000 pounds","44,000 pounds"],"answer":2,"explanation":"New Hampshire RSA 266:18-b allows a tandem axle to carry up to 40,000 pounds for a truck-tractor and single semi-trailer combination of 4 or more axles carrying raw forestry products (unprocessed logs and wood chips). Source: NH RSA 266:18-b.","handbook":"","hbref":""},{"q":"New Hampshire law authorizes enforcement officers to allow what general tolerance above the posted axle-group and gross weight limits before issuing a violation?","options":["1 percent","2 percent","5 percent","15 percent"],"answer":2,"explanation":"New Hampshire RSA 266:18-a and 266:18-c authorize a tolerance of 5 percent above the stated weight limitations (with up to 10 percent allowed on certain axle weights under 266:18-c). Source: NH RSA 266:18-a / 266:18-c.","handbook":"","hbref":""},{"q":"On the Interstate system, two consecutive sets of tandem axles in New Hampshire may each carry 34,000 pounds only if the distance between the first and last axles of those tandem sets is at least:","options":["28 feet","30 feet","36 feet","40 feet"],"answer":2,"explanation":"New Hampshire RSA 266:18 allows two consecutive tandem-axle sets to carry 34,000 pounds each only if the overall distance between the first and last axles is 36 feet or more, and total gross weight does not exceed 80,000 pounds. Source: NH RSA 266:18.","handbook":"","hbref":""},{"q":"On New Hampshire's non-Interstate general highway system, what is the maximum tandem-axle weight for a five-or-more-axle combination?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":2,"explanation":"New Hampshire RSA 266:18-a permits a tandem axle on a 5-or-more-axle combination on the non-Interstate general highway system to carry up to 36,000 pounds, higher than the 34,000-pound Interstate tandem limit. Source: NH RSA 266:18-a.","handbook":"","hbref":""},{"q":"A New Hampshire-based carrier wants an annual oversize permit for statewide travel of a vehicle no greater than 75 feet long, 10 feet 6 inches wide, and 13 feet 6 inches high. What is the stated annual permit fee for statewide travel?","options":["$60.00","$115.00","$200.00","$300.00"],"answer":1,"explanation":"NHDOT lists the annual oversize permit fee as $115.00 for statewide travel (or $60.00 for travel within a 100-mile radius) for NH-based and registered carriers, for vehicles within the stated 75 ft / 10 ft 6 in / 13 ft 6 in limits. Source: NHDOT OSOW Permit fees.","handbook":"","hbref":""},{"q":"Under New Hampshire RSA 266:16, the penalty for a first offense of operating a vehicle exceeding the permitted size limits is a fine of:","options":["Not more than $100","Not more than $250","Not more than $500","Not more than $1,000"],"answer":0,"explanation":"New Hampshire RSA 266:16 sets the penalty for exceeding permitted size at a fine of not more than $100 for a first offense and not more than $250 for a subsequent offense within the same calendar year. Source: NH RSA 266:16 Penalty for Exceeding Permitted Size.","handbook":"","hbref":""},{"q":"Under New Hampshire CDL rules, which license class is required to drive a combination of vehicles with a gross combination weight rating (GCWR) of 26,001 pounds or more, provided the unit being towed has a GVWR over 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"New Hampshire defines a Class A CDL as any combination of vehicles with a GCWR of 26,001 lbs or more where the towed unit's GVWR exceeds 10,000 lbs. Source: NH DMV License Classifications, Restrictions and Endorsements page; NH Commercial Driver's Manual.","handbook":"","hbref":""},{"q":"In New Hampshire, which CDL class covers any SINGLE vehicle with a GVWR of 26,001 pounds or more, or such a vehicle towing a unit not in excess of 10,000 pounds GVWR?","options":["Class A","Class B","Class C","Class M"],"answer":1,"explanation":"NH defines a Class B CDL as a single vehicle with a GVWR of 26,001 lbs or more, or such a vehicle towing a unit not over 10,000 lbs GVWR. Source: NH DMV License Classifications page; NH Commercial Driver's Manual.","handbook":"","hbref":""},{"q":"A New Hampshire driver operates a single vehicle under 26,001 lbs that is designed to carry 18 passengers including the driver. Which CDL class does this require?","options":["Class A","Class B","Class C","No CDL is required"],"answer":2,"explanation":"NH defines a Class C CDL as a vehicle not meeting Class A or B that transports 16 or more passengers (including the driver), is placarded for hazardous materials, or is a tank vehicle. An 18-passenger vehicle falls under Class C. Source: NH DMV License Classifications page.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a New Hampshire CDL restricted to INTRASTATE (within New Hampshire only) operation?","options":["16 years old","18 years old","21 years old","25 years old"],"answer":1,"explanation":"In New Hampshire you must be at least 18 to operate a commercial motor vehicle intrastate (within NH). Source: NH DMV Commercial Driver Licenses page; NH Commercial Driver's Manual.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a New Hampshire CDL valid for INTERSTATE (across state lines) commercial driving?","options":["18 years old","19 years old","21 years old","23 years old"],"answer":2,"explanation":"New Hampshire (following the federal standard) requires drivers to be at least 21 to operate a commercial motor vehicle in interstate commerce. Drivers 18-20 are restricted to intrastate operation. Source: NH DMV Commercial Driver Licenses page.","handbook":"","hbref":""},{"q":"Under New Hampshire and federal rules, how long must an applicant hold a Commercial Learner Permit (CLP) before being allowed to take the CDL skills (road) test?","options":["7 days","10 days","14 days","30 days"],"answer":2,"explanation":"An applicant must hold the CLP for at least 14 days before taking the CDL skills test. This is a federal requirement enforced by NH. Source: NH DMV Commercial Driver Learner Permit page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"When a New Hampshire Commercial Driver Learner Permit holder drives a commercial motor vehicle, who must accompany them?","options":["Any licensed driver age 18 or older","A person 25 or older holding a CDL valid for that vehicle type, seated immediately next to the permit holder","Any CDL holder seated anywhere in the vehicle","A New Hampshire DMV examiner only"],"answer":1,"explanation":"NH requires the CLP holder to be accompanied by a person 25 years of age or older who holds a CDL valid for the type of vehicle being driven and who occupies the seat immediately adjacent to the permit holder. Source: NH DMV Commercial Driver Learner Permit page.","handbook":"","hbref":""},{"q":"Which endorsement code is required on a New Hampshire CDL to transport hazardous materials in amounts that require placarding?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"answer":1,"explanation":"The H (HazMat) endorsement is required to drive any commercial vehicle transporting hazardous materials that must be placarded under state or federal regulations. Source: NH DMV HazMat Endorsement page.","handbook":"","hbref":""},{"q":"Before a New Hampshire driver can be issued the HazMat (H) endorsement, which additional screening is federally required?","options":["A TSA security threat assessment (fingerprint-based background check)","An FBI polygraph examination","A New Hampshire State Police interview","A DOT drug test only"],"answer":0,"explanation":"Applicants for the H endorsement must pass a Transportation Security Administration (TSA) security threat assessment, which includes a fingerprint-based background check, in addition to the HazMat knowledge test. Source: NH DMV HazMat Endorsement page; 49 CFR 1572.","handbook":"","hbref":""},{"q":"On a New Hampshire CDL, which endorsement is required to operate a tank vehicle (used to carry liquids or gases in bulk)?","options":["H endorsement","T endorsement","N endorsement","P endorsement"],"answer":2,"explanation":"The N (Tank Vehicle) endorsement is required to operate a tank vehicle designed to transport liquids or gases in bulk. Source: NH DMV License Classifications, Restrictions and Endorsements page.","handbook":"","hbref":""},{"q":"Which New Hampshire CDL endorsement is required to pull double or triple trailers?","options":["T endorsement","N endorsement","D endorsement","X endorsement"],"answer":0,"explanation":"The T endorsement (Doubles/Triples) is required to tow double or triple trailers. It is obtained by passing a knowledge test; no separate skills test is required for it. Source: NH DMV License Classifications page; NH Commercial Driver's Manual.","handbook":"","hbref":""},{"q":"Which endorsement does New Hampshire require to drive a commercial vehicle designed to transport 16 or more passengers, including the driver?","options":["S endorsement","P endorsement","N endorsement","T endorsement"],"answer":1,"explanation":"The P (Passenger) endorsement is required to drive any commercial vehicle designed to transport 16 or more passengers including the driver. Source: NH DMV Commercial Driver Licenses page.","handbook":"","hbref":""},{"q":"To obtain the New Hampshire School Bus (S) endorsement, what does the applicant generally also need?","options":["A HazMat (H) endorsement","A Tank (N) endorsement","A Passenger (P) endorsement","A Doubles/Triples (T) endorsement"],"answer":2,"explanation":"A school bus carries 16 or more occupants, so NH requires the Passenger (P) endorsement in addition to passing the School Bus (S) knowledge test and a passenger-vehicle road skills test. Source: NH DMV School Bus Drivers page.","handbook":"","hbref":""},{"q":"What minimum passing score does New Hampshire require on the CDL general knowledge written test to qualify for a Commercial Learner Permit?","options":["70%","75%","80%","90%"],"answer":2,"explanation":"New Hampshire requires a score of 80% or higher on the CDL knowledge examinations, including the general knowledge test. Source: NH DMV Commercial Driver Learner Permit page; NH Commercial Driver's Manual.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) taken before certain New Hampshire CDL skills/knowledge tests must be completed through what?","options":["Any New Hampshire community college","A provider listed on the FMCSA Training Provider Registry (TPR)","The New Hampshire DMV's own training division","Any employer-run program, no registration needed"],"answer":1,"explanation":"ELDT must be completed through a provider listed on the FMCSA Training Provider Registry (TPR); the provider self-certifies and submits completion records to FMCSA. Source: FMCSA ELDT / Training Provider Registry; NH DMV CDL pages.","handbook":"","hbref":""},{"q":"Which of the following requires ELDT (Entry-Level Driver Training) before a New Hampshire applicant may take the corresponding test?","options":["Adding a Doubles/Triples (T) endorsement","Adding a Tank (N) endorsement","Obtaining a Class A CDL for the first time","Renewing an existing Class B CDL with no class change"],"answer":2,"explanation":"Federal ELDT rules (effective Feb. 7, 2022) apply to obtaining a Class A or B CDL for the first time, upgrading Class B to Class A, and obtaining an H, P, or S endorsement for the first time. The N and T endorsements and simple renewals do not require ELDT. Source: FMCSA ELDT regulations; NH DMV CDL pages.","handbook":"","hbref":""},{"q":"When applying for a New Hampshire CDL, which self-certification category indicates a driver who operates across state lines and must meet the federal DOT medical certificate requirement?","options":["Interstate non-excepted","Intrastate excepted","Interstate excepted","Intrastate non-excepted"],"answer":0,"explanation":"NH uses the four federal self-certification categories. 'Interstate non-excepted' covers drivers operating across state lines who must hold a valid DOT medical certificate on file. Source: NH DMV CDL Medical Card Update page; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"To apply for a New Hampshire CDL or Commercial Learner Permit, an applicant must generally present proof of which combination of documents?","options":["Identity only","Identity and Social Security Number only","Identity, Social Security Number, and New Hampshire residency/lawful presence","A passport only, which covers all requirements"],"answer":2,"explanation":"New Hampshire requires applicants to prove identity, provide a document showing the Social Security Number, and provide documents establishing NH residency and lawful presence. Source: NH DMV Required Documents / Commercial Driver Learner Permit pages.","handbook":"","hbref":""},{"q":"How long is a New Hampshire Commercial Driver Learner Permit (CLP) valid before it must be renewed?","options":["30 days","60 days","180 days","365 days"],"answer":2,"explanation":"A New Hampshire CLP is valid for 180 days and may be renewed one time, provided the required knowledge tests were passed within a one-year period. This follows the federal CLP validity standard. Source: NH DMV Commercial Driver Learner Permit page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"A 19-year-old New Hampshire resident wants a CDL. Which privilege are they NOT eligible for until they turn 21?","options":["Holding a Class B CDL","Operating intrastate within New Hampshire","Obtaining a HazMat (H) endorsement","Obtaining a Tank (N) endorsement"],"answer":2,"explanation":"New Hampshire applicants under 21 are restricted to intrastate operation and cannot obtain the HazMat (H) or Passenger-for-interstate privileges; the H endorsement specifically requires the applicant to be at least 21. Source: NH DMV Commercial Driver Licenses / HazMat Endorsement pages.","handbook":"","hbref":""},{"q":"In New Hampshire, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.04","0.08","0.02","0.10"],"answer":0,"explanation":"New Hampshire sets the BAC limit for operating a CMV at 0.04, half the 0.08 limit for non-commercial drivers. Source: NH CDL Manual (alcohol/drugs section); RSA 265-A:2.","handbook":"","hbref":""},{"q":"By driving a commercial motor vehicle on New Hampshire roads, a CDL holder is legally deemed to have done what regarding chemical testing for alcohol or drugs?","options":["Given implied consent to submit to testing if lawfully requested","Waived any future right to a CDL","Agreed to pay a fixed $500 testing fee","Consented only to a breath test but not blood"],"answer":0,"explanation":"Under New Hampshire's implied-consent law, anyone who drives in the state is deemed to have consented to chemical testing to determine alcohol concentration when lawfully requested. Source: RSA 265-A:4; NH CDL Manual.","handbook":"","hbref":""},{"q":"For a first major offense (such as a DUI in a CMV), what is the minimum CDL disqualification period in New Hampshire?","options":["1 year","60 days","6 months","3 years"],"answer":0,"explanation":"A first major offense disqualifies a driver from operating a CMV for not less than one year in New Hampshire. Source: RSA 263:94; 49 CFR 383.51; NH CDL Manual.","handbook":"","hbref":""},{"q":"If a New Hampshire driver commits a first major offense while operating a CMV placarded for hazardous materials, the minimum disqualification is:","options":["3 years","1 year","120 days","Lifetime"],"answer":0,"explanation":"A first major offense committed while transporting placarded hazardous materials raises the minimum disqualification from one year to three years. Source: RSA 263:94; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification period in New Hampshire for a second major offense (e.g., a second DUI in a CMV) arising from a separate incident?","options":["Life","10 years","5 years","3 years"],"answer":0,"explanation":"A second conviction for a major offense from a separate incident results in lifetime disqualification from operating a CMV. Source: RSA 263:94; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A New Hampshire CDL holder refuses to submit to chemical testing while operating a CMV. For a first refusal, the minimum CDL disqualification is:","options":["1 year","90 days","6 months","30 days"],"answer":0,"explanation":"Refusing a lawfully requested chemical test is treated as a major offense; a first refusal carries a minimum one-year CDL disqualification (three years if placarded for hazmat). Source: RSA 263:94; RSA 265-A:4.","handbook":"","hbref":""},{"q":"If a New Hampshire CDL holder refuses chemical testing a second time (a separate incident), the CDL disqualification is:","options":["Life","5 years","2 years","1 year"],"answer":0,"explanation":"A second instance of refusing chemical testing, like any second major offense, results in lifetime CDL disqualification. Source: RSA 263:94; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In New Hampshire, being convicted of TWO serious traffic violations in a CMV arising from separate incidents within 3 years results in a CDL disqualification of at least:","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"Two serious traffic violations within a 3-year period disqualify a driver from operating a CMV for not less than 60 days. Source: RSA 263:94; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Being convicted of THREE serious traffic violations in a CMV from separate incidents within 3 years results in a New Hampshire CDL disqualification of at least:","options":["120 days","60 days","90 days","1 year"],"answer":0,"explanation":"Three serious traffic violations within a 3-year period disqualify a driver from operating a CMV for not less than 120 days. Source: RSA 263:94; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under New Hampshire's CDL rules, at what speed over the posted limit does a single speeding offense become a 'serious traffic violation'?","options":["15 mph or more over the limit","10 mph or more over the limit","20 mph or more over the limit","25 mph or more over the limit"],"answer":0,"explanation":"Speeding 15 mph or more above the posted limit is defined as a serious traffic violation for CDL purposes in New Hampshire. Source: RSA 259:98-a; N.H. Admin. Code Saf-C 1809.02.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' for a New Hampshire CDL holder?","options":["Following too closely (tailgating)","Parking in a fire lane","Driving 5 mph over the limit","An expired registration sticker"],"answer":0,"explanation":"Following too closely is one of the enumerated serious traffic violations for CDL holders, along with reckless driving, erratic lane changes, and excessive speeding. Source: RSA 259:98-a; Saf-C 1809.02.","handbook":"","hbref":""},{"q":"For a FIRST conviction of a railroad-highway grade crossing violation while operating a CMV in New Hampshire, the minimum disqualification is:","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A first railroad-highway grade crossing violation in a CMV carries a minimum 60-day disqualification. Source: 49 CFR 383.51 Table 3, adopted by New Hampshire; NH CDL Manual.","handbook":"","hbref":""},{"q":"A SECOND railroad-highway grade crossing violation in a CMV within 3 years results in a New Hampshire CDL disqualification of at least:","options":["120 days","60 days","90 days","1 year"],"answer":0,"explanation":"A second grade-crossing violation within 3 years carries a minimum 120-day disqualification. Source: 49 CFR 383.51 Table 3, adopted by New Hampshire.","handbook":"","hbref":""},{"q":"A THIRD or subsequent railroad-highway grade crossing violation in a CMV within 3 years results in a New Hampshire CDL disqualification of at least:","options":["1 year","120 days","180 days","60 days"],"answer":0,"explanation":"A third or subsequent grade-crossing violation within 3 years carries a minimum disqualification of 1 year. Source: 49 CFR 383.51 Table 3, adopted by New Hampshire.","handbook":"","hbref":""},{"q":"In New Hampshire, the FIRST violation of driving a CMV while under an out-of-service (OOS) order (non-hazmat) results in a disqualification of:","options":["No less than 180 days and no more than 1 year","No less than 60 days and no more than 120 days","No less than 30 days and no more than 90 days","No less than 2 years and no more than 5 years"],"answer":0,"explanation":"A first out-of-service order violation disqualifies the driver for not less than 180 days and not more than 1 year. Source: 49 CFR 383.51 Table 4, adopted by New Hampshire; NH CDL Manual.","handbook":"","hbref":""},{"q":"A SECOND out-of-service (OOS) order violation in a CMV within 10 years results in a New Hampshire disqualification of:","options":["No less than 2 years and no more than 5 years","No less than 180 days and no more than 1 year","No less than 1 year and no more than 3 years","Life"],"answer":0,"explanation":"A second OOS order violation within 10 years carries a disqualification of not less than 2 years and not more than 5 years. Source: 49 CFR 383.51 Table 4, adopted by New Hampshire.","handbook":"","hbref":""},{"q":"A driver hauling placarded hazardous materials or operating a vehicle designed for 16+ passengers commits a FIRST out-of-service order violation in New Hampshire. The disqualification is:","options":["No less than 180 days and no more than 2 years","No less than 180 days and no more than 1 year","No less than 60 days and no more than 120 days","No less than 3 years and no more than 5 years"],"answer":0,"explanation":"A first OOS violation while transporting placarded hazmat or in a 16+ passenger vehicle carries an elevated period of not less than 180 days and not more than 2 years. Source: 49 CFR 383.51 Table 4, adopted by New Hampshire.","handbook":"","hbref":""},{"q":"Under New Hampshire's hands-free law, what is the fine for a FIRST offense of using a handheld mobile electronic device while driving?","options":["$100","$50","$250","$500"],"answer":0,"explanation":"New Hampshire's hands-free law fines a first offense $100, a second $250, and any subsequent offense within 24 months $500. Handheld use is prohibited for all drivers, including CMV operators. Source: RSA 265:79-c.","handbook":"","hbref":""},{"q":"Under New Hampshire's hands-free law (RSA 265:79-c), what is the fine for a SECOND offense of using a handheld electronic device while driving?","options":["$250","$100","$500","$150"],"answer":0,"explanation":"A second offense of New Hampshire's hands-free law is fined $250 (a first offense is $100 and a subsequent offense within 24 months is $500). Source: RSA 265:79-c.","handbook":"","hbref":""},{"q":"For counting first and subsequent CDL disqualifying offenses in New Hampshire, convictions are tallied based on which rule?","options":["Each conviction from a separate incident counts, whether committed in a CMV or a non-CMV","Only convictions while driving a CMV count","Only convictions within the past 12 months count","Only convictions resulting in jail time count"],"answer":0,"explanation":"For determining first and subsequent disqualifying violations, each conviction from a separate incident counts, whether the offense occurred in a commercial or non-commercial vehicle. Source: RSA 263:94; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under New Hampshire's Move Over law, what must a CDL driver do when approaching a stopped vehicle on the shoulder displaying blue, red, or amber warning lights?","options":["Reduce speed and, if practical, move over to give the vehicle a wide berth","Maintain speed but sound the horn continuously while passing","Come to a complete stop in the travel lane until the vehicle leaves","Continue at the posted speed because the law applies only to police cruisers"],"answer":0,"explanation":"New Hampshire's Move Over law (RSA 265:37-a) requires a driver to maintain a reduced speed and, if practical, give a wide berth to public safety personnel and to any stopped vehicle displaying blue, red, or amber emergency or warning lights, moving out of a blocked lane when safe. Source: NH RSA 265:37-a; NH CDL Manual.","handbook":"","hbref":""},{"q":"In New Hampshire, before crossing railroad tracks a placarded hazardous-materials vehicle or a school bus carrying children must stop within what distance of the nearest rail?","options":["Not less than 15 feet nor more than 50 feet","Not less than 5 feet nor more than 25 feet","Not less than 25 feet nor more than 75 feet","Not less than 50 feet nor more than 100 feet"],"answer":0,"explanation":"RSA 265:50 requires drivers of buses carrying passengers, school buses carrying children, and vehicles carrying explosive/hazardous substances to stop within 50 feet but not less than 15 feet of the nearest rail, then look and listen before proceeding. Source: NH RSA 265:50; NH CDL Manual.","handbook":"","hbref":""},{"q":"On a New Hampshire two-lane road, a driver meeting or overtaking a stopped school bus with its red lights flashing must stop the vehicle at least how far from the bus?","options":["At least 25 feet away","At least 10 feet away","At least 50 feet away","At least 100 feet away"],"answer":0,"explanation":"RSA 265:54 requires a driver meeting or overtaking a stopped school bus that is receiving or discharging children to stop at least 25 feet from the bus and remain stopped until the bus resumes motion or the lights stop flashing. Source: NH RSA 265:54.","handbook":"","hbref":""},{"q":"On a New Hampshire divided highway with separate roadways, when does a CDL driver NOT have to stop for a school bus loading children?","options":["When the bus is on the other half of the divided highway traveling in the opposite direction","Never — a stop is always required for a school bus with flashing red lights","Only when the driver is operating an empty straight truck","Whenever the driver is traveling faster than 45 mph"],"answer":0,"explanation":"RSA 265:54 provides that a driver on a divided highway with separate roadways need not stop when meeting or passing a school bus that is on the other half of the divided highway traveling in the opposite direction. On an undivided road, all directions must stop. Source: NH RSA 265:54.","handbook":"","hbref":""},{"q":"What is the general maximum speed limit on New Hampshire interstate highways and turnpikes that are four-lane divided highways (outside the higher-limit I-93 segment)?","options":["65 mph","55 mph","70 mph","75 mph"],"answer":0,"explanation":"RSA 265:60 sets a maximum of 65 mph on the interstate system and the central and eastern New Hampshire turnpikes where they are four-lane divided highways. New Hampshire applies the same posted limits to trucks as to cars. Source: NH RSA 265:60.","handbook":"","hbref":""},{"q":"On which New Hampshire roadway is the posted speed limit 70 mph, the highest in the state?","options":["I-93 from mile marker 45 to the Vermont border","The entire length of I-95 (Blue Star Turnpike)","The Spaulding Turnpike from Portsmouth to Milton","I-89 from Concord to the Vermont border"],"answer":0,"explanation":"RSA 265:60 sets the speed limit at 70 mph on I-93 from mile marker 45 to the Vermont border. This is the highest posted limit in New Hampshire and applies to commercial vehicles as well. Source: NH RSA 265:60.","handbook":"","hbref":""},{"q":"Does New Hampshire post a lower speed limit for trucks than for passenger cars on its interstates?","options":["No — trucks must obey the same posted limit as all other vehicles","Yes — trucks are limited to 55 mph where cars may go 65 mph","Yes — trucks are limited to 60 mph statewide","Yes — trucks are limited to 45 mph on all divided highways"],"answer":0,"explanation":"New Hampshire's speed statute (RSA 265:60) sets maximum limits that apply to all vehicles and does not establish a separate, lower truck speed limit; commercial vehicles obey the same posted limits as cars. Source: NH RSA 265:60.","handbook":"","hbref":""},{"q":"Under New Hampshire law, what is required of a slow-moving truck on a multilane roadway regarding lane position?","options":["It must keep to the right-hand lane and not continuously occupy the left lane in a way that impedes traffic","It may stay in the left lane indefinitely as long as it signals","It must use only the center lane on any three-lane highway","It is exempt from keep-right rules because of its size"],"answer":0,"explanation":"RSA 265:16 requires a vehicle proceeding slower than normal traffic to keep to the right-hand lane and prohibits operating continuously in the left lane of a multilane roadway when it impedes the flow of traffic. Source: NH RSA 265:16.","handbook":"","hbref":""},{"q":"New Hampshire requires every truck or bus over 10,000 pounds to carry which type of emergency warning devices for use when stopped on the highway?","options":["Three bidirectional reflective warning devices (reflective triangles)","Two burning liquid-fuel lanterns","A single battery-powered strobe beacon","Four red cloth flags on poles"],"answer":0,"explanation":"RSA 265:113 requires every truck, bus, or truck-tractor over 10,000 pounds GVW to carry three bidirectional reflective warning devices approved by the director, consistent with federal motor carrier safety regulations. Source: NH RSA 265:113; NH CDL Manual.","handbook":"","hbref":""},{"q":"When a New Hampshire commercial vehicle over 10,000 pounds is stopped on a two-lane highway, where should the three warning devices generally be placed?","options":["About 10 feet behind the vehicle, 100 feet to the rear, and 100 feet to the front","All three within 10 feet of the rear bumper","One 25 feet ahead and two 25 feet behind","200 feet ahead, 200 feet behind, and one on the roof"],"answer":0,"explanation":"Under RSA 265:113, on an ordinary two-way road the devices are placed about 10 feet from the vehicle on the traffic side, 100 feet to the rear, and 100 feet to the front. On a divided or one-way road the spacing is 10, 100, and 200 feet toward approaching traffic. Source: NH RSA 265:113; NH CDL Manual.","handbook":"","hbref":""},{"q":"After stopping for a railroad crossing in New Hampshire, what does the law require of a bus or hazmat driver while actually crossing the tracks?","options":["Cross in a gear low enough that there is no need to shift gears while on the tracks","Accelerate hard and shift up quickly to clear the tracks fastest","Shift to neutral and coast across the tracks","Engage the parking brake briefly at the midpoint of the crossing"],"answer":0,"explanation":"RSA 265:50 directs that, after stopping and when it is safe to proceed, the driver must cross in such a gear that there is no necessity for changing gears while crossing, and shall not shift gears while on the tracks. Source: NH RSA 265:50.","handbook":"","hbref":""},{"q":"What is New Hampshire's penalty structure for a first offense of failing to obey the Move Over law (RSA 265:37-a)?","options":["$75 plus penalty assessment for a first offense","$250 plus a 30-day license suspension for a first offense","$500 plus mandatory CDL disqualification","A written warning only for the first offense"],"answer":0,"explanation":"Under RSA 265:37-a, a first violation of New Hampshire's Move Over law carries a fine of $75 plus penalty assessment, increasing to $250 plus assessment for a subsequent offense within 12 months. Source: NH RSA 265:37-a.","handbook":"","hbref":""},{"q":"Without an oversize permit, what is the maximum legal width of a commercial vehicle on New Hampshire highways?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 6 inches"],"answer":0,"explanation":"New Hampshire follows the federal legal width limit of 8 feet 6 inches (102 inches); anything wider requires an oversize permit from NHDOT. Source: NH DOT oversize/overweight permit rules; NH State Police Troop G motor carrier guidance.","handbook":"","hbref":""},{"q":"Without an overweight permit, what is the maximum legal gross vehicle weight for a commercial vehicle on New Hampshire highways?","options":["80,000 pounds","73,280 pounds","90,000 pounds","100,000 pounds"],"answer":0,"explanation":"New Hampshire's legal maximum gross vehicle weight is 80,000 pounds on both interstate and other highways; exceeding it requires an overweight permit/certification through NHDOT. Source: NH DOT oversize/overweight permit rules; NH State Police Troop G.","handbook":"","hbref":""},{"q":"Without a permit, what is the maximum legal height of a commercial vehicle on New Hampshire roads?","options":["13 feet 6 inches","12 feet 6 inches","14 feet 0 inches","13 feet 0 inches"],"answer":0,"explanation":"New Hampshire's legal maximum vehicle height is 13 feet 6 inches on all road types; a taller load requires an oversize permit from NHDOT. Source: NH DOT oversize/overweight permit rules.","handbook":"","hbref":""},{"q":"On the Franconia Notch Parkway portion of I-93 in New Hampshire, what is distinctive for commercial drivers compared with the rest of the interstate?","options":["It narrows to a single lane in each direction with a reduced 45 mph limit","It has a dedicated truck-only express lane in each direction","It permits an 80 mph limit for through trucks","It bans all passenger cars during daylight hours"],"answer":0,"explanation":"The Franconia Notch Parkway segment of I-93 was built under a special exception to interstate standards and narrows to a single lane each direction with a posted 45 mph limit, requiring extra caution from CMVs on the grade. Source: NH DOT; NH RSA 265:60 reduced-zone authority.","handbook":"","hbref":""},{"q":"Which agency issues oversize/overweight permits for commercial vehicles exceeding legal limits in New Hampshire?","options":["The New Hampshire Department of Transportation (NHDOT)","The Federal Highway Administration regional office","The local police department of each town crossed","The New Hampshire Liquor Commission"],"answer":0,"explanation":"Oversize and overweight permits in New Hampshire are issued by the New Hampshire Department of Transportation (NHDOT) permit office; loads exceeding legal size or weight must be permitted and may be route-restricted. Source: NH DOT oversize/overweight permit office.","handbook":"","hbref":""},{"q":"Under New Hampshire law, when a school bus is moving and is followed by how many or more vehicles must the bus driver pull over to let them pass when conditions permit?","options":["5 or more following vehicles","3 or more following vehicles","10 or more following vehicles","2 or more following vehicles"],"answer":0,"explanation":"RSA 265:54 directs that whenever road conditions and space permit and the number of vehicles following a moving school bus is 5 or more, the bus driver shall pull over to let the following vehicles pass. Source: NH RSA 265:54.","handbook":"","hbref":""},{"q":"In New Hampshire, what must a driver do when approaching a transit or motorcoach bus that has stopped to let passengers board or alight (and is not a school bus showing red flashers)?","options":["Slow down and, if necessary for public safety, come to a full stop","Pass at full speed because only school buses require caution","Stop at least 100 feet back regardless of conditions","Sound the horn three times and proceed without slowing"],"answer":0,"explanation":"RSA 265:55 requires a driver approaching or passing a bus, streetcar, or other passenger vehicle stopped to load or unload passengers to slow down and, if necessary for the safety of the public, bring the vehicle to a full stop. Source: NH RSA 265:55.","handbook":"","hbref":""},{"q":"A CDL driver is meeting a stopped school bus with red lights flashing on an undivided New Hampshire highway. The driver may resume travel when:","options":["The bus resumes motion or the red flashing lights are turned off","Three seconds have passed since stopping, regardless of the lights","The driver judges no children are visible, even if lights still flash","The bus driver waves, even though the red lights remain on"],"answer":0,"explanation":"Under RSA 265:54, a driver stopped for a school bus on an undivided road must remain stopped until the bus resumes motion or the flashing red lights are turned off; a first violation is a $150 fine plus assessment with possible license suspension. Source: NH RSA 265:54.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver Licenses (CDLs) in New Hampshire?","options":["The New Hampshire Division of Motor Vehicles (DMV)","The Federal Motor Carrier Safety Administration (FMCSA)","The New Hampshire Department of Transportation (NHDOT)","The New Hampshire State Police Commercial Bureau"],"answer":0,"explanation":"In New Hampshire, CDLs are issued by the New Hampshire Division of Motor Vehicles (DMV), which administers testing and licensing under federal FMCSA standards. NHDOT handles roads and oversize/overweight permits, not licensing. Source: NH DMV, Commercial Driver Licenses page.","handbook":"","hbref":""},{"q":"Before a New Hampshire applicant may schedule the CDL skills (road) test, what federal training must they complete?","options":["Entry-Level Driver Training (ELDT) from a registered provider","A 160-hour state apprenticeship program","A defensive-driving course approved by the NH DMV","An OSHA commercial-vehicle safety certification"],"answer":0,"explanation":"New Hampshire follows the federal ELDT rule: applicants must complete Entry-Level Driver Training from an FMCSA Training Provider Registry provider before they can schedule the CDL skills test. Source: NH DMV, Commercial Driver Learner Permit page; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"After a New Hampshire CLP is issued, how long must the holder wait before the CDL road (skills) test may be scheduled?","options":["At least 14 days","At least 10 days","At least 30 days","At least 7 days"],"answer":0,"explanation":"New Hampshire applies the federal 14-day hold: after passing the knowledge exams and being issued the CLP, the road examination may be scheduled no sooner than 14 days from the date the CLP was issued. Source: NH DMV, Commercial Driver Learner Permit page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"The New Hampshire CDL skills test consists of three separate parts. Which set correctly lists them?","options":["Pre-trip inspection, basic vehicle control, and on-road driving","Written knowledge, vision screening, and on-road driving","Pre-trip inspection, air-brake demonstration, and night driving","Coupling/uncoupling, backing, and a written endorsement exam"],"answer":0,"explanation":"The New Hampshire CDL skills test has three parts: the pre-trip (vehicle) inspection, the basic vehicle control skills test, and the on-road driving test. The knowledge and vision tests are separate prerequisites, not part of the skills test. Source: NH DMV, CDL Road Test page.","handbook":"","hbref":""},{"q":"On New Hampshire's self-certification for CDL applicants, how many categories of commercial operation must the driver choose from?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"New Hampshire CDL applicants must self-certify into one of four categories: interstate non-excepted, interstate excepted, intrastate non-excepted, and intrastate excepted. Source: NH DMV self-certification form DSMV 612.","handbook":"","hbref":""},{"q":"A New Hampshire driver self-certifies as 'interstate non-excepted.' What does this category require?","options":["A valid DOT Medical Examiner's Certificate on file","No medical certificate of any kind","Only a state-issued intrastate medical waiver","A Transportation Worker Identification Credential instead of a medical card"],"answer":0,"explanation":"Interstate non-excepted drivers operate across state lines in non-excepted commerce and must hold and keep on file a valid DOT Medical Examiner's Certificate. Excepted categories are not required to provide a medical card. Source: NH DMV form DSMV 612; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which New Hampshire form is used by CDL holders to self-certify their operating category and submit medical-card information to the DMV?","options":["DSMV 612","DSMV 312","MCSA-5876","DSMV 500"],"answer":0,"explanation":"New Hampshire uses form DSMV 612 for CDL self-certification and to submit medical-card/certification information to the DMV. DSMV 312 is the CDL application; MCSA-5876 is the federal Medical Examiner's Certificate completed by the examiner. Source: NH DMV, CDL Medical Card Update; form DSMV 612.","handbook":"","hbref":""},{"q":"On the New Hampshire general knowledge CDL written test, what is the minimum score required to pass?","options":["80%","70%","75%","90%"],"answer":0,"explanation":"New Hampshire requires a minimum passing score of 80% on the CDL general knowledge test (40 of 50 questions correct). Source: NH CDL Manual; NH DMV knowledge testing requirements.","handbook":"","hbref":""},{"q":"A New Hampshire CDL expires on the licensee's birthday in which year following issuance?","options":["The fifth year","The fourth year","The sixth year","The tenth year"],"answer":0,"explanation":"Under RSA 263:93, a New Hampshire commercial driver license expires on the licensee's birthdate in the fifth year following issuance, making it a five-year renewal cycle. Source: NH RSA 263:93 (License Expiration and Renewal).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a New Hampshire CDL for intrastate (in-state only) driving?","options":["18 years old","16 years old","21 years old","19 years old"],"answer":0,"explanation":"An applicant must be at least 18 to hold a New Hampshire CDL for intrastate driving. Drivers under 21 are restricted to intrastate operation only. Source: NH DMV, Commercial Driver Licenses page.","handbook":"","hbref":""},{"q":"What is the minimum age to drive interstate (across state lines) or to obtain a HAZMAT endorsement on a New Hampshire CDL?","options":["21 years old","18 years old","23 years old","25 years old"],"answer":0,"explanation":"A New Hampshire CDL holder must be at least 21 to drive in interstate commerce or to carry a HAZMAT endorsement. Holders aged 18-20 are limited to intrastate driving. Source: NH DMV, Commercial Driver Licenses page; 49 CFR 383.","handbook":"","hbref":""},{"q":"Which form is the New Hampshire Commercial Driver License application itself?","options":["DSMV 312","DSMV 612","MCSA-5875","DSMV 426"],"answer":0,"explanation":"The New Hampshire CDL application is form DSMV 312. DSMV 612 is the separate self-certification/medical-card form. Source: NH DMV CDL forms; Apply for a CDL.","handbook":"","hbref":""},{"q":"Besides the knowledge and skills tests, which screening must every New Hampshire CDL applicant pass?","options":["A vision examination","A written first-aid exam","A drug-and-alcohol blood test administered at the DMV","A physical agility obstacle course"],"answer":0,"explanation":"All New Hampshire CDL applicants must pass a vision examination in addition to the knowledge and skills tests. Source: NH DMV, Commercial Driver Licenses page.","handbook":"","hbref":""},{"q":"For the New Hampshire CDL road test, the applicant must generally provide which kind of test vehicle?","options":["A representative vehicle of the same class/type as the CDL sought, with a valid inspection sticker","Any passenger car with current registration","A vehicle provided free of charge by the NH DMV","A rental vehicle under 26,001 lbs GVWR regardless of class"],"answer":0,"explanation":"The applicant must supply a representative test vehicle matching the class/type of CDL being sought, properly registered and insured and displaying a valid New Hampshire inspection sticker. Source: NH DMV, CDL Road Test page.","handbook":"","hbref":""},{"q":"If a New Hampshire CDL holder's medical certification lapses and an updated certificate or variance is not submitted, the DMV must downgrade the CDL within how long?","options":["60 days","10 days","30 days","180 days"],"answer":0,"explanation":"Under the federal medical-certification rule that New Hampshire enforces, the state must downgrade a CDL or CLP within 60 days of a lapse if a current medical certificate or variance is not submitted (or the driver changes to an excepted/intrastate category where allowed). Source: 49 CFR 383.73; NH DMV CDL Medical Card Update.","handbook":"","hbref":""},{"q":"Which New Hampshire CDL class authorizes operating a single vehicle with a GVWR of 26,001 lbs or more (towing nothing over 10,000 lbs)?","options":["Class B","Class A","Class C","Class D"],"answer":0,"explanation":"A Class B CDL covers any single vehicle with a GVWR of 26,001 lbs or more, or such a vehicle towing a unit not over 10,000 lbs GVWR. Class A covers combinations over 26,001 lbs with a towed unit over 10,000 lbs. Source: NH DMV, License Classifications page.","handbook":"","hbref":""},{"q":"Before applying for a HAZMAT endorsement on a New Hampshire CDL, what additional federal step must the applicant complete?","options":["A TSA security threat assessment with fingerprint-based background check","A 40-hour OSHA hazardous-materials handling course","An EPA hazardous-waste transporter registration","A second on-road skills test in a tank vehicle"],"answer":0,"explanation":"Applicants for a HAZMAT endorsement must pass a TSA security threat assessment, which includes fingerprinting and a background check, in addition to the HAZMAT knowledge test. Source: NH DMV, Commercial Driver Licenses page; 49 CFR Part 1572.","handbook":"","hbref":""},{"q":"Under the modernized federal medical-certification process that New Hampshire follows (effective 2025), how do most Medical Examiner's Certificate results now reach the state?","options":["Medical examiners transmit results electronically to FMCSA, which sends them to the state to update the driving record","Drivers must always hand-deliver the paper certificate to a DMV office","Employers mail certificates directly to the FMCSA on the driver's behalf","Certificates are filed only with the driver's insurance carrier"],"answer":0,"explanation":"Under the federal process effective June 23, 2025 that New Hampshire follows, certified medical examiners report exam results electronically to FMCSA, which transmits the medical-certification status to the state to update the CDL record; drivers still must self-certify their operating category (e.g., via DSMV 612). Source: FMCSA Medical Certification rule; NH DMV CDL Medical Card Update.","handbook":"","hbref":""},{"q":"A 19-year-old passes all New Hampshire CDL tests and qualifies for a CDL. What operating restriction applies?","options":["They are limited to intrastate (within New Hampshire) commerce until age 21","They may drive interstate but not carry passengers","They may drive interstate only with a HAZMAT endorsement","There is no age-based operating restriction once tests are passed"],"answer":0,"explanation":"A New Hampshire CDL holder who is at least 18 but under 21 is restricted to intrastate driving only; interstate operation and HAZMAT require age 21. Source: NH DMV, Commercial Driver Licenses page; 49 CFR 391.11.","handbook":"","hbref":""}],"ru":{"0":{"q":"На дорогах штата Нью-Гэмпшир какова максимальная ширина транспортного средства, включая груз, до того как потребуется разрешение на сверхгабаритную перевозку?","options":["96 inches","102 inches","108 inches","114 inches"],"explanation":"New Hampshire RSA 266:12 запрещает движение любого транспортного средства, ширина которого вместе с грузом превышает 102 inches (8 feet 6 inches). Это соответствует федеральному стандарту для National Network. Источник: NH RSA 266:12 Width; NH CDL Manual."},"1":{"q":"Какова максимальная высота, включая груз, стандартного транспортного средства (не перевозящего сборные дома), допустимая на дорогах штата Нью-Гэмпшир без разрешения?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"explanation":"New Hampshire RSA 266:10 гласит, что ни одно транспортное средство (за исключением перевозящего сборные дома или модульные здания), общая высота которого вместе с грузом превышает 13 feet 6 inches, не может двигаться по дорогам штата. Источник: NH RSA 266:10 Height."},"2":{"q":"В штате Нью-Гэмпшир какова максимальная длина полуприцепа в составе «тягач/полуприцеп», эксплуатируемом без разрешения?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"New Hampshire RSA 266:11 допускает полуприцеп длиной до 53 feet в составе «седельный тягач и один полуприцеп» (для прицепов длиннее 48 feet действуют дополнительные требования к шкворню и задней защите). Источник: NH RSA 266:11 Length."},"3":{"q":"Согласно законодательству штата Нью-Гэмпшир, какова максимальная полная масса транспортного средства (включая все допуски правоохранительных органов) для составного транспортного средства с пятью или более осями, эксплуатируемого без разрешения на перегруз?","options":["73,280 pounds","80,000 pounds","84,000 pounds","90,000 pounds"],"explanation":"Штат Нью-Гэмпшир ограничивает максимальную полную массу для состава с 5 или более осями значением 80,000 pounds, включая все допуски правоохранительных органов, что соответствует федеральному пределу. Источник: NH RSA 266:18 / 266:18-a."},"4":{"q":"Какова максимальная нагрузка на одиночную ось, допустимая на системе межштатных и оборонных автомагистралей штата Нью-Гэмпшир без разрешения?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"На системе межштатных и оборонных автомагистралей New Hampshire RSA 266:18 ограничивает одиночную ось значением 20,000 pounds, что соответствует федеральному стандарту для межштатных дорог. (Более высокие значения, такие как 22,400 lb, применяются только к определённым конфигурациям вне межштатной системы.) Источник: NH RSA 266:18."},"5":{"q":"На системе межштатных и оборонных автомагистралей штата Нью-Гэмпшир какова максимальная нагрузка, допустимая на сдвоенную ось?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"New Hampshire RSA 266:18 ограничивает сдвоенную ось значением 34,000 pounds на системе межштатных и оборонных автомагистралей, как и федеральный стандарт. Источник: NH RSA 266:18."},"6":{"q":"Контроль перегруза в штате Нью-Гэмпшир использует формулу распределения веса, связывающую полную массу с расстоянием между осями и числом осей. Эта формула широко известна как:","options":["Federal bridge formula","Формула отступа шкворня (kingpin setback)","Формула полной массы состава (gross combination rating)","Формула массы тары (tare weight)"],"explanation":"New Hampshire RSA 266:18 включает федеральную мостовую формулу (federal bridge formula) W = 500[LN/(N-1) + 12N + 36], где W — полная масса на группу осей, L — расстояние между крайними осями, а N — число осей. Источник: NH RSA 266:18."},"7":{"q":"В мостовой формуле штата Нью-Гэмпшир W = 500[LN/(N-1) + 12N + 36] что обозначает переменная «N»?","options":["Число осей в группе","Чистую массу груза","Число прицепов","Номинальную ширину шины"],"explanation":"В мостовой формуле, принятой штатом Нью-Гэмпшир (RSA 266:18), N равно числу осей в рассматриваемой группе; L — расстояние в футах между крайними осями, а W — итоговая допустимая полная масса. Источник: NH RSA 266:18."},"8":{"q":"Грузовые составы с тройными прицепами (triple-trailer) на дорогах штата Нью-Гэмпшир:","options":["Разрешены только на межштатных автомагистралях","Разрешены при наличии годового разрешения","Запрещены","Разрешены только в ночное время"],"explanation":"New Hampshire RSA 266:11-b запрещает эксплуатацию грузовиков с тройными прицепами на дорогах штата. Источник: NH RSA 266:11-b Triple Trailer Trucks Prohibited."},"9":{"q":"Перевозчику нужно перевезти груз, превышающий установленные в штате Нью-Гэмпшир пределы по габаритам или массе. Какое ведомство выдаёт необходимое разрешение на сверхгабаритную/сверхтяжёлую перевозку?","options":["Местный дорожный смотритель города","The New Hampshire Department of Transportation","The Federal Motor Carrier Safety Administration","Управление шерифа округа"],"explanation":"Разрешения на сверхгабаритные/сверхтяжёлые перевозки (OSOW) в штате Нью-Гэмпшир выдаются NH Department of Transportation через его офис разрешений (заявки онлайн, лично по адресу 7 Hazen Drive, Concord, или по телефону). Источник: NHDOT Permits / OSOW Permit Office."},"10":{"q":"Сверхгабаритному или сверхтяжёлому грузу в штате Нью-Гэмпшир обычно разрешается движение в какие часы?","options":["24 часа в сутки, в любой день","С получаса до восхода солнца до получаса после заката, с понедельника по пятницу","Только с 9:00 p.m. до 5:00 a.m. ежедневно","Только по выходным, чтобы избежать пиковых пробок"],"explanation":"Согласно правилам разрешений NHDOT OSOW, сверхгабаритные/сверхтяжёлые грузы обычно могут перемещаться с получаса до восхода солнца до получаса после заката, с понедельника по пятницу, при этом движение сверхгабаритных грузов по выходным и праздникам не допускается. Источник: NHDOT OSOW Permit travel restrictions."},"11":{"q":"Какова максимальная длина, включая передний и задний бамперы, одиночного транспортного средства или автобуса на дорогах штата Нью-Гэмпшир без разрешения?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"New Hampshire RSA 266:11 ограничивает одиночное транспортное средство или автобус длиной 45 feet, включая передний и задний бамперы. Источник: NH RSA 266:11 Length."},"12":{"q":"Когда транспортное средство перевозит сборные дома или модульные здания в штате Нью-Гэмпшир, максимально допустимая высота составляет:","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"New Hampshire RSA 266:10 допускает максимальную высоту 14 feet 6 inches для транспортных средств, перевозящих сборные дома или модульные здания; грузы, превышающие 13 feet 6 inches, требуют сопровождения (эскорта) непополицейским сопровождающим. Источник: NH RSA 266:10 Height."},"13":{"q":"На системе автомагистралей общего пользования штата Нью-Гэмпшир, не относящихся к межштатным, одиночная ось 3-осного одиночного транспортного средства может нести максимально:","options":["18,000 pounds","20,000 pounds","22,400 pounds","25,000 pounds"],"explanation":"New Hampshire RSA 266:18-a допускает до 22,400 pounds на ось для 3-осных одиночных транспортных средств (и других транспортных средств с осями, отстоящими на 10 feet или более) на системе автомагистралей общего пользования вне межштатной сети, что выше предела 20,000 pounds для межштатных дорог. Источник: NH RSA 266:18-a."},"14":{"q":"Для состава «седельный тягач и один полуприцеп» с четырьмя или более осями, перевозящего необработанную лесную продукцию в штате Нью-Гэмпшир, максимальная нагрузка на сдвоенную ось увеличивается до:","options":["34,000 pounds","36,000 pounds","40,000 pounds","44,000 pounds"],"explanation":"New Hampshire RSA 266:18-b допускает нагрузку на сдвоенную ось до 40,000 pounds для состава «седельный тягач и один полуприцеп» с 4 или более осями, перевозящего необработанную лесную продукцию (необработанные брёвна и древесную щепу). Источник: NH RSA 266:18-b."},"15":{"q":"Законодательство штата Нью-Гэмпшир разрешает сотрудникам контроля допускать какой общий допуск сверх установленных пределов по группе осей и полной массе, прежде чем выписать нарушение?","options":["1 percent","2 percent","5 percent","15 percent"],"explanation":"New Hampshire RSA 266:18-a и 266:18-c разрешают допуск в 5 percent сверх установленных пределов по массе (с допуском до 10 percent для определённых нагрузок на ось согласно 266:18-c). Источник: NH RSA 266:18-a / 266:18-c."},"16":{"q":"На межштатной системе два последовательных комплекта сдвоенных осей в штате Нью-Гэмпшир могут каждый нести по 34,000 pounds только если расстояние между первой и последней осями этих комплектов сдвоенных осей составляет не менее:","options":["28 feet","30 feet","36 feet","40 feet"],"explanation":"New Hampshire RSA 266:18 допускает, чтобы два последовательных комплекта сдвоенных осей несли по 34,000 pounds каждый, только если общее расстояние между первой и последней осями составляет 36 feet или более, и полная масса не превышает 80,000 pounds. Источник: NH RSA 266:18."},"17":{"q":"На системе автомагистралей общего пользования штата Нью-Гэмпшир вне межштатной сети какова максимальная нагрузка на сдвоенную ось для состава с пятью или более осями?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"New Hampshire RSA 266:18-a допускает нагрузку на сдвоенную ось состава с 5 или более осями на системе автомагистралей общего пользования вне межштатной сети до 36,000 pounds, что выше предела 34,000 pounds для сдвоенной оси на межштатных дорогах. Источник: NH RSA 266:18-a."},"18":{"q":"Перевозчик, базирующийся в штате Нью-Гэмпшир, хочет получить годовое разрешение на сверхгабаритную перевозку по всему штату для транспортного средства длиной не более 75 feet, шириной 10 feet 6 inches и высотой 13 feet 6 inches. Каков указанный годовой сбор за разрешение для перевозок по всему штату?","options":["$60.00","$115.00","$200.00","$300.00"],"explanation":"NHDOT указывает годовой сбор за разрешение на сверхгабаритную перевозку в размере $115.00 для перевозок по всему штату (или $60.00 для перевозок в радиусе 100-mile) для перевозчиков, базирующихся и зарегистрированных в штате Нью-Гэмпшир, для транспортных средств в указанных пределах 75 ft / 10 ft 6 in / 13 ft 6 in. Источник: NHDOT OSOW Permit fees."},"19":{"q":"Согласно New Hampshire RSA 266:16, штраф за первое нарушение, состоящее в эксплуатации транспортного средства, превышающего разрешённые пределы по габаритам, составляет:","options":["Не более $100","Не более $250","Не более $500","Не более $1,000"],"explanation":"New Hampshire RSA 266:16 устанавливает штраф за превышение разрешённых габаритов в размере не более $100 за первое нарушение и не более $250 за последующее нарушение в течение того же календарного года. Источник: NH RSA 266:16 Penalty for Exceeding Permitted Size."},"20":{"q":"Согласно правилам CDL штата Нью-Гэмпшир, какой класс прав требуется для управления составом транспортных средств с полной массой состава (GCWR) 26,001 pounds или более, при условии, что буксируемая единица имеет GVWR свыше 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"Штат Нью-Гэмпшир определяет Class A CDL как любой состав транспортных средств с GCWR 26,001 lbs или более, где GVWR буксируемой единицы превышает 10,000 lbs. Источник: страница NH DMV License Classifications, Restrictions and Endorsements; NH Commercial Driver's Manual."},"21":{"q":"В штате Нью-Гэмпшир какой класс CDL охватывает любое ОДИНОЧНОЕ транспортное средство с GVWR 26,001 pounds или более, либо такое транспортное средство, буксирующее единицу с GVWR не более 10,000 pounds?","options":["Class A","Class B","Class C","Class M"],"explanation":"Нью-Гэмпшир определяет Class B CDL как одиночное транспортное средство с GVWR 26,001 lbs или более, либо такое транспортное средство, буксирующее единицу с GVWR не более 10,000 lbs. Источник: страница NH DMV License Classifications; NH Commercial Driver's Manual."},"22":{"q":"Водитель в штате Нью-Гэмпшир управляет одиночным транспортным средством массой менее 26,001 lbs, рассчитанным на перевозку 18 пассажиров, включая водителя. Какой класс CDL для этого требуется?","options":["Class A","Class B","Class C","CDL не требуется"],"explanation":"Нью-Гэмпшир определяет Class C CDL как транспортное средство, не подпадающее под Class A или B, которое перевозит 16 или более пассажиров (включая водителя), снабжено табличками (placard) для опасных материалов или является цистерной. Транспортное средство на 18 пассажиров подпадает под Class C. Источник: страница NH DMV License Classifications."},"23":{"q":"Каков минимальный возраст для получения CDL штата Нью-Гэмпшир с ограничением до ВНУТРИШТАТНЫХ перевозок (только в пределах штата Нью-Гэмпшир)?","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"В штате Нью-Гэмпшир вам должно быть не менее 18 лет, чтобы управлять коммерческим транспортным средством внутри штата (в пределах Нью-Гэмпшира). Источник: страница NH DMV Commercial Driver Licenses; NH Commercial Driver's Manual."},"24":{"q":"Каков минимальный возраст для получения CDL штата Нью-Гэмпшир, действительного для МЕЖШТАТНЫХ (через границы штатов) коммерческих перевозок?","options":["18 years old","19 years old","21 years old","23 years old"],"explanation":"Штат Нью-Гэмпшир (следуя федеральному стандарту) требует, чтобы водителям было не менее 21 года для управления коммерческим транспортным средством в межштатных перевозках. Водители в возрасте 18-20 лет ограничены внутриштатными перевозками. Источник: страница NH DMV Commercial Driver Licenses."},"25":{"q":"Согласно правилам штата Нью-Гэмпшир и федеральным правилам, как долго заявитель должен владеть Commercial Learner Permit (CLP), прежде чем ему будет разрешено сдавать практический экзамен CDL (вождение)?","options":["7 days","10 days","14 days","30 days"],"explanation":"Заявитель должен владеть CLP не менее 14 days, прежде чем сдавать практический экзамен CDL. Это федеральное требование, применяемое в штате Нью-Гэмпшир. Источник: страница NH DMV Commercial Driver Learner Permit; 49 CFR 383.25."},"26":{"q":"Когда владелец Commercial Driver Learner Permit штата Нью-Гэмпшир управляет коммерческим транспортным средством, кто должен его сопровождать?","options":["Любой лицензированный водитель в возрасте 18 лет и старше","Лицо 25 лет или старше, имеющее CDL, действительный для данного типа транспортного средства, сидящее непосредственно рядом с владельцем разрешения","Любой владелец CDL, сидящий в любом месте транспортного средства","Только экзаменатор New Hampshire DMV"],"explanation":"Нью-Гэмпшир требует, чтобы владельца CLP сопровождало лицо в возрасте 25 лет или старше, имеющее CDL, действительный для типа управляемого транспортного средства, и занимающее сиденье непосредственно рядом с владельцем разрешения. Источник: страница NH DMV Commercial Driver Learner Permit."},"27":{"q":"Какой код подтверждения (endorsement) требуется в CDL штата Нью-Гэмпшир для перевозки опасных материалов в количествах, требующих наличия табличек (placard)?","options":["Подтверждение N","Подтверждение H","Подтверждение T","Подтверждение X"],"explanation":"Подтверждение H (HazMat) требуется для управления любым коммерческим транспортным средством, перевозящим опасные материалы, которые должны быть обозначены табличками (placard) согласно нормам штата или федеральным нормам. Источник: страница NH DMV HazMat Endorsement."},"28":{"q":"Прежде чем водителю в штате Нью-Гэмпшир может быть выдано подтверждение HazMat (H), какая дополнительная проверка требуется на федеральном уровне?","options":["Оценка угрозы безопасности TSA (проверка биографии на основе отпечатков пальцев)","Проверка на полиграфе FBI","Собеседование с New Hampshire State Police","Только тест на наркотики DOT"],"explanation":"Заявители на подтверждение H должны пройти оценку угрозы безопасности Transportation Security Administration (TSA), которая включает проверку биографии на основе отпечатков пальцев, в дополнение к тесту на знание HazMat. Источник: страница NH DMV HazMat Endorsement; 49 CFR 1572."},"29":{"q":"В CDL штата Нью-Гэмпшир какое подтверждение требуется для управления цистерной (используемой для перевозки жидкостей или газов наливом)?","options":["Подтверждение H","Подтверждение T","Подтверждение N","Подтверждение P"],"explanation":"Подтверждение N (Tank Vehicle) требуется для управления цистерной, предназначенной для перевозки жидкостей или газов наливом. Источник: страница NH DMV License Classifications, Restrictions and Endorsements."},"30":{"q":"Какое подтверждение CDL штата Нью-Гэмпшир требуется для буксировки двойных или тройных прицепов?","options":["Подтверждение T","Подтверждение N","Подтверждение D","Подтверждение X"],"explanation":"Подтверждение T (Doubles/Triples) требуется для буксировки двойных или тройных прицепов. Оно получается путём сдачи теста на знания; отдельный практический экзамен для него не требуется. Источник: страница NH DMV License Classifications; NH Commercial Driver's Manual."},"31":{"q":"Какое подтверждение CDL требует штат Нью-Гэмпшир для управления коммерческим транспортным средством, рассчитанным на перевозку 16 или более пассажиров, включая водителя?","options":["Подтверждение S","Подтверждение P","Подтверждение N","Подтверждение T"],"explanation":"Подтверждение P (Passenger) требуется для управления любым коммерческим транспортным средством, рассчитанным на перевозку 16 или более пассажиров, включая водителя. Источник: страница NH DMV Commercial Driver Licenses."},"32":{"q":"Чтобы получить подтверждение School Bus (S) штата Нью-Гэмпшир, что обычно также необходимо заявителю?","options":["Подтверждение HazMat (H)","Подтверждение Tank (N)","Подтверждение Passenger (P)","Подтверждение Doubles/Triples (T)"],"explanation":"Школьный автобус перевозит 16 или более человек, поэтому штат Нью-Гэмпшир требует подтверждение Passenger (P) в дополнение к сдаче теста на знания School Bus (S) и практического экзамена по вождению пассажирского транспортного средства. Источник: страница NH DMV School Bus Drivers."},"33":{"q":"Какой минимальный проходной балл требует штат Нью-Гэмпшир на письменном тесте на общие знания CDL для получения Commercial Learner Permit?","options":["70%","75%","80%","90%"],"explanation":"Штат Нью-Гэмпшир требует балл 80% или выше на экзаменах на знания CDL, включая тест на общие знания. Источник: страница NH DMV Commercial Driver Learner Permit; NH Commercial Driver's Manual."},"34":{"q":"Entry-Level Driver Training (ELDT), проходимое перед определёнными практическими экзаменами/тестами на знания CDL в штате Нью-Гэмпшир, должно быть пройдено через что?","options":["Любой общественный колледж штата Нью-Гэмпшир","Провайдера, включённого в FMCSA Training Provider Registry (TPR)","Собственное учебное подразделение New Hampshire DMV","Любую программу, проводимую работодателем, без необходимости регистрации"],"explanation":"ELDT должно быть пройдено через провайдера, включённого в FMCSA Training Provider Registry (TPR); провайдер самостоятельно удостоверяет и подаёт записи о прохождении в FMCSA. Источник: FMCSA ELDT / Training Provider Registry; страницы NH DMV CDL."},"35":{"q":"Что из перечисленного требует ELDT (Entry-Level Driver Training) до того, как заявитель в штате Нью-Гэмпшир сможет сдать соответствующий тест?","options":["Добавление подтверждения Doubles/Triples (T)","Добавление подтверждения Tank (N)","Получение Class A CDL впервые","Продление существующего Class B CDL без изменения класса"],"explanation":"Федеральные правила ELDT (вступившие в силу 7 февраля 2022 года) применяются к получению Class A или B CDL впервые, переходу с Class B на Class A и получению подтверждения H, P или S впервые. Подтверждения N и T, а также простые продления не требуют ELDT. Источник: нормы FMCSA ELDT; страницы NH DMV CDL."},"36":{"q":"При подаче заявления на CDL штата Нью-Гэмпшир какая категория самоудостоверения (self-certification) указывает на водителя, который выполняет перевозки через границы штатов и должен соответствовать федеральному требованию о медицинской справке DOT?","options":["Interstate non-excepted","Intrastate excepted","Interstate excepted","Intrastate non-excepted"],"explanation":"Нью-Гэмпшир использует четыре федеральные категории самоудостоверения. «Interstate non-excepted» охватывает водителей, выполняющих перевозки через границы штатов, которые должны иметь действующую медицинскую справку DOT в деле. Источник: страница NH DMV CDL Medical Card Update; 49 CFR 383.71."},"37":{"q":"Чтобы подать заявление на CDL или Commercial Learner Permit штата Нью-Гэмпшир, заявитель, как правило, должен предъявить подтверждение какого сочетания документов?","options":["Только удостоверение личности","Только удостоверение личности и Social Security Number","Удостоверение личности, Social Security Number и подтверждение проживания/законного пребывания в штате Нью-Гэмпшир","Только паспорт, который покрывает все требования"],"explanation":"Штат Нью-Гэмпшир требует, чтобы заявители подтвердили личность, предоставили документ с указанием Social Security Number, а также предоставили документы, устанавливающие проживание в штате Нью-Гэмпшир и законное пребывание. Источник: страницы NH DMV Required Documents / Commercial Driver Learner Permit."},"38":{"q":"Как долго действителен Commercial Driver Learner Permit (CLP) штата Нью-Гэмпшир, прежде чем его необходимо продлить?","options":["30 days","60 days","180 days","365 days"],"explanation":"CLP штата Нью-Гэмпшир действителен 180 days и может быть продлён один раз, при условии, что требуемые тесты на знания были сданы в течение одного года. Это соответствует федеральному стандарту срока действия CLP. Источник: страница NH DMV Commercial Driver Learner Permit; 49 CFR 383.25."},"39":{"q":"19-летний житель штата Нью-Гэмпшир хочет получить CDL. На какую привилегию он НЕ имеет права, пока ему не исполнится 21 год?","options":["Владение Class B CDL","Внутриштатные перевозки в пределах штата Нью-Гэмпшир","Получение подтверждения HazMat (H)","Получение подтверждения Tank (N)"],"explanation":"Заявители в штате Нью-Гэмпшир младше 21 года ограничены внутриштатными перевозками и не могут получить подтверждение HazMat (H) или привилегии Passenger для межштатных перевозок; подтверждение H, в частности, требует, чтобы заявителю было не менее 21 года. Источник: страницы NH DMV Commercial Driver Licenses / HazMat Endorsement."},"40":{"q":"В штате Нью-Гэмпшир каков максимальный уровень концентрации алкоголя в крови (BAC), при котором человек может законно управлять коммерческим транспортным средством (CMV)?","options":["0.04","0.08","0.02","0.10"],"explanation":"Штат Нью-Гэмпшир устанавливает предел BAC для управления CMV в 0.04, что вдвое меньше предела 0.08 для некоммерческих водителей. Источник: NH CDL Manual (раздел об алкоголе/наркотиках); RSA 265-A:2."},"41":{"q":"Управляя коммерческим транспортным средством на дорогах штата Нью-Гэмпшир, владелец CDL юридически считается совершившим что в отношении химического тестирования на алкоголь или наркотики?","options":["Давшим подразумеваемое согласие на прохождение тестирования при законном требовании","Отказавшимся от любого будущего права на CDL","Согласившимся уплатить фиксированный сбор за тестирование в размере $500","Согласившимся только на тест дыхания, но не крови"],"explanation":"Согласно закону штата Нью-Гэмпшир о подразумеваемом согласии (implied consent), любой, кто управляет транспортным средством в штате, считается давшим согласие на химическое тестирование для определения концентрации алкоголя при законном требовании. Источник: RSA 265-A:4; NH CDL Manual."},"42":{"q":"За первое серьёзное правонарушение (например, вождение в нетрезвом виде, DUI, в CMV) каков минимальный срок дисквалификации CDL в штате Нью-Гэмпшир?","options":["1 year","60 days","6 months","3 years"],"explanation":"Первое серьёзное правонарушение дисквалифицирует водителя от управления CMV на срок не менее одного года в штате Нью-Гэмпшир. Источник: RSA 263:94; 49 CFR 383.51; NH CDL Manual."},"43":{"q":"Если водитель в штате Нью-Гэмпшир совершает первое серьёзное правонарушение при управлении CMV, обозначенным табличками (placard) для опасных материалов, минимальная дисквалификация составляет:","options":["3 years","1 year","120 days","Пожизненно"],"explanation":"Первое серьёзное правонарушение, совершённое при перевозке опасных материалов с табличками (placard), повышает минимальную дисквалификацию с одного года до трёх лет. Источник: RSA 263:94; 49 CFR 383.51."},"44":{"q":"Каков срок дисквалификации в штате Нью-Гэмпшир за второе серьёзное правонарушение (например, второе DUI в CMV), возникшее в результате отдельного инцидента?","options":["Пожизненно","10 years","5 years","3 years"],"explanation":"Второе осуждение за серьёзное правонарушение по отдельному инциденту приводит к пожизненной дисквалификации от управления CMV. Источник: RSA 263:94; 49 CFR 383.51."},"45":{"q":"Владелец CDL штата Нью-Гэмпшир отказывается пройти химическое тестирование при управлении CMV. За первый отказ минимальная дисквалификация CDL составляет:","options":["1 year","90 days","6 months","30 days"],"explanation":"Отказ от законно запрошенного химического теста рассматривается как серьёзное правонарушение; первый отказ влечёт минимальную дисквалификацию CDL на один год (три года, если есть таблички placard для опасных материалов). Источник: RSA 263:94; RSA 265-A:4."},"46":{"q":"Если владелец CDL штата Нью-Гэмпшир отказывается от химического тестирования во второй раз (отдельный инцидент), дисквалификация CDL составляет:","options":["Пожизненно","5 years","2 years","1 year"],"explanation":"Второй случай отказа от химического тестирования, как и любое второе серьёзное правонарушение, приводит к пожизненной дисквалификации CDL. Источник: RSA 263:94; 49 CFR 383.51."},"47":{"q":"В штате Нью-Гэмпшир осуждение за ДВА серьёзных нарушения правил дорожного движения в CMV, возникших в результате отдельных инцидентов в течение 3 years, приводит к дисквалификации CDL на срок не менее:","options":["60 days","30 days","120 days","1 year"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение периода 3 years дисквалифицируют водителя от управления CMV на срок не менее 60 days. Источник: RSA 263:94; 49 CFR 383.51."},"48":{"q":"Осуждение за ТРИ серьёзных нарушения правил дорожного движения в CMV по отдельным инцидентам в течение 3 years приводит к дисквалификации CDL штата Нью-Гэмпшир на срок не менее:","options":["120 days","60 days","90 days","1 year"],"explanation":"Три серьёзных нарушения правил дорожного движения в течение периода 3 years дисквалифицируют водителя от управления CMV на срок не менее 120 days. Источник: RSA 263:94; 49 CFR 383.51."},"49":{"q":"Согласно правилам CDL штата Нью-Гэмпшир, при какой скорости сверх установленного предела одиночное нарушение скоростного режима становится «серьёзным нарушением правил дорожного движения»?","options":["15 mph или более сверх предела","10 mph или более сверх предела","20 mph или более сверх предела","25 mph или более сверх предела"],"explanation":"Превышение скорости на 15 mph или более сверх установленного предела определяется как серьёзное нарушение правил дорожного движения для целей CDL в штате Нью-Гэмпшир. Источник: RSA 259:98-a; N.H. Admin. Code Saf-C 1809.02."},"50":{"q":"Что из перечисленного классифицируется как «серьёзное нарушение правил дорожного движения» для владельца CDL штата Нью-Гэмпшир?","options":["Движение на слишком близком расстоянии (tailgating)","Парковка в пожарной полосе","Движение со скоростью 5 mph сверх предела","Просроченная регистрационная наклейка"],"explanation":"Движение на слишком близком расстоянии является одним из перечисленных серьёзных нарушений правил дорожного движения для владельцев CDL, наряду с безрассудным вождением, беспорядочной сменой полос и чрезмерным превышением скорости. Источник: RSA 259:98-a; Saf-C 1809.02."},"51":{"q":"За ПЕРВОЕ осуждение за нарушение на железнодорожном переезде при управлении CMV в штате Нью-Гэмпшир минимальная дисквалификация составляет:","options":["60 days","30 days","120 days","1 year"],"explanation":"Первое нарушение на железнодорожном переезде в CMV влечёт минимальную дисквалификацию в 60 days. Источник: 49 CFR 383.51 Table 3, принятая штатом Нью-Гэмпшир; NH CDL Manual."},"52":{"q":"ВТОРОЕ нарушение на железнодорожном переезде в CMV в течение 3 years приводит к дисквалификации CDL штата Нью-Гэмпшир на срок не менее:","options":["120 days","60 days","90 days","1 year"],"explanation":"Второе нарушение на переезде в течение 3 years влечёт минимальную дисквалификацию в 120 days. Источник: 49 CFR 383.51 Table 3, принятая штатом Нью-Гэмпшир."},"53":{"q":"ТРЕТЬЕ или последующее нарушение на железнодорожном переезде в CMV в течение 3 years приводит к дисквалификации CDL штата Нью-Гэмпшир на срок не менее:","options":["1 year","120 days","180 days","60 days"],"explanation":"Третье или последующее нарушение на переезде в течение 3 years влечёт минимальную дисквалификацию в 1 year. Источник: 49 CFR 383.51 Table 3, принятая штатом Нью-Гэмпшир."},"54":{"q":"В штате Нью-Гэмпшир ПЕРВОЕ нарушение, состоящее в управлении CMV в нарушение предписания о выводе из эксплуатации (out-of-service, OOS) (без опасных материалов), приводит к дисквалификации на срок:","options":["Не менее 180 days и не более 1 year","Не менее 60 days и не более 120 days","Не менее 30 days и не более 90 days","Не менее 2 years и не более 5 years"],"explanation":"Первое нарушение предписания о выводе из эксплуатации дисквалифицирует водителя на срок не менее 180 days и не более 1 year. Источник: 49 CFR 383.51 Table 4, принятая штатом Нью-Гэмпшир; NH CDL Manual."},"55":{"q":"ВТОРОЕ нарушение предписания о выводе из эксплуатации (OOS) в CMV в течение 10 years приводит к дисквалификации в штате Нью-Гэмпшир на срок:","options":["Не менее 2 years и не более 5 years","Не менее 180 days и не более 1 year","Не менее 1 year и не более 3 years","Пожизненно"],"explanation":"Второе нарушение предписания OOS в течение 10 years влечёт дисквалификацию на срок не менее 2 years и не более 5 years. Источник: 49 CFR 383.51 Table 4, принятая штатом Нью-Гэмпшир."},"56":{"q":"Водитель, перевозящий опасные материалы с табличками (placard) или управляющий транспортным средством, рассчитанным на 16+ пассажиров, совершает ПЕРВОЕ нарушение предписания о выводе из эксплуатации в штате Нью-Гэмпшир. Дисквалификация составляет:","options":["Не менее 180 days и не более 2 years","Не менее 180 days и не более 1 year","Не менее 60 days и не более 120 days","Не менее 3 years и не более 5 years"],"explanation":"Первое нарушение OOS при перевозке опасных материалов с табличками (placard) или в транспортном средстве на 16+ пассажиров влечёт повышенный срок не менее 180 days и не более 2 years. Источник: 49 CFR 383.51 Table 4, принятая штатом Нью-Гэмпшир."},"57":{"q":"Согласно закону штата Нью-Гэмпшир о вождении со свободными руками (hands-free), каков штраф за ПЕРВОЕ нарушение, состоящее в использовании портативного мобильного электронного устройства во время вождения?","options":["$100","$50","$250","$500"],"explanation":"Закон штата Нью-Гэмпшир о вождении со свободными руками устанавливает штраф за первое нарушение $100, за второе $250, а за любое последующее нарушение в течение 24 months — $500. Использование портативных устройств запрещено для всех водителей, включая операторов CMV. Источник: RSA 265:79-c."},"58":{"q":"Согласно закону штата Нью-Гэмпшир о вождении со свободными руками (RSA 265:79-c), каков штраф за ВТОРОЕ нарушение, состоящее в использовании портативного электронного устройства во время вождения?","options":["$250","$100","$500","$150"],"explanation":"Второе нарушение закона штата Нью-Гэмпшир о вождении со свободными руками наказывается штрафом $250 (первое нарушение — $100, а последующее нарушение в течение 24 months — $500). Источник: RSA 265:79-c."},"59":{"q":"Для подсчёта первых и последующих правонарушений, влекущих дисквалификацию CDL в штате Нью-Гэмпшир, осуждения учитываются на основании какого правила?","options":["Каждое осуждение по отдельному инциденту учитывается, независимо от того, совершено ли оно в CMV или в некоммерческом транспортном средстве","Учитываются только осуждения при управлении CMV","Учитываются только осуждения за последние 12 месяцев","Учитываются только осуждения, повлёкшие тюремное заключение"],"explanation":"Для определения первых и последующих правонарушений, влекущих дисквалификацию, каждое осуждение по отдельному инциденту учитывается, независимо от того, произошло ли правонарушение в коммерческом или некоммерческом транспортном средстве. Источник: RSA 263:94; 49 CFR 383.51."},"60":{"q":"Согласно закону Нью-Гэмпшира «Move Over», что должен сделать водитель с CDL при приближении к стоящему на обочине транспортному средству с включёнными синими, красными или жёлтыми проблесковыми маячками?","options":["Снизить скорость и, если это практически осуществимо, перестроиться, чтобы объехать транспортное средство с большим запасом","Сохранять скорость, но непрерывно сигналить при проезде","Полностью остановиться в полосе движения, пока транспортное средство не уедет","Продолжать движение с установленной скоростью, поскольку закон применяется только к полицейским машинам"],"explanation":"Закон Нью-Гэмпшира «Move Over» (RSA 265:37-a) требует от водителя поддерживать сниженную скорость и, если это практически осуществимо, обеспечивать большой запас для сотрудников служб общественной безопасности и для любого стоящего транспортного средства с включёнными синими, красными или жёлтыми аварийными или предупредительными маячками, перестраиваясь из заблокированной полосы, когда это безопасно. Источник: NH RSA 265:37-a; NH CDL Manual."},"61":{"q":"В Нью-Гэмпшире перед пересечением железнодорожных путей транспортное средство с табличками, перевозящее опасные материалы, или школьный автобус с детьми должны остановиться на каком расстоянии от ближайшего рельса?","options":["Не менее 15 футов и не более 50 футов","Не менее 5 футов и не более 25 футов","Не менее 25 футов и не более 75 футов","Не менее 50 футов и не более 100 футов"],"explanation":"RSA 265:50 требует, чтобы водители автобусов с пассажирами, школьных автобусов с детьми и транспортных средств, перевозящих взрывчатые/опасные вещества, останавливались в пределах 50 футов, но не ближе 15 футов от ближайшего рельса, после чего смотрели и прислушивались перед тем, как продолжить движение. Источник: NH RSA 265:50; NH CDL Manual."},"62":{"q":"На двухполосной дороге Нью-Гэмпшира водитель, встречающий или обгоняющий стоящий школьный автобус с мигающими красными огнями, должен остановить транспортное средство на каком минимальном расстоянии от автобуса?","options":["Не менее чем в 25 футах","Не менее чем в 10 футах","Не менее чем в 50 футах","Не менее чем в 100 футах"],"explanation":"RSA 265:54 требует, чтобы водитель, встречающий или обгоняющий стоящий школьный автобус, который принимает или высаживает детей, остановился не менее чем в 25 футах от автобуса и оставался на месте, пока автобус не возобновит движение или мигающие огни не погаснут. Источник: NH RSA 265:54."},"63":{"q":"На разделённой автомагистрали Нью-Гэмпшира с отдельными проезжими частями, когда водитель с CDL НЕ обязан останавливаться перед школьным автобусом, принимающим детей?","options":["Когда автобус находится на другой половине разделённой автомагистрали и движется в противоположном направлении","Никогда — остановка всегда обязательна для школьного автобуса с мигающими красными огнями","Только когда водитель управляет пустым одиночным грузовиком","Всякий раз, когда водитель движется быстрее 45 mph"],"explanation":"RSA 265:54 предусматривает, что водитель на разделённой автомагистрали с отдельными проезжими частями не обязан останавливаться при встрече или проезде школьного автобуса, который находится на другой половине разделённой автомагистрали и движется в противоположном направлении. На неразделённой дороге останавливаться должны все направления. Источник: NH RSA 265:54."},"64":{"q":"Каково общее максимальное ограничение скорости на межштатных автомагистралях и платных дорогах Нью-Гэмпшира, которые являются четырёхполосными разделёнными автомагистралями (за пределами участка I-93 с более высоким лимитом)?","options":["65 mph","55 mph","70 mph","75 mph"],"explanation":"RSA 265:60 устанавливает максимум 65 mph на межштатной системе автомагистралей, а также на центральной и восточной платных дорогах Нью-Гэмпшира там, где они являются четырёхполосными разделёнными автомагистралями. Нью-Гэмпшир применяет к грузовикам те же установленные лимиты, что и к легковым автомобилям. Источник: NH RSA 265:60."},"65":{"q":"На какой дороге Нью-Гэмпшира установлено ограничение скорости 70 mph — самое высокое в штате?","options":["I-93 от отметки мили 45 до границы с Вермонтом","I-95 на всём протяжении (Blue Star Turnpike)","Spaulding Turnpike от Портсмута до Милтона","I-89 от Конкорда до границы с Вермонтом"],"explanation":"RSA 265:60 устанавливает ограничение скорости 70 mph на I-93 от отметки мили 45 до границы с Вермонтом. Это самый высокий установленный лимит в Нью-Гэмпшире, и он также применяется к коммерческим транспортным средствам. Источник: NH RSA 265:60."},"66":{"q":"Устанавливает ли Нью-Гэмпшир более низкое ограничение скорости для грузовиков, чем для легковых автомобилей, на своих межштатных автомагистралях?","options":["Нет — грузовики должны соблюдать то же установленное ограничение, что и все остальные транспортные средства","Да — грузовики ограничены 55 mph там, где легковые автомобили могут ехать 65 mph","Да — грузовики ограничены 60 mph по всему штату","Да — грузовики ограничены 45 mph на всех разделённых автомагистралях"],"explanation":"Закон Нью-Гэмпшира о скорости (RSA 265:60) устанавливает максимальные лимиты, применяемые ко всем транспортным средствам, и не устанавливает отдельного, более низкого ограничения скорости для грузовиков; коммерческие транспортные средства соблюдают те же установленные лимиты, что и легковые автомобили. Источник: NH RSA 265:60."},"67":{"q":"Согласно закону Нью-Гэмпшира, что требуется от медленно движущегося грузовика на многополосной дороге в отношении положения в полосе?","options":["Он должен держаться правой полосы и не занимать постоянно левую полосу таким образом, чтобы препятствовать движению","Он может оставаться в левой полосе сколь угодно долго, пока подаёт сигнал","Он должен использовать только центральную полосу на любой трёхполосной дороге","Он освобождён от правил движения справа из-за своих размеров"],"explanation":"RSA 265:16 требует, чтобы транспортное средство, движущееся медленнее обычного потока, держалось правой полосы, и запрещает постоянное движение в левой полосе многополосной дороги, когда это препятствует потоку движения. Источник: NH RSA 265:16."},"68":{"q":"Нью-Гэмпшир требует, чтобы каждый грузовик или автобус массой более 10,000 фунтов перевозил какие аварийные предупредительные устройства для использования при остановке на дороге?","options":["Три двунаправленных светоотражающих предупредительных устройства (светоотражающие треугольники)","Два горящих фонаря на жидком топливе","Один проблесковый маяк на батарейках","Четыре красных матерчатых флага на шестах"],"explanation":"RSA 265:113 требует, чтобы каждый грузовик, автобус или седельный тягач с GVW более 10,000 фунтов перевозил три двунаправленных светоотражающих предупредительных устройства, утверждённых директором, в соответствии с федеральными правилами безопасности автоперевозчиков. Источник: NH RSA 265:113; NH CDL Manual."},"69":{"q":"Когда коммерческое транспортное средство Нью-Гэмпшира массой более 10,000 фунтов остановилось на двухполосной дороге, где обычно следует размещать три предупредительных устройства?","options":["Примерно в 10 футах позади транспортного средства, в 100 футах сзади и в 100 футах спереди","Все три в пределах 10 футов от заднего бампера","Одно в 25 футах впереди и два в 25 футах позади","В 200 футах впереди, в 200 футах позади и одно на крыше"],"explanation":"Согласно RSA 265:113, на обычной двусторонней дороге устройства размещаются примерно в 10 футах от транспортного средства со стороны движения, в 100 футах сзади и в 100 футах спереди. На разделённой или односторонней дороге расстановка составляет 10, 100 и 200 футов в сторону приближающегося потока. Источник: NH RSA 265:113; NH CDL Manual."},"70":{"q":"После остановки перед железнодорожным переездом в Нью-Гэмпшире, что закон требует от водителя автобуса или транспортного средства с опасными грузами во время непосредственного пересечения путей?","options":["Пересекать на достаточно низкой передаче, чтобы не возникало необходимости переключать передачи на путях","Резко ускоряться и быстро переключаться вверх, чтобы пересечь пути как можно быстрее","Перейти на нейтраль и накатом проехать через пути","На короткое время включить стояночный тормоз в середине переезда"],"explanation":"RSA 265:50 предписывает, что после остановки и когда это безопасно, водитель должен пересекать пути на такой передаче, чтобы не было необходимости переключать передачи во время пересечения, и не должен переключать передачи, находясь на путях. Источник: NH RSA 265:50."},"71":{"q":"Какова структура штрафов в Нью-Гэмпшире за первое нарушение закона «Move Over» (RSA 265:37-a)?","options":["$75 плюс штрафной сбор за первое нарушение","$250 плюс приостановка действия прав на 30 дней за первое нарушение","$500 плюс обязательная дисквалификация CDL","Только письменное предупреждение за первое нарушение"],"explanation":"Согласно RSA 265:37-a, первое нарушение закона Нью-Гэмпшира «Move Over» влечёт штраф $75 плюс штрафной сбор, увеличиваясь до $250 плюс сбор за последующее нарушение в течение 12 месяцев. Источник: NH RSA 265:37-a."},"72":{"q":"Какова максимальная законная ширина коммерческого транспортного средства на дорогах Нью-Гэмпшира без специального разрешения на негабарит?","options":["8 футов 6 дюймов","8 футов 0 дюймов","9 футов 0 дюймов","10 футов 6 дюймов"],"explanation":"Нью-Гэмпшир следует федеральному законному пределу ширины в 8 футов 6 дюймов (102 inches); всё, что шире, требует разрешения на негабарит от NHDOT. Источник: правила NH DOT по разрешениям на негабаритные/тяжеловесные грузы; руководство по автоперевозкам NH State Police Troop G."},"73":{"q":"Какова максимальная законная полная масса коммерческого транспортного средства на дорогах Нью-Гэмпшира без разрешения на перегруз?","options":["80,000 фунтов","73,280 фунтов","90,000 фунтов","100,000 фунтов"],"explanation":"Законная максимальная полная масса транспортного средства в Нью-Гэмпшире составляет 80,000 фунтов как на межштатных, так и на других автомагистралях; превышение требует разрешения/сертификации на перегруз через NHDOT. Источник: правила NH DOT по разрешениям на негабаритные/тяжеловесные грузы; NH State Police Troop G."},"74":{"q":"Какова максимальная законная высота коммерческого транспортного средства на дорогах Нью-Гэмпшира без разрешения?","options":["13 футов 6 дюймов","12 футов 6 дюймов","14 футов 0 дюймов","13 футов 0 дюймов"],"explanation":"Законная максимальная высота транспортного средства в Нью-Гэмпшире составляет 13 футов 6 дюймов на всех типах дорог; более высокий груз требует разрешения на негабарит от NHDOT. Источник: правила NH DOT по разрешениям на негабаритные/тяжеловесные грузы."},"75":{"q":"Чем участок Franconia Notch Parkway на I-93 в Нью-Гэмпшире отличается для водителей коммерческого транспорта по сравнению с остальной частью межштатной автомагистрали?","options":["Он сужается до одной полосы в каждом направлении с пониженным лимитом 45 mph","На нём есть выделенная экспресс-полоса только для грузовиков в каждом направлении","На нём разрешён лимит 80 mph для транзитных грузовиков","На нём запрещены все легковые автомобили в светлое время суток"],"explanation":"Участок Franconia Notch Parkway на I-93 был построен по специальному исключению из стандартов межштатных автомагистралей и сужается до одной полосы в каждом направлении с установленным лимитом 45 mph, что требует особой осторожности от коммерческого транспорта на уклоне. Источник: NH DOT; полномочия по зонам с пониженным лимитом по NH RSA 265:60."},"76":{"q":"Какое ведомство выдаёт разрешения на негабаритные/тяжеловесные грузы для коммерческих транспортных средств, превышающих законные пределы, в Нью-Гэмпшире?","options":["Департамент транспорта Нью-Гэмпшира (NHDOT)","Региональное отделение Федерального управления автомобильных дорог","Местная полиция каждого пересекаемого города","Комиссия по алкоголю Нью-Гэмпшира"],"explanation":"Разрешения на негабаритные и тяжеловесные грузы в Нью-Гэмпшире выдаёт офис разрешений Департамента транспорта Нью-Гэмпшира (NHDOT); грузы, превышающие законные размеры или массу, должны иметь разрешение и могут иметь ограничения по маршруту. Источник: офис разрешений NH DOT на негабаритные/тяжеловесные грузы."},"77":{"q":"Согласно закону Нью-Гэмпшира, при скольких или более следующих позади транспортных средствах водитель движущегося школьного автобуса должен съехать на обочину, чтобы пропустить их, когда позволяют условия?","options":["5 или более следующих позади транспортных средств","3 или более следующих позади транспортных средств","10 или более следующих позади транспортных средств","2 или более следующих позади транспортных средств"],"explanation":"RSA 265:54 предписывает, что всякий раз, когда дорожные условия и пространство позволяют, а число транспортных средств, следующих за движущимся школьным автобусом, составляет 5 или более, водитель автобуса должен съехать на обочину, чтобы пропустить следующие позади транспортные средства. Источник: NH RSA 265:54."},"78":{"q":"В Нью-Гэмпшире, что должен сделать водитель при приближении к транзитному или междугороднему автобусу, который остановился для посадки или высадки пассажиров (и не является школьным автобусом с включёнными красными мигалками)?","options":["Снизить скорость и, если это необходимо для общественной безопасности, полностью остановиться","Проезжать на полной скорости, поскольку осторожность требуется только для школьных автобусов","Остановиться не менее чем в 100 футах позади независимо от условий","Просигналить три раза и продолжить движение, не снижая скорости"],"explanation":"RSA 265:55 требует, чтобы водитель, приближающийся к автобусу, трамваю или другому пассажирскому транспортному средству, остановившемуся для посадки или высадки пассажиров, или проезжающий мимо него, снижал скорость и, если это необходимо для безопасности населения, полностью останавливал транспортное средство. Источник: NH RSA 265:55."},"79":{"q":"Водитель с CDL встречает стоящий школьный автобус с мигающими красными огнями на неразделённой дороге Нью-Гэмпшира. Водитель может возобновить движение, когда:","options":["Автобус возобновит движение или мигающие красные огни будут выключены","Прошло три секунды с момента остановки, независимо от огней","Водитель решит, что детей не видно, даже если огни всё ещё мигают","Водитель автобуса махнёт рукой, хотя красные огни остаются включёнными"],"explanation":"Согласно RSA 265:54, водитель, остановившийся перед школьным автобусом на неразделённой дороге, должен оставаться на месте, пока автобус не возобновит движение или мигающие красные огни не будут выключены; первое нарушение влечёт штраф $150 плюс сбор с возможной приостановкой действия прав. Источник: NH RSA 265:54."},"80":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) в Нью-Гэмпшире?","options":["Отдел транспортных средств Нью-Гэмпшира (DMV)","Федеральное управление безопасности автоперевозчиков (FMCSA)","Департамент транспорта Нью-Гэмпшира (NHDOT)","Коммерческое бюро полиции штата Нью-Гэмпшир"],"explanation":"В Нью-Гэмпшире CDL выдаёт Отдел транспортных средств Нью-Гэмпшира (DMV), который проводит тестирование и лицензирование в соответствии с федеральными стандартами FMCSA. NHDOT занимается дорогами и разрешениями на негабаритные/тяжеловесные грузы, а не лицензированием. Источник: NH DMV, страница Commercial Driver Licenses."},"81":{"q":"Прежде чем заявитель в Нью-Гэмпшире сможет записаться на экзамен по навыкам вождения (дорожный тест) CDL, какое федеральное обучение он должен пройти?","options":["Обучение водителей начального уровня (ELDT) у зарегистрированного провайдера","160-часовую программу ученичества штата","Курс безопасного вождения, одобренный NH DMV","Сертификацию по безопасности коммерческих транспортных средств OSHA"],"explanation":"Нью-Гэмпшир следует федеральному правилу ELDT: заявители должны пройти обучение водителей начального уровня (ELDT) у провайдера из реестра провайдеров обучения FMCSA, прежде чем смогут записаться на экзамен по навыкам вождения CDL. Источник: NH DMV, страница Commercial Driver Learner Permit; 49 CFR Part 380."},"82":{"q":"После выдачи CLP в Нью-Гэмпшире, сколько должен ждать его обладатель, прежде чем можно будет записаться на дорожный тест (тест по навыкам) CDL?","options":["Не менее 14 дней","Не менее 10 дней","Не менее 30 дней","Не менее 7 дней"],"explanation":"Нью-Гэмпшир применяет федеральное 14-дневное ожидание: после сдачи экзаменов на знания и выдачи CLP дорожный экзамен можно назначить не ранее чем через 14 дней с даты выдачи CLP. Источник: NH DMV, страница Commercial Driver Learner Permit; 49 CFR 383.25."},"83":{"q":"Тест по навыкам вождения CDL Нью-Гэмпшира состоит из трёх отдельных частей. В каком наборе они перечислены правильно?","options":["Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Письменный тест на знания, проверка зрения и вождение по дороге","Предрейсовый осмотр, демонстрация работы пневмотормозов и ночное вождение","Сцепка/расцепка, движение задним ходом и письменный экзамен на эндорсмент"],"explanation":"Тест по навыкам вождения CDL Нью-Гэмпшира состоит из трёх частей: предрейсовый осмотр (транспортного средства), тест базовых навыков управления транспортным средством и тест вождения по дороге. Тесты на знания и зрение являются отдельными предварительными условиями, а не частью теста по навыкам. Источник: NH DMV, страница CDL Road Test."},"84":{"q":"Сколько категорий коммерческой деятельности должен выбрать водитель при самосертификации для заявителей на CDL в Нью-Гэмпшире?","options":["Четыре","Две","Три","Пять"],"explanation":"Заявители на CDL в Нью-Гэмпшире должны самосертифицироваться в одну из четырёх категорий: межштатная неисключённая, межштатная исключённая, внутриштатная неисключённая и внутриштатная исключённая. Источник: форма самосертификации NH DMV DSMV 612."},"85":{"q":"Водитель в Нью-Гэмпшире самосертифицируется как «межштатный неисключённый» (interstate non-excepted). Что требует эта категория?","options":["Наличие действующего медицинского сертификата DOT Medical Examiner's Certificate в деле","Никакого медицинского сертификата любого вида","Только выданного штатом внутриштатного медицинского отказа","Идентификационного документа транспортного работника (TWIC) вместо медицинской карты"],"explanation":"Межштатные неисключённые водители работают за пределами штата в неисключённых перевозках и должны иметь и хранить в деле действующий DOT Medical Examiner's Certificate. Исключённые категории не обязаны предоставлять медицинскую карту. Источник: форма NH DMV DSMV 612; 49 CFR 383.71."},"86":{"q":"Какая форма Нью-Гэмпшира используется обладателями CDL для самосертификации своей категории деятельности и предоставления информации о медицинской карте в DMV?","options":["DSMV 612","DSMV 312","MCSA-5876","DSMV 500"],"explanation":"Нью-Гэмпшир использует форму DSMV 612 для самосертификации CDL и предоставления информации о медицинской карте/сертификации в DMV. DSMV 312 — это заявление на CDL; MCSA-5876 — это федеральный Medical Examiner's Certificate, заполняемый экзаменатором. Источник: NH DMV, CDL Medical Card Update; форма DSMV 612."},"87":{"q":"Каков минимальный проходной балл на письменном тесте на общие знания CDL в Нью-Гэмпшире?","options":["80%","70%","75%","90%"],"explanation":"Нью-Гэмпшир требует минимального проходного балла 80% на тесте на общие знания CDL (40 из 50 вопросов правильно). Источник: NH CDL Manual; требования NH DMV к тестированию знаний."},"88":{"q":"CDL Нью-Гэмпшира истекает в день рождения обладателя лицензии в каком году после выдачи?","options":["На пятый год","На четвёртый год","На шестой год","На десятый год"],"explanation":"Согласно RSA 263:93, коммерческое водительское удостоверение Нью-Гэмпшира истекает в день рождения обладателя лицензии на пятый год после выдачи, что составляет пятилетний цикл продления. Источник: NH RSA 263:93 (License Expiration and Renewal)."},"89":{"q":"Каков минимальный возраст для получения CDL Нью-Гэмпшира для внутриштатного вождения (только внутри штата)?","options":["18 лет","16 лет","21 год","19 лет"],"explanation":"Заявителю должно быть не менее 18 лет, чтобы иметь CDL Нью-Гэмпшира для внутриштатного вождения. Водители младше 21 года ограничены только внутриштатными перевозками. Источник: NH DMV, страница Commercial Driver Licenses."},"90":{"q":"Каков минимальный возраст для вождения между штатами (за пределами штата) или для получения эндорсмента HAZMAT на CDL Нью-Гэмпшира?","options":["21 год","18 лет","23 года","25 лет"],"explanation":"Обладателю CDL Нью-Гэмпшира должен быть не менее 21 года, чтобы водить в межштатных перевозках или иметь эндорсмент HAZMAT. Обладатели в возрасте 18-20 лет ограничены внутриштатным вождением. Источник: NH DMV, страница Commercial Driver Licenses; 49 CFR 383."},"91":{"q":"Какая форма является собственно заявлением на коммерческое водительское удостоверение Нью-Гэмпшира?","options":["DSMV 312","DSMV 612","MCSA-5875","DSMV 426"],"explanation":"Заявление на CDL Нью-Гэмпшира — это форма DSMV 312. DSMV 612 — это отдельная форма самосертификации/медицинской карты. Источник: формы CDL NH DMV; Apply for a CDL."},"92":{"q":"Помимо тестов на знания и навыки, какую проверку должен пройти каждый заявитель на CDL в Нью-Гэмпшире?","options":["Проверку зрения","Письменный экзамен по оказанию первой помощи","Анализ крови на наркотики и алкоголь, проводимый в DMV","Полосу препятствий на физическую ловкость"],"explanation":"Все заявители на CDL в Нью-Гэмпшире должны пройти проверку зрения в дополнение к тестам на знания и навыки. Источник: NH DMV, страница Commercial Driver Licenses."},"93":{"q":"Для дорожного теста CDL в Нью-Гэмпшире заявитель, как правило, должен предоставить какое тестовое транспортное средство?","options":["Представительное транспортное средство того же класса/типа, что и запрашиваемый CDL, с действующей наклейкой техосмотра","Любой легковой автомобиль с действующей регистрацией","Транспортное средство, предоставляемое бесплатно NH DMV","Арендованное транспортное средство массой менее 26,001 lbs GVWR независимо от класса"],"explanation":"Заявитель должен предоставить представительное тестовое транспортное средство, соответствующее классу/типу запрашиваемого CDL, надлежащим образом зарегистрированное и застрахованное, с действующей наклейкой техосмотра Нью-Гэмпшира. Источник: NH DMV, страница CDL Road Test."},"94":{"q":"Если медицинская сертификация обладателя CDL Нью-Гэмпшира истекает и обновлённый сертификат или вариация не предоставлены, в течение какого срока DMV должен понизить категорию CDL?","options":["60 дней","10 дней","30 дней","180 дней"],"explanation":"Согласно федеральному правилу о медицинской сертификации, которое применяет Нью-Гэмпшир, штат должен понизить категорию CDL или CLP в течение 60 дней после истечения, если не предоставлен действующий медицинский сертификат или вариация (или водитель не переходит в исключённую/внутриштатную категорию там, где это разрешено). Источник: 49 CFR 383.73; NH DMV CDL Medical Card Update."},"95":{"q":"Какой класс CDL Нью-Гэмпшира разрешает управление одиночным транспортным средством с GVWR 26,001 lbs или более (с буксировкой не более 10,000 lbs)?","options":["Класс B","Класс A","Класс C","Класс D"],"explanation":"CDL класса B охватывает любое одиночное транспортное средство с GVWR 26,001 lbs или более, либо такое транспортное средство, буксирующее единицу не более 10,000 lbs GVWR. Класс A охватывает составы свыше 26,001 lbs с буксируемой единицей свыше 10,000 lbs. Источник: NH DMV, страница License Classifications."},"96":{"q":"Прежде чем подать заявление на эндорсмент HAZMAT на CDL Нью-Гэмпшира, какой дополнительный федеральный шаг должен выполнить заявитель?","options":["Оценку угрозы безопасности TSA с проверкой биографии по отпечаткам пальцев","40-часовой курс OSHA по обращению с опасными материалами","Регистрацию перевозчика опасных отходов EPA","Повторный дорожный тест по навыкам на цистерне"],"explanation":"Заявители на эндорсмент HAZMAT должны пройти оценку угрозы безопасности TSA, которая включает снятие отпечатков пальцев и проверку биографии, в дополнение к тесту на знания HAZMAT. Источник: NH DMV, страница Commercial Driver Licenses; 49 CFR Part 1572."},"97":{"q":"Согласно модернизированному федеральному процессу медицинской сертификации, которому следует Нью-Гэмпшир (вступившему в силу в 2025 году), каким образом результаты большинства Medical Examiner's Certificate теперь поступают в штат?","options":["Медицинские экзаменаторы передают результаты в электронном виде в FMCSA, которое направляет их в штат для обновления водительского досье","Водители всегда должны лично доставлять бумажный сертификат в офис DMV","Работодатели отправляют сертификаты напрямую в FMCSA от имени водителя","Сертификаты подаются только страховщику водителя"],"explanation":"Согласно федеральному процессу, вступившему в силу 23 июня 2025 года, которому следует Нью-Гэмпшир, сертифицированные медицинские экзаменаторы передают результаты осмотра в электронном виде в FMCSA, которое передаёт статус медицинской сертификации в штат для обновления досье CDL; водители по-прежнему должны самосертифицировать свою категорию деятельности (например, через DSMV 612). Источник: правило FMCSA о медицинской сертификации; NH DMV CDL Medical Card Update."},"98":{"q":"19-летний человек сдаёт все тесты CDL в Нью-Гэмпшире и квалифицируется для получения CDL. Какое ограничение деятельности применяется?","options":["Он ограничен внутриштатными (в пределах Нью-Гэмпшира) перевозками до достижения 21 года","Он может водить между штатами, но не перевозить пассажиров","Он может водить между штатами только с эндорсментом HAZMAT","После сдачи тестов нет ограничений по возрасту"],"explanation":"Обладатель CDL Нью-Гэмпшира, которому не менее 18, но менее 21 года, ограничен только внутриштатным вождением; межштатные перевозки и HAZMAT требуют возраста 21 год. Источник: NH DMV, страница Commercial Driver Licenses; 49 CFR 391.11."}},"tr":{"0":{"q":"New Hampshire yollarında, aşırı boyut izni gerekmeden önce bir aracın yükü dahil izin verilen azami genişliği nedir?","options":["96 inches","102 inches","108 inches","114 inches"],"explanation":"New Hampshire RSA 266:12, yükü dahil genişliği 102 inches (8 feet 6 inches) aşan herhangi bir aracın kullanılmasını yasaklar. Bu, National Network için federal standartla uyumludur. Kaynak: NH RSA 266:12 Width; NH CDL Manual."},"1":{"q":"İzin gerekmeden New Hampshire yollarında izin verilen standart bir aracın (prefabrik konut taşımayan) yükü dahil azami yüksekliği nedir?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"explanation":"New Hampshire RSA 266:10, yükü dahil toplam yüksekliği 13 feet 6 inches'ten fazla olan hiçbir aracın (prefabrik konut veya modüler bina taşıyanlar hariç) eyalet yollarında kullanılamayacağını belirtir. Kaynak: NH RSA 266:10 Height."},"2":{"q":"New Hampshire'da, izinsiz çalışan bir çekici/yarı römork kombinasyonunda bir yarı römorkun azami uzunluğu nedir?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"New Hampshire RSA 266:11, bir çekici ve tek yarı römork kombinasyonunda 53 feet'e kadar yarı römorka izin verir (48 feet'i aşan römorklar için ek kingpin ve arka koruma gereksinimleri vardır). Kaynak: NH RSA 266:11 Length."},"3":{"q":"New Hampshire yasalarına göre, fazla ağırlık izni olmadan çalışan beş veya daha fazla akslı bir kombinasyon aracın (tüm kolluk kuvveti toleransları dahil) azami brüt araç ağırlığı nedir?","options":["73,280 pounds","80,000 pounds","84,000 pounds","90,000 pounds"],"explanation":"New Hampshire, 5 veya daha fazla akslı bir kombinasyon için azami brüt ağırlığı, federal sınırla uyumlu olarak, tüm kolluk kuvveti toleransları dahil 80,000 pounds ile sınırlar. Kaynak: NH RSA 266:18 / 266:18-a."},"4":{"q":"New Hampshire'ın Interstate ve Defense Highway System'inde izinsiz olarak izin verilen azami tek aks ağırlığı nedir?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Interstate ve Defense Highway System'de, New Hampshire RSA 266:18, tek bir aksı federal Interstate standardıyla uyumlu olarak 20,000 pounds ile sınırlar. (22,400 lb gibi daha yüksek değerler yalnızca belirli Interstate dışı yapılandırmalar için geçerlidir.) Kaynak: NH RSA 266:18."},"5":{"q":"New Hampshire'ın Interstate ve Defense Highway System'inde bir tandem aks üzerinde izin verilen azami ağırlık nedir?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"New Hampshire RSA 266:18, Interstate ve Defense Highway System'de bir tandem aksı federal standartla aynı olacak şekilde 34,000 pounds ile sınırlar. Kaynak: NH RSA 266:18."},"6":{"q":"New Hampshire'ın fazla ağırlık denetimi, brüt ağırlığı aks aralığı ve aks sayısıyla ilişkilendiren bir ağırlık dağılımı formülü kullanır. Bu formül genellikle hangi adla bilinir?","options":["Federal bridge formula","Kingpin setback formula","Gross combination rating formula","Tare weight formula"],"explanation":"New Hampshire RSA 266:18, federal bridge formula olan W = 500[LN/(N-1) + 12N + 36] formülünü içerir; burada W bir aks grubundaki brüt ağırlık, L uç akslar arasındaki mesafe ve N aks sayısıdır. Kaynak: NH RSA 266:18."},"7":{"q":"New Hampshire bridge formülünde W = 500[LN/(N-1) + 12N + 36], 'N' değişkeni neyi temsil eder?","options":["Gruptaki aks sayısı","Yükün net ağırlığı","Römork sayısı","Nominal lastik genişliği"],"explanation":"New Hampshire (RSA 266:18) tarafından benimsenen bridge formülünde, N söz konusu gruptaki aks sayısına eşittir; L uç akslar arasındaki feet cinsinden mesafe ve W ortaya çıkan izin verilen brüt ağırlıktır. Kaynak: NH RSA 266:18."},"8":{"q":"New Hampshire yollarında üçlü römorklu kamyon kombinasyonları:","options":["Yalnızca Interstate'lerde izinlidir","Yıllık izinle izinlidir","Yasaktır","Yalnızca gece izinlidir"],"explanation":"New Hampshire RSA 266:11-b, eyalet yollarında üçlü römorklu kamyonların çalıştırılmasını yasaklar. Kaynak: NH RSA 266:11-b Triple Trailer Trucks Prohibited."},"9":{"q":"Bir taşıyıcının New Hampshire'ın yasal boyut veya ağırlık sınırlarını aşan bir yükü taşıması gerekiyor. Gerekli aşırı boyut/aşırı ağırlık iznini hangi kurum verir?","options":["Yerel kasaba yol görevlisi","New Hampshire Department of Transportation","Federal Motor Carrier Safety Administration","İlçe şerif ofisi"],"explanation":"New Hampshire'da aşırı boyut/aşırı ağırlık (OSOW) izinleri, izin ofisi aracılığıyla NH Department of Transportation tarafından verilir (başvurular çevrimiçi, 7 Hazen Drive, Concord adresinde şahsen veya telefonla yapılır). Kaynak: NHDOT Permits / OSOW Permit Office."},"10":{"q":"New Hampshire'da aşırı boyutlu veya aşırı ağırlıklı bir yükün genellikle hangi saatlerde seyahat etmesine izin verilir?","options":["Günde 24 saat, herhangi bir gün","Pazartesiden Cumaya, gün doğumundan yarım saat önce gün batımından yarım saat sonrasına kadar","Yalnızca her gün 9:00 p.m. ile 5:00 a.m. arasında","İşe gidiş geliş trafiğinden kaçınmak için yalnızca hafta sonları"],"explanation":"NHDOT OSOW izin kurallarına göre, aşırı boyut/aşırı ağırlık yükleri genellikle Pazartesiden Cumaya gün doğumundan yarım saat önce gün batımından yarım saat sonrasına kadar seyahat edebilir; aşırı boyutlu yüklerin hafta sonu ve tatil seyahatine izin verilmez. Kaynak: NHDOT OSOW Permit travel restrictions."},"11":{"q":"İzin gerekmeden New Hampshire yollarında ön ve arka tamponlar dahil tek üniteli bir araç veya otobüsün azami uzunluğu nedir?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"New Hampshire RSA 266:11, tek üniteli bir araç veya otobüsü ön ve arka tamponlar dahil 45 feet ile sınırlar. Kaynak: NH RSA 266:11 Length."},"12":{"q":"Bir araç New Hampshire'da prefabrik konut veya modüler bina taşırken, izin verilen azami yükseklik:","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"New Hampshire RSA 266:10, prefabrik konut veya modüler bina taşıyan araçlar için azami 14 feet 6 inches yüksekliğe izin verir; 13 feet 6 inches'ı aşan yükler polis dışı bir refakat gerektirir. Kaynak: NH RSA 266:10 Height."},"13":{"q":"New Hampshire'ın Interstate dışı (genel) karayolu sisteminde, 3 akslı tek üniteli bir araçtaki tek bir aks azami ne kadar taşıyabilir?","options":["18,000 pounds","20,000 pounds","22,400 pounds","25,000 pounds"],"explanation":"New Hampshire RSA 266:18-a, Interstate dışı genel karayolu sisteminde 3 akslı tek üniteli araçlarda (ve aksları 10 feet veya daha fazla aralıklı diğer araçlarda) aks başına 22,400 pounds'a kadar izin verir; bu, 20,000 pound'luk Interstate sınırından daha yüksektir. Kaynak: NH RSA 266:18-a."},"14":{"q":"New Hampshire'da işlenmemiş orman ürünleri taşıyan dört veya daha fazla akslı bir çekici ve tek yarı römork kombinasyonunda, bir tandem aks üzerindeki azami ağırlık şu değere yükseltilir:","options":["34,000 pounds","36,000 pounds","40,000 pounds","44,000 pounds"],"explanation":"New Hampshire RSA 266:18-b, işlenmemiş orman ürünleri (işlenmemiş tomruk ve odun yongası) taşıyan 4 veya daha fazla akslı bir çekici ve tek yarı römork kombinasyonu için bir tandem aksın 40,000 pounds'a kadar taşımasına izin verir. Kaynak: NH RSA 266:18-b."},"15":{"q":"New Hampshire yasaları, denetim görevlilerinin ihlal düzenlemeden önce ilan edilen aks grubu ve brüt ağırlık sınırlarının üzerinde hangi genel toleransa izin vermesine yetki verir?","options":["1 percent","2 percent","5 percent","15 percent"],"explanation":"New Hampshire RSA 266:18-a ve 266:18-c, belirtilen ağırlık sınırlamalarının 5 percent üzerinde bir toleransa yetki verir (266:18-c kapsamında belirli aks ağırlıklarında 10 percent'e kadar izin verilir). Kaynak: NH RSA 266:18-a / 266:18-c."},"16":{"q":"Interstate sisteminde, New Hampshire'da iki ardışık tandem aks seti, ancak bu tandem setlerinin ilk ve son aksları arasındaki mesafe en az şu değer olduğunda her biri 34,000 pounds taşıyabilir:","options":["28 feet","30 feet","36 feet","40 feet"],"explanation":"New Hampshire RSA 266:18, iki ardışık tandem aks setinin her birinin yalnızca ilk ve son akslar arasındaki toplam mesafe 36 feet veya daha fazla olduğunda ve toplam brüt ağırlık 80,000 pounds'u aşmadığında her biri 34,000 pounds taşımasına izin verir. Kaynak: NH RSA 266:18."},"17":{"q":"New Hampshire'ın Interstate dışı genel karayolu sisteminde, beş veya daha fazla akslı bir kombinasyon için azami tandem aks ağırlığı nedir?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"New Hampshire RSA 266:18-a, Interstate dışı genel karayolu sisteminde 5 veya daha fazla akslı bir kombinasyondaki bir tandem aksın 36,000 pounds'a kadar taşımasına izin verir; bu, 34,000 pound'luk Interstate tandem sınırından daha yüksektir. Kaynak: NH RSA 266:18-a."},"18":{"q":"New Hampshire merkezli bir taşıyıcı, en fazla 75 feet uzunluğunda, 10 feet 6 inches genişliğinde ve 13 feet 6 inches yüksekliğinde bir aracın eyalet genelinde seyahati için yıllık aşırı boyut izni istiyor. Eyalet genelinde seyahat için belirtilen yıllık izin ücreti nedir?","options":["$60.00","$115.00","$200.00","$300.00"],"explanation":"NHDOT, NH merkezli ve kayıtlı taşıyıcılar için, belirtilen 75 ft / 10 ft 6 in / 13 ft 6 in sınırları içindeki araçlar için yıllık aşırı boyut izni ücretini eyalet genelinde seyahat için $115.00 (veya 100 mil yarıçap içinde seyahat için $60.00) olarak listeler. Kaynak: NHDOT OSOW Permit fees."},"19":{"q":"New Hampshire RSA 266:16 kapsamında, izin verilen boyut sınırlarını aşan bir aracı kullanmanın ilk ihlali için ceza şu tutarda bir para cezasıdır:","options":["En fazla $100","En fazla $250","En fazla $500","En fazla $1,000"],"explanation":"New Hampshire RSA 266:16, izin verilen boyutu aşma cezasını ilk ihlal için en fazla $100 ve aynı takvim yılı içindeki sonraki bir ihlal için en fazla $250 para cezası olarak belirler. Kaynak: NH RSA 266:16 Penalty for Exceeding Permitted Size."},"20":{"q":"New Hampshire CDL kurallarına göre, çekilen ünitenin GVWR'si 10,000 pounds'un üzerinde olması koşuluyla, brüt kombinasyon ağırlık derecesi (GCWR) 26,001 pounds veya daha fazla olan bir araç kombinasyonunu kullanmak için hangi ehliyet sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"New Hampshire, Class A CDL'yi GCWR'si 26,001 lbs veya daha fazla olan ve çekilen ünitenin GVWR'sinin 10,000 lbs'yi aştığı herhangi bir araç kombinasyonu olarak tanımlar. Kaynak: NH DMV License Classifications, Restrictions and Endorsements sayfası; NH Commercial Driver's Manual."},"21":{"q":"New Hampshire'da, GVWR'si 26,001 pounds veya daha fazla olan herhangi bir TEK aracı veya 10,000 pounds GVWR'yi aşmayan bir ünite çeken böyle bir aracı hangi CDL sınıfı kapsar?","options":["Class A","Class B","Class C","Class M"],"explanation":"NH, Class B CDL'yi GVWR'si 26,001 lbs veya daha fazla olan tek bir araç veya 10,000 lbs GVWR'yi aşmayan bir ünite çeken böyle bir araç olarak tanımlar. Kaynak: NH DMV License Classifications sayfası; NH Commercial Driver's Manual."},"22":{"q":"New Hampshire'lı bir sürücü, sürücü dahil 18 yolcu taşımak üzere tasarlanmış 26,001 lbs altında tek bir aracı kullanır. Bu hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","CDL gerekmez"],"explanation":"NH, Class C CDL'yi Class A veya B'ye uymayan ve 16 veya daha fazla yolcu (sürücü dahil) taşıyan, tehlikeli maddeler için plaketlenmiş veya bir tank aracı olan bir araç olarak tanımlar. 18 yolcu kapasiteli bir araç Class C kapsamına girer. Kaynak: NH DMV License Classifications sayfası."},"23":{"q":"INTRASTATE (yalnızca New Hampshire içinde) çalışmayla sınırlı bir New Hampshire CDL'si almak için asgari yaş nedir?","options":["16 yaşında","18 yaşında","21 yaşında","25 yaşında"],"explanation":"New Hampshire'da bir ticari motorlu aracı intrastate (NH içinde) kullanmak için en az 18 yaşında olmalısınız. Kaynak: NH DMV Commercial Driver Licenses sayfası; NH Commercial Driver's Manual."},"24":{"q":"INTERSTATE (eyalet sınırları ötesinde) ticari sürüş için geçerli bir New Hampshire CDL'si almak için asgari yaş nedir?","options":["18 yaşında","19 yaşında","21 yaşında","23 yaşında"],"explanation":"New Hampshire (federal standardı izleyerek), sürücülerin eyaletler arası ticarette bir ticari motorlu aracı kullanmak için en az 21 yaşında olmasını gerektirir. 18-20 yaş arası sürücüler intrastate çalışmayla sınırlıdır. Kaynak: NH DMV Commercial Driver Licenses sayfası."},"25":{"q":"New Hampshire ve federal kurallara göre, bir başvuru sahibinin CDL beceri (yol) testine girmesine izin verilmeden önce bir Commercial Learner Permit (CLP) ne kadar süre elinde bulundurması gerekir?","options":["7 days","10 days","14 days","30 days"],"explanation":"Bir başvuru sahibi, CDL beceri testine girmeden önce CLP'yi en az 14 days elinde bulundurmalıdır. Bu, NH tarafından uygulanan federal bir gerekliliktir. Kaynak: NH DMV Commercial Driver Learner Permit sayfası; 49 CFR 383.25."},"26":{"q":"Bir New Hampshire Commercial Driver Learner Permit sahibi bir ticari motorlu aracı kullandığında, kendisine kim eşlik etmelidir?","options":["18 yaş veya üzeri herhangi bir ehliyetli sürücü","O araç tipi için geçerli bir CDL'ye sahip, izin sahibinin hemen yanında oturan 25 yaş veya üzeri bir kişi","Araçta herhangi bir yerde oturan herhangi bir CDL sahibi","Yalnızca bir New Hampshire DMV sınav görevlisi"],"explanation":"NH, CLP sahibine, kullanılan araç tipi için geçerli bir CDL'ye sahip ve izin sahibinin hemen yanındaki koltukta oturan 25 yaş veya üzeri bir kişinin eşlik etmesini gerektirir. Kaynak: NH DMV Commercial Driver Learner Permit sayfası."},"27":{"q":"Plaketleme gerektiren miktarlarda tehlikeli madde taşımak için bir New Hampshire CDL'sinde hangi onay kodu gereklidir?","options":["N onayı","H onayı","T onayı","X onayı"],"explanation":"H (HazMat) onayı, eyalet veya federal düzenlemeler uyarınca plaketlenmesi gereken tehlikeli maddeleri taşıyan herhangi bir ticari aracı kullanmak için gereklidir. Kaynak: NH DMV HazMat Endorsement sayfası."},"28":{"q":"Bir New Hampshire sürücüsüne HazMat (H) onayı verilmeden önce, federal olarak hangi ek tarama gereklidir?","options":["Bir TSA güvenlik tehdidi değerlendirmesi (parmak izi tabanlı geçmiş kontrolü)","Bir FBI poligraf sınavı","Bir New Hampshire State Police görüşmesi","Yalnızca bir DOT uyuşturucu testi"],"explanation":"H onayı için başvuranlar, HazMat bilgi testine ek olarak, parmak izi tabanlı geçmiş kontrolünü içeren bir Transportation Security Administration (TSA) güvenlik tehdidi değerlendirmesinden geçmelidir. Kaynak: NH DMV HazMat Endorsement sayfası; 49 CFR 1572."},"29":{"q":"Bir New Hampshire CDL'sinde, bir tank aracını (sıvı veya gazları dökme olarak taşımak için kullanılan) kullanmak için hangi onay gereklidir?","options":["H onayı","T onayı","N onayı","P onayı"],"explanation":"N (Tank Vehicle) onayı, sıvı veya gazları dökme olarak taşımak üzere tasarlanmış bir tank aracını kullanmak için gereklidir. Kaynak: NH DMV License Classifications, Restrictions and Endorsements sayfası."},"30":{"q":"İkili veya üçlü römork çekmek için hangi New Hampshire CDL onayı gereklidir?","options":["T onayı","N onayı","D onayı","X onayı"],"explanation":"İkili veya üçlü römork çekmek için T onayı (Doubles/Triples) gereklidir. Bir bilgi testini geçerek alınır; bunun için ayrı bir beceri testi gerekmez. Kaynak: NH DMV License Classifications sayfası; NH Commercial Driver's Manual."},"31":{"q":"New Hampshire, sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış bir ticari aracı kullanmak için hangi onayı gerektirir?","options":["S onayı","P onayı","N onayı","T onayı"],"explanation":"P (Passenger) onayı, sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış herhangi bir ticari aracı kullanmak için gereklidir. Kaynak: NH DMV Commercial Driver Licenses sayfası."},"32":{"q":"New Hampshire School Bus (S) onayını almak için, başvuru sahibi genellikle ayrıca neye ihtiyaç duyar?","options":["Bir HazMat (H) onayı","Bir Tank (N) onayı","Bir Passenger (P) onayı","Bir Doubles/Triples (T) onayı"],"explanation":"Bir okul otobüsü 16 veya daha fazla yolcu taşır, bu nedenle NH, School Bus (S) bilgi testini ve bir yolcu aracı yol beceri testini geçmeye ek olarak Passenger (P) onayını gerektirir. Kaynak: NH DMV School Bus Drivers sayfası."},"33":{"q":"New Hampshire, bir Commercial Learner Permit almaya hak kazanmak için CDL genel bilgi yazılı testinde hangi asgari geçer notu gerektirir?","options":["70%","75%","80%","90%"],"explanation":"New Hampshire, genel bilgi testi dahil CDL bilgi sınavlarında 80% veya daha yüksek bir puan gerektirir. Kaynak: NH DMV Commercial Driver Learner Permit sayfası; NH Commercial Driver's Manual."},"34":{"q":"Belirli New Hampshire CDL beceri/bilgi testlerinden önce alınan Entry-Level Driver Training (ELDT) hangi yolla tamamlanmalıdır?","options":["Herhangi bir New Hampshire community college","FMCSA Training Provider Registry (TPR) üzerinde listelenen bir sağlayıcı","New Hampshire DMV'nin kendi eğitim bölümü","Kayıt gerekmeden, işveren tarafından yürütülen herhangi bir program"],"explanation":"ELDT, FMCSA Training Provider Registry (TPR) üzerinde listelenen bir sağlayıcı aracılığıyla tamamlanmalıdır; sağlayıcı kendi kendini sertifikalandırır ve tamamlama kayıtlarını FMCSA'ya gönderir. Kaynak: FMCSA ELDT / Training Provider Registry; NH DMV CDL sayfaları."},"35":{"q":"Aşağıdakilerden hangisi, bir New Hampshire başvuru sahibinin ilgili teste girebilmesi için önce ELDT (Entry-Level Driver Training) gerektirir?","options":["Bir Doubles/Triples (T) onayı eklemek","Bir Tank (N) onayı eklemek","İlk kez bir Class A CDL almak","Sınıf değişikliği olmadan mevcut bir Class B CDL'yi yenilemek"],"explanation":"Federal ELDT kuralları (7 Şubat 2022'de yürürlüğe girmiştir), ilk kez bir Class A veya B CDL almaya, Class B'den Class A'ya yükseltmeye ve ilk kez bir H, P veya S onayı almaya uygulanır. N ve T onayları ile basit yenilemeler ELDT gerektirmez. Kaynak: FMCSA ELDT regulations; NH DMV CDL sayfaları."},"36":{"q":"Bir New Hampshire CDL'sine başvururken, eyalet sınırları ötesinde çalışan ve federal DOT tıbbi sertifika gerekliliğini karşılaması gereken bir sürücüyü hangi öz sertifikasyon kategorisi gösterir?","options":["Interstate non-excepted","Intrastate excepted","Interstate excepted","Intrastate non-excepted"],"explanation":"NH, dört federal öz sertifikasyon kategorisini kullanır. 'Interstate non-excepted', eyalet sınırları ötesinde çalışan ve dosyasında geçerli bir DOT tıbbi sertifikası bulundurması gereken sürücüleri kapsar. Kaynak: NH DMV CDL Medical Card Update sayfası; 49 CFR 383.71."},"37":{"q":"Bir New Hampshire CDL'sine veya Commercial Learner Permit'e başvurmak için, bir başvuru sahibi genellikle hangi belge kombinasyonunun kanıtını sunmalıdır?","options":["Yalnızca kimlik","Yalnızca kimlik ve Social Security Number","Kimlik, Social Security Number ve New Hampshire ikametgahı/yasal varlık","Tüm gereksinimleri karşılayan yalnızca bir pasaport"],"explanation":"New Hampshire, başvuru sahiplerinin kimliklerini kanıtlamasını, Social Security Number'ı gösteren bir belge sunmasını ve NH ikametgahı ile yasal varlığı belirleyen belgeler sunmasını gerektirir. Kaynak: NH DMV Required Documents / Commercial Driver Learner Permit sayfaları."},"38":{"q":"Bir New Hampshire Commercial Driver Learner Permit (CLP) yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["30 days","60 days","180 days","365 days"],"explanation":"Bir New Hampshire CLP'si 180 days geçerlidir ve gerekli bilgi testlerinin bir yıllık süre içinde geçilmiş olması koşuluyla bir kez yenilenebilir. Bu, federal CLP geçerlilik standardını izler. Kaynak: NH DMV Commercial Driver Learner Permit sayfası; 49 CFR 383.25."},"39":{"q":"19 yaşındaki bir New Hampshire sakini bir CDL istiyor. 21 yaşına gelene kadar hangi ayrıcalığa hak kazanamaz?","options":["Bir Class B CDL'ye sahip olmak","New Hampshire içinde intrastate çalışmak","Bir HazMat (H) onayı almak","Bir Tank (N) onayı almak"],"explanation":"21 yaşından küçük New Hampshire başvuru sahipleri intrastate çalışmayla sınırlıdır ve HazMat (H) veya eyaletler arası Passenger ayrıcalıklarını alamaz; H onayı özellikle başvuru sahibinin en az 21 yaşında olmasını gerektirir. Kaynak: NH DMV Commercial Driver Licenses / HazMat Endorsement sayfaları."},"40":{"q":"New Hampshire'da, bir kişinin yasal olarak bir ticari motorlu aracı (CMV) kullanabileceği azami kan alkol konsantrasyonu (BAC) nedir?","options":["0.04","0.08","0.02","0.10"],"explanation":"New Hampshire, bir CMV kullanmak için BAC sınırını, ticari olmayan sürücüler için olan 0.08 sınırının yarısı olan 0.04 olarak belirler. Kaynak: NH CDL Manual (alkol/uyuşturucu bölümü); RSA 265-A:2."},"41":{"q":"New Hampshire yollarında bir ticari motorlu araç kullanarak, bir CDL sahibi yasal olarak alkol veya uyuşturucu için kimyasal test konusunda ne yapmış sayılır?","options":["Yasal olarak talep edilmesi halinde test yaptırmaya zımni rıza göstermiş sayılır","Gelecekteki herhangi bir CDL hakkından feragat etmiş sayılır","Sabit bir $500 test ücreti ödemeyi kabul etmiş sayılır","Yalnızca nefes testine rıza göstermiş, ancak kana rıza göstermemiş sayılır"],"explanation":"New Hampshire'ın zımni rıza yasası uyarınca, eyalette araç kullanan herkes, yasal olarak talep edildiğinde alkol konsantrasyonunu belirlemek için kimyasal teste rıza göstermiş sayılır. Kaynak: RSA 265-A:4; NH CDL Manual."},"42":{"q":"İlk büyük suç için (CMV'de bir DUI gibi), New Hampshire'da asgari CDL diskalifiye süresi nedir?","options":["1 year","60 days","6 months","3 years"],"explanation":"İlk büyük suç, New Hampshire'da bir sürücüyü bir CMV kullanmaktan en az bir yıl boyunca diskalifiye eder. Kaynak: RSA 263:94; 49 CFR 383.51; NH CDL Manual."},"43":{"q":"Bir New Hampshire sürücüsü, tehlikeli maddeler için plaketlenmiş bir CMV kullanırken ilk büyük suçu işlerse, asgari diskalifiye süresi:","options":["3 years","1 year","120 days","Ömür boyu"],"explanation":"Plaketlenmiş tehlikeli madde taşırken işlenen ilk büyük suç, asgari diskalifiye süresini bir yıldan üç yıla çıkarır. Kaynak: RSA 263:94; 49 CFR 383.51."},"44":{"q":"Ayrı bir olaydan kaynaklanan ikinci bir büyük suç için (örneğin, bir CMV'de ikinci bir DUI) New Hampshire'daki diskalifiye süresi nedir?","options":["Ömür boyu","10 years","5 years","3 years"],"explanation":"Ayrı bir olaydan kaynaklanan ikinci bir büyük suç mahkumiyeti, bir CMV kullanmaktan ömür boyu diskalifiye ile sonuçlanır. Kaynak: RSA 263:94; 49 CFR 383.51."},"45":{"q":"Bir New Hampshire CDL sahibi, bir CMV kullanırken kimyasal test yaptırmayı reddeder. İlk ret için, asgari CDL diskalifiye süresi:","options":["1 year","90 days","6 months","30 days"],"explanation":"Yasal olarak talep edilen bir kimyasal testi reddetmek büyük bir suç olarak ele alınır; ilk ret asgari bir yıllık CDL diskalifiyesi taşır (hazmat için plaketlenmişse üç yıl). Kaynak: RSA 263:94; RSA 265-A:4."},"46":{"q":"Bir New Hampshire CDL sahibi kimyasal testi ikinci kez reddederse (ayrı bir olay), CDL diskalifiyesi:","options":["Ömür boyu","5 years","2 years","1 year"],"explanation":"Kimyasal testi reddetmenin ikinci örneği, herhangi bir ikinci büyük suç gibi, ömür boyu CDL diskalifiyesi ile sonuçlanır. Kaynak: RSA 263:94; 49 CFR 383.51."},"47":{"q":"New Hampshire'da, 3 yıl içinde ayrı olaylardan kaynaklanan bir CMV'de İKİ ciddi trafik ihlalinden mahkum olmak, en az şu süreyle CDL diskalifiyesi ile sonuçlanır:","options":["60 days","30 days","120 days","1 year"],"explanation":"3 yıllık bir süre içinde iki ciddi trafik ihlali, bir sürücüyü bir CMV kullanmaktan en az 60 days boyunca diskalifiye eder. Kaynak: RSA 263:94; 49 CFR 383.51."},"48":{"q":"3 yıl içinde ayrı olaylardan kaynaklanan bir CMV'de ÜÇ ciddi trafik ihlalinden mahkum olmak, en az şu süreyle bir New Hampshire CDL diskalifiyesi ile sonuçlanır:","options":["120 days","60 days","90 days","1 year"],"explanation":"3 yıllık bir süre içinde üç ciddi trafik ihlali, bir sürücüyü bir CMV kullanmaktan en az 120 days boyunca diskalifiye eder. Kaynak: RSA 263:94; 49 CFR 383.51."},"49":{"q":"New Hampshire'ın CDL kuralları uyarınca, tek bir hız ihlali, ilan edilen sınırın üzerinde hangi hızda 'ciddi trafik ihlali' haline gelir?","options":["Sınırın 15 mph veya daha fazla üzerinde","Sınırın 10 mph veya daha fazla üzerinde","Sınırın 20 mph veya daha fazla üzerinde","Sınırın 25 mph veya daha fazla üzerinde"],"explanation":"İlan edilen sınırın 15 mph veya daha fazla üzerinde hız yapmak, New Hampshire'da CDL amaçları için ciddi bir trafik ihlali olarak tanımlanır. Kaynak: RSA 259:98-a; N.H. Admin. Code Saf-C 1809.02."},"50":{"q":"Aşağıdakilerden hangisi bir New Hampshire CDL sahibi için 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Çok yakından takip etmek (arkadan yapışmak)","Bir yangın şeridine park etmek","Sınırın 5 mph üzerinde araç kullanmak","Süresi dolmuş bir kayıt etiketi"],"explanation":"Çok yakından takip etmek, dikkatsiz araç kullanma, düzensiz şerit değişiklikleri ve aşırı hız ile birlikte CDL sahipleri için sayılan ciddi trafik ihlallerinden biridir. Kaynak: RSA 259:98-a; Saf-C 1809.02."},"51":{"q":"New Hampshire'da bir CMV kullanırken bir demiryolu-karayolu hemzemin geçit ihlalinden İLK mahkumiyet için, asgari diskalifiye süresi:","options":["60 days","30 days","120 days","1 year"],"explanation":"Bir CMV'de ilk demiryolu-karayolu hemzemin geçit ihlali asgari 60 günlük bir diskalifiye taşır. Kaynak: New Hampshire tarafından benimsenen 49 CFR 383.51 Table 3; NH CDL Manual."},"52":{"q":"3 yıl içinde bir CMV'de İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali, en az şu süreyle bir New Hampshire CDL diskalifiyesi ile sonuçlanır:","options":["120 days","60 days","90 days","1 year"],"explanation":"3 yıl içinde ikinci bir hemzemin geçit ihlali asgari 120 günlük bir diskalifiye taşır. Kaynak: New Hampshire tarafından benimsenen 49 CFR 383.51 Table 3."},"53":{"q":"3 yıl içinde bir CMV'de ÜÇÜNCÜ veya sonraki bir demiryolu-karayolu hemzemin geçit ihlali, en az şu süreyle bir New Hampshire CDL diskalifiyesi ile sonuçlanır:","options":["1 year","120 days","180 days","60 days"],"explanation":"3 yıl içinde üçüncü veya sonraki bir hemzemin geçit ihlali asgari 1 year'lık bir diskalifiye taşır. Kaynak: New Hampshire tarafından benimsenen 49 CFR 383.51 Table 3."},"54":{"q":"New Hampshire'da, bir hizmet dışı (OOS) emri altında bir CMV kullanmanın İLK ihlali (hazmat dışı) şu süreyle bir diskalifiye ile sonuçlanır:","options":["180 days'den az olmayan ve 1 year'dan fazla olmayan","60 days'den az olmayan ve 120 days'den fazla olmayan","30 days'den az olmayan ve 90 days'den fazla olmayan","2 years'dan az olmayan ve 5 years'dan fazla olmayan"],"explanation":"İlk hizmet dışı emri ihlali, sürücüyü 180 days'den az olmayan ve 1 year'dan fazla olmayan bir süre için diskalifiye eder. Kaynak: New Hampshire tarafından benimsenen 49 CFR 383.51 Table 4; NH CDL Manual."},"55":{"q":"10 yıl içinde bir CMV'de İKİNCİ bir hizmet dışı (OOS) emri ihlali, şu süreyle bir New Hampshire diskalifiyesi ile sonuçlanır:","options":["2 years'dan az olmayan ve 5 years'dan fazla olmayan","180 days'den az olmayan ve 1 year'dan fazla olmayan","1 year'dan az olmayan ve 3 years'dan fazla olmayan","Ömür boyu"],"explanation":"10 yıl içinde ikinci bir OOS emri ihlali, 2 years'dan az olmayan ve 5 years'dan fazla olmayan bir diskalifiye taşır. Kaynak: New Hampshire tarafından benimsenen 49 CFR 383.51 Table 4."},"56":{"q":"Plaketlenmiş tehlikeli madde taşıyan veya 16+ yolcu için tasarlanmış bir araç kullanan bir sürücü, New Hampshire'da İLK bir hizmet dışı emri ihlalini işler. Diskalifiye süresi:","options":["180 days'den az olmayan ve 2 years'dan fazla olmayan","180 days'den az olmayan ve 1 year'dan fazla olmayan","60 days'den az olmayan ve 120 days'den fazla olmayan","3 years'dan az olmayan ve 5 years'dan fazla olmayan"],"explanation":"Plaketlenmiş hazmat taşırken veya 16+ yolcu kapasiteli bir araçta işlenen ilk OOS ihlali, 180 days'den az olmayan ve 2 years'dan fazla olmayan yükseltilmiş bir süre taşır. Kaynak: New Hampshire tarafından benimsenen 49 CFR 383.51 Table 4."},"57":{"q":"New Hampshire'ın hands-free yasası uyarınca, araç kullanırken elde tutulan bir mobil elektronik cihazı kullanmanın İLK ihlali için para cezası nedir?","options":["$100","$50","$250","$500"],"explanation":"New Hampshire'ın hands-free yasası, ilk ihlale $100, ikinciye $250 ve 24 ay içindeki sonraki herhangi bir ihlale $500 para cezası verir. Elde tutarak kullanım, CMV operatörleri dahil tüm sürücüler için yasaktır. Kaynak: RSA 265:79-c."},"58":{"q":"New Hampshire'ın hands-free yasası (RSA 265:79-c) uyarınca, araç kullanırken elde tutulan bir elektronik cihazı kullanmanın İKİNCİ ihlali için para cezası nedir?","options":["$250","$100","$500","$150"],"explanation":"New Hampshire'ın hands-free yasasının ikinci ihlaline $250 para cezası verilir (ilk ihlal $100 ve 24 ay içindeki sonraki bir ihlal $500'dir). Kaynak: RSA 265:79-c."},"59":{"q":"New Hampshire'da ilk ve sonraki CDL diskalifiye edici suçları sayarken, mahkumiyetler hangi kurala göre toplanır?","options":["Bir CMV'de veya CMV olmayan bir araçta işlenmiş olsun, ayrı bir olaydan kaynaklanan her mahkumiyet sayılır","Yalnızca bir CMV kullanırken alınan mahkumiyetler sayılır","Yalnızca son 12 ay içindeki mahkumiyetler sayılır","Yalnızca hapis cezasıyla sonuçlanan mahkumiyetler sayılır"],"explanation":"İlk ve sonraki diskalifiye edici ihlalleri belirlemek için, suç ticari veya ticari olmayan bir araçta meydana gelmiş olsun, ayrı bir olaydan kaynaklanan her mahkumiyet sayılır. Kaynak: RSA 263:94; 49 CFR 383.51."},"60":{"q":"New Hampshire'in Move Over (Şeritten Çekilme) yasası uyarınca, bir CDL sürücüsü banketde durmuş ve mavi, kırmızı veya sarı uyarı ışıkları yanan bir araca yaklaşırken ne yapmalıdır?","options":["Hızını düşürmeli ve mümkünse araca geniş bir mesafe bırakmak için şerit değiştirmeli","Hızını korumalı ancak geçerken kornaya sürekli basmalı","Araç ayrılana kadar gidiş şeridinde tamamen durmalı","Yasa yalnızca polis araçları için geçerli olduğundan belirlenen hızda devam etmeli"],"explanation":"New Hampshire'in Move Over yasası (RSA 265:37-a), bir sürücünün hızını düşürmesini ve mümkünse kamu güvenliği personeline ve mavi, kırmızı veya sarı acil durum ya da uyarı ışığı yanan herhangi bir durmuş araca geniş mesafe bırakmasını, güvenli olduğunda kapalı şeritten çıkmasını gerektirir. Kaynak: NH RSA 265:37-a; NH CDL Manual."},"61":{"q":"New Hampshire'de, demiryolu raylarını geçmeden önce plakartlı tehlikeli madde taşıyan bir araç veya çocuk taşıyan bir okul otobüsü en yakın raya hangi mesafe içinde durmalıdır?","options":["15 fitten az ve 50 fitten fazla olmamak üzere","5 fitten az ve 25 fitten fazla olmamak üzere","25 fitten az ve 75 fitten fazla olmamak üzere","50 fitten az ve 100 fitten fazla olmamak üzere"],"explanation":"RSA 265:50, yolcu taşıyan otobüslerin, çocuk taşıyan okul otobüslerinin ve patlayıcı/tehlikeli madde taşıyan araçların sürücülerinin en yakın raya 50 fit içinde ancak 15 fitten az olmayacak şekilde durmalarını, ardından devam etmeden önce bakıp dinlemelerini gerektirir. Kaynak: NH RSA 265:50; NH CDL Manual."},"62":{"q":"New Hampshire'de iki şeritli bir yolda, kırmızı ışıkları yanıp sönen durmuş bir okul otobüsüne karşıdan gelen veya onu geçen bir sürücü aracını otobüsten en az ne kadar uzakta durdurmalıdır?","options":["En az 25 fit uzakta","En az 10 fit uzakta","En az 50 fit uzakta","En az 100 fit uzakta"],"explanation":"RSA 265:54, çocukları indiren veya bindiren durmuş bir okul otobüsüne karşıdan gelen veya onu geçen bir sürücünün otobüsten en az 25 fit uzakta durmasını ve otobüs hareket etmeye başlayana ya da ışıklar yanıp sönmeyi durdurana kadar durmuş halde kalmasını gerektirir. Kaynak: NH RSA 265:54."},"63":{"q":"Ayrı yol şeritlerine sahip bölünmüş bir New Hampshire otoyolunda, bir CDL sürücüsü çocuk bindiren bir okul otobüsü için ne zaman durmak zorunda DEĞİLDİR?","options":["Otobüs, bölünmüş otoyolun diğer yarısında ters yönde seyrederken","Asla — yanıp sönen kırmızı ışıkları olan bir okul otobüsü için her zaman durmak gerekir","Yalnızca sürücü boş bir düz kasa kamyon kullanırken","Sürücü 45 mph'den hızlı seyrederken her zaman"],"explanation":"RSA 265:54, ayrı yol şeritlerine sahip bölünmüş bir otoyolda seyreden bir sürücünün, otoyolun diğer yarısında ters yönde seyreden bir okul otobüsüne karşıdan geldiğinde veya onu geçtiğinde durmak zorunda olmadığını öngörür. Bölünmemiş bir yolda tüm yönlerin durması gerekir. Kaynak: NH RSA 265:54."},"64":{"q":"Dört şeritli bölünmüş otoyol olan New Hampshire eyaletler arası otoyollarında ve paralı yollarında (daha yüksek limitli I-93 kesimi dışında) genel azami hız limiti nedir?","options":["65 mph","55 mph","70 mph","75 mph"],"explanation":"RSA 265:60, eyaletler arası sistemde ve merkezi ve doğu New Hampshire paralı yollarında, dört şeritli bölünmüş otoyol oldukları yerlerde azami 65 mph belirler. New Hampshire kamyonlara da otomobillere uyguladığı aynı belirlenen limitleri uygular. Kaynak: NH RSA 265:60."},"65":{"q":"New Hampshire'de hangi yolda belirlenen hız limiti eyaletteki en yüksek olan 70 mph'dir?","options":["45 mil işaretinden Vermont sınırına kadar I-93","I-95'in (Blue Star Turnpike) tüm uzunluğu","Portsmouth'tan Milton'a kadar Spaulding Turnpike","Concord'dan Vermont sınırına kadar I-89"],"explanation":"RSA 265:60, 45 mil işaretinden Vermont sınırına kadar I-93'te hız limitini 70 mph olarak belirler. Bu, New Hampshire'deki en yüksek belirlenen limittir ve ticari araçlar için de geçerlidir. Kaynak: NH RSA 265:60."},"66":{"q":"New Hampshire eyaletler arası otoyollarında kamyonlar için binek otomobillere göre daha düşük bir hız limiti belirler mi?","options":["Hayır — kamyonlar tüm diğer araçlarla aynı belirlenen limite uymalıdır","Evet — otomobiller 65 mph gidebilirken kamyonlar 55 mph ile sınırlıdır","Evet — kamyonlar eyalet genelinde 60 mph ile sınırlıdır","Evet — kamyonlar tüm bölünmüş otoyollarda 45 mph ile sınırlıdır"],"explanation":"New Hampshire'in hız yasası (RSA 265:60), tüm araçlar için geçerli olan azami limitler belirler ve ayrı, daha düşük bir kamyon hız limiti oluşturmaz; ticari araçlar otomobillerle aynı belirlenen limitlere uyar. Kaynak: NH RSA 265:60."},"67":{"q":"New Hampshire yasasına göre, çok şeritli bir yolda yavaş giden bir kamyondan şerit konumu açısından ne istenir?","options":["En sağdaki şeritte kalmalı ve sol şeridi trafiği engelleyecek şekilde sürekli işgal etmemelidir","Sinyal verdiği sürece sol şeritte süresiz kalabilir","Üç şeritli herhangi bir otoyolda yalnızca orta şeridi kullanmalıdır","Boyutu nedeniyle sağda kalma kurallarından muaftır"],"explanation":"RSA 265:16, normal trafikten daha yavaş ilerleyen bir aracın en sağdaki şeritte kalmasını gerektirir ve çok şeritli bir yolun sol şeridinde trafik akışını engellediğinde sürekli seyretmesini yasaklar. Kaynak: NH RSA 265:16."},"68":{"q":"New Hampshire, 10,000 pounds üzerindeki her kamyon veya otobüsün, otoyolda durduğunda kullanmak üzere hangi tür acil durum uyarı cihazları taşımasını gerektirir?","options":["Üç adet çift yönlü yansıtıcı uyarı cihazı (yansıtıcı üçgenler)","Sıvı yakıtla yanan iki fener","Pille çalışan tek bir flaşör işaret lambası","Direklere takılı dört kırmızı bez bayrak"],"explanation":"RSA 265:113, 10,000 pounds GVW üzerindeki her kamyon, otobüs veya çekicinin, federal motorlu taşıyıcı güvenlik düzenlemeleriyle uyumlu olarak müdür tarafından onaylanan üç adet çift yönlü yansıtıcı uyarı cihazı taşımasını gerektirir. Kaynak: NH RSA 265:113; NH CDL Manual."},"69":{"q":"10,000 pounds üzerindeki bir New Hampshire ticari aracı iki şeritli bir otoyolda durduğunda, üç uyarı cihazı genellikle nereye yerleştirilmelidir?","options":["Aracın yaklaşık 10 fit arkasına, 100 fit gerisine ve 100 fit önüne","Üçü de arka tamponun 10 fit içinde","Biri 25 fit ileriye ve ikisi 25 fit geriye","200 fit ileriye, 200 fit geriye ve biri çatıya"],"explanation":"RSA 265:113 uyarınca, sıradan iki yönlü bir yolda cihazlar aracın trafik tarafında yaklaşık 10 fit, 100 fit geriye ve 100 fit ileriye yerleştirilir. Bölünmüş veya tek yönlü bir yolda aralık, yaklaşan trafiğe doğru 10, 100 ve 200 fittir. Kaynak: NH RSA 265:113; NH CDL Manual."},"70":{"q":"New Hampshire'de bir demiryolu geçidi için durduktan sonra, yasa raylar üzerinden geçerken bir otobüs veya hazmat sürücüsünden ne yapmasını ister?","options":["Raylar üzerindeyken vites değiştirmeye gerek olmayacak kadar düşük bir viteste geçmeli","Sert hızlanmalı ve rayları en hızlı şekilde geçmek için hızla yukarı vites yapmalı","Boşa almalı ve raylar üzerinden ataletle geçmeli","Geçişin orta noktasında el frenini kısa süreliğine çekmeli"],"explanation":"RSA 265:50, durduktan sonra ve devam etmek güvenli olduğunda, sürücünün geçerken vites değiştirme gereği olmayacak bir viteste geçmesini ve raylar üzerindeyken vites değiştirmemesini emreder. Kaynak: NH RSA 265:50."},"71":{"q":"New Hampshire'in Move Over yasasına (RSA 265:37-a) uymama konusunda ilk ihlal için ceza yapısı nedir?","options":["İlk ihlal için 75 dolar artı ceza tahakkuku","İlk ihlal için 250 dolar artı 30 günlük ehliyet askıya alınması","500 dolar artı zorunlu CDL diskalifiyesi","İlk ihlal için yalnızca yazılı uyarı"],"explanation":"RSA 265:37-a uyarınca, New Hampshire'in Move Over yasasının ilk ihlali 75 dolar artı ceza tahakkuku para cezası taşır ve 12 ay içinde sonraki bir ihlal için 250 dolar artı tahakkuka yükselir. Kaynak: NH RSA 265:37-a."},"72":{"q":"Aşırı boyut izni olmadan, New Hampshire otoyollarında bir ticari aracın azami yasal genişliği nedir?","options":["8 fit 6 inç","8 fit 0 inç","9 fit 0 inç","10 fit 6 inç"],"explanation":"New Hampshire, federal yasal genişlik limiti olan 8 fit 6 inçi (102 inches) takip eder; daha geniş olan herhangi bir şey NHDOT'tan aşırı boyut izni gerektirir. Kaynak: NH DOT aşırı boyut/aşırı ağırlık izin kuralları; NH State Police Troop G motorlu taşıyıcı rehberi."},"73":{"q":"Aşırı ağırlık izni olmadan, New Hampshire otoyollarında bir ticari araç için azami yasal brüt araç ağırlığı nedir?","options":["80,000 pounds","73,280 pounds","90,000 pounds","100,000 pounds"],"explanation":"New Hampshire'in yasal azami brüt araç ağırlığı hem eyaletler arası hem de diğer otoyollarda 80,000 pounds'tur; bunu aşmak NHDOT aracılığıyla aşırı ağırlık izni/sertifikasyonu gerektirir. Kaynak: NH DOT aşırı boyut/aşırı ağırlık izin kuralları; NH State Police Troop G."},"74":{"q":"İzin olmadan, New Hampshire yollarında bir ticari aracın azami yasal yüksekliği nedir?","options":["13 fit 6 inç","12 fit 6 inç","14 fit 0 inç","13 fit 0 inç"],"explanation":"New Hampshire'in yasal azami araç yüksekliği tüm yol türlerinde 13 fit 6 inçtir; daha yüksek bir yük NHDOT'tan aşırı boyut izni gerektirir. Kaynak: NH DOT aşırı boyut/aşırı ağırlık izin kuralları."},"75":{"q":"New Hampshire'de I-93'ün Franconia Notch Parkway bölümünde, ticari sürücüler için eyaletler arası otoyolun geri kalanına kıyasla ayırt edici olan nedir?","options":["Her yönde tek şeride daralır ve düşürülmüş 45 mph limiti uygulanır","Her yönde yalnızca kamyonlara özel bir ekspres şeridi vardır","Geçiş kamyonları için 80 mph limitine izin verir","Gündüz saatlerinde tüm binek otomobilleri yasaklar"],"explanation":"I-93'ün Franconia Notch Parkway kesimi, eyaletler arası standartlara özel bir istisna kapsamında inşa edildi ve her yönde tek şeride daralarak belirlenen 45 mph limiti uygulanır; bu, eğimde CMV'lerden ekstra dikkat gerektirir. Kaynak: NH DOT; NH RSA 265:60 düşürülmüş bölge yetkisi."},"76":{"q":"New Hampshire'de yasal limitleri aşan ticari araçlar için aşırı boyut/aşırı ağırlık izinlerini hangi kurum verir?","options":["New Hampshire Department of Transportation (NHDOT)","Federal Highway Administration bölge ofisi","Geçilen her kasabanın yerel polis departmanı","New Hampshire Liquor Commission"],"explanation":"New Hampshire'de aşırı boyut ve aşırı ağırlık izinleri New Hampshire Department of Transportation (NHDOT) izin ofisi tarafından verilir; yasal boyut veya ağırlığı aşan yükler izinlendirilmeli ve güzergah kısıtlamasına tabi olabilir. Kaynak: NH DOT aşırı boyut/aşırı ağırlık izin ofisi."},"77":{"q":"New Hampshire yasasına göre, hareket halindeki bir okul otobüsünü kaç veya daha fazla araç takip ettiğinde otobüs sürücüsü koşullar uygun olduğunda onların geçmesine izin vermek için kenara çekmelidir?","options":["5 veya daha fazla takip eden araç","3 veya daha fazla takip eden araç","10 veya daha fazla takip eden araç","2 veya daha fazla takip eden araç"],"explanation":"RSA 265:54, yol koşulları ve alan elverdiğinde ve hareket halindeki bir okul otobüsünü takip eden araç sayısı 5 veya daha fazla olduğunda, otobüs sürücüsünün takip eden araçların geçmesine izin vermek için kenara çekmesini emreder. Kaynak: NH RSA 265:54."},"78":{"q":"New Hampshire'de, yolcuların binmesi veya inmesi için durmuş bir toplu taşıma veya şehirlerarası otobüse (ve kırmızı flaşör gösteren bir okul otobüsü olmayan) yaklaşırken bir sürücü ne yapmalıdır?","options":["Yavaşlamalı ve kamu güvenliği için gerekirse tam olarak durmalı","Yalnızca okul otobüsleri dikkat gerektirdiğinden tam hızda geçmeli","Koşullar ne olursa olsun en az 100 fit geride durmalı","Kornaya üç kez basmalı ve yavaşlamadan devam etmeli"],"explanation":"RSA 265:55, yolcu indirmek veya bindirmek için durmuş bir otobüse, tramvaya veya diğer yolcu aracına yaklaşan ya da onu geçen bir sürücünün yavaşlamasını ve kamu güvenliği için gerekirse aracı tam olarak durdurmasını gerektirir. Kaynak: NH RSA 265:55."},"79":{"q":"Bir CDL sürücüsü, bölünmemiş bir New Hampshire otoyolunda kırmızı ışıkları yanıp sönen durmuş bir okul otobüsüne karşıdan geliyor. Sürücü ne zaman yola devam edebilir:","options":["Otobüs hareket etmeye başladığında veya yanıp sönen kırmızı ışıklar kapatıldığında","Işıklara bakılmaksızın durduktan sonra üç saniye geçtiğinde","Işıklar hâlâ yanıp sönse bile sürücü hiçbir çocuğun görünmediğine karar verdiğinde","Kırmızı ışıklar açık kalsa bile otobüs sürücüsü el salladığında"],"explanation":"RSA 265:54 uyarınca, bölünmemiş bir yolda bir okul otobüsü için durmuş bir sürücü, otobüs hareket etmeye başlayana veya yanıp sönen kırmızı ışıklar kapatılana kadar durmuş halde kalmalıdır; ilk ihlal 150 dolar para cezası artı tahakkuk ve olası ehliyet askıya alınmasıdır. Kaynak: NH RSA 265:54."},"80":{"q":"New Hampshire'de Ticari Sürücü Belgelerini (CDL) hangi kurum verir?","options":["New Hampshire Division of Motor Vehicles (DMV)","Federal Motor Carrier Safety Administration (FMCSA)","New Hampshire Department of Transportation (NHDOT)","New Hampshire State Police Commercial Bureau"],"explanation":"New Hampshire'de CDL'ler, federal FMCSA standartları kapsamında test ve lisanslamayı yöneten New Hampshire Division of Motor Vehicles (DMV) tarafından verilir. NHDOT yolları ve aşırı boyut/aşırı ağırlık izinlerini ele alır, lisanslamayı değil. Kaynak: NH DMV, Commercial Driver Licenses sayfası."},"81":{"q":"Bir New Hampshire başvuru sahibi CDL beceri (yol) testini planlayabilmeden önce hangi federal eğitimi tamamlamalıdır?","options":["Kayıtlı bir sağlayıcıdan Entry-Level Driver Training (ELDT)","160 saatlik bir eyalet çıraklık programı","NH DMV tarafından onaylanmış bir savunmacı sürüş kursu","Bir OSHA ticari araç güvenlik sertifikası"],"explanation":"New Hampshire federal ELDT kuralını takip eder: başvuru sahipleri CDL beceri testini planlayabilmeden önce bir FMCSA Training Provider Registry sağlayıcısından Entry-Level Driver Training tamamlamalıdır. Kaynak: NH DMV, Commercial Driver Learner Permit sayfası; 49 CFR Part 380."},"82":{"q":"Bir New Hampshire CLP'si verildikten sonra, CDL yol (beceri) testi planlanabilmeden önce sahibinin ne kadar beklemesi gerekir?","options":["En az 14 gün","En az 10 gün","En az 30 gün","En az 7 gün"],"explanation":"New Hampshire federal 14 günlük bekleme süresini uygular: bilgi sınavları geçilip CLP verildikten sonra, yol sınavı CLP'nin verildiği tarihten itibaren 14 günden önce planlanamaz. Kaynak: NH DMV, Commercial Driver Learner Permit sayfası; 49 CFR 383.25."},"83":{"q":"New Hampshire CDL beceri testi üç ayrı bölümden oluşur. Hangi grup bunları doğru şekilde listeler?","options":["Yola çıkış öncesi muayene, temel araç kontrolü ve yolda sürüş","Yazılı bilgi, görme taraması ve yolda sürüş","Yola çıkış öncesi muayene, hava freni gösterimi ve gece sürüşü","Bağlama/çözme, geri gitme ve yazılı bir onay sınavı"],"explanation":"New Hampshire CDL beceri testinin üç bölümü vardır: yola çıkış öncesi (araç) muayenesi, temel araç kontrol becerileri testi ve yolda sürüş testi. Bilgi ve görme testleri ayrı ön koşullardır, beceri testinin parçası değildir. Kaynak: NH DMV, CDL Road Test sayfası."},"84":{"q":"New Hampshire'in CDL başvuru sahipleri için öz beyanında (self-certification), sürücünün kaç ticari faaliyet kategorisinden seçim yapması gerekir?","options":["Dört","İki","Üç","Beş"],"explanation":"New Hampshire CDL başvuru sahipleri dört kategoriden birine öz beyanda bulunmalıdır: eyaletler arası istisna dışı, eyaletler arası istisnalı, eyalet içi istisna dışı ve eyalet içi istisnalı. Kaynak: NH DMV öz beyan formu DSMV 612."},"85":{"q":"Bir New Hampshire sürücüsü 'eyaletler arası istisna dışı' (interstate non-excepted) olarak öz beyanda bulunuyor. Bu kategori neyi gerektirir?","options":["Dosyada geçerli bir DOT Medical Examiner's Certificate","Hiçbir türde sağlık sertifikası yok","Yalnızca eyalet tarafından verilen bir eyalet içi sağlık muafiyeti","Sağlık kartı yerine bir Transportation Worker Identification Credential"],"explanation":"Eyaletler arası istisna dışı sürücüler, istisna dışı ticarette eyalet sınırları arasında faaliyet gösterir ve dosyada geçerli bir DOT Medical Examiner's Certificate bulundurmalı ve saklamalıdır. İstisnalı kategorilerin bir sağlık kartı sunması gerekmez. Kaynak: NH DMV form DSMV 612; 49 CFR 383.71."},"86":{"q":"CDL sahiplerinin faaliyet kategorilerini öz beyan etmek ve sağlık kartı bilgilerini DMV'ye sunmak için hangi New Hampshire formu kullanılır?","options":["DSMV 612","DSMV 312","MCSA-5876","DSMV 500"],"explanation":"New Hampshire, CDL öz beyanı ve sağlık kartı/sertifikasyon bilgilerini DMV'ye sunmak için DSMV 612 formunu kullanır. DSMV 312 CDL başvurusudur; MCSA-5876 muayeneci tarafından doldurulan federal Medical Examiner's Certificate'tır. Kaynak: NH DMV, CDL Medical Card Update; form DSMV 612."},"87":{"q":"New Hampshire genel bilgi CDL yazılı testinde geçmek için gereken asgari puan nedir?","options":["80%","70%","75%","90%"],"explanation":"New Hampshire, CDL genel bilgi testinde asgari geçme puanı olarak 80% gerektirir (50 sorudan 40'ı doğru). Kaynak: NH CDL Manual; NH DMV bilgi testi gereksinimleri."},"88":{"q":"Bir New Hampshire CDL'si, verilişinden sonraki hangi yılda belge sahibinin doğum gününde sona erer?","options":["Beşinci yıl","Dördüncü yıl","Altıncı yıl","Onuncu yıl"],"explanation":"RSA 263:93 uyarınca, bir New Hampshire ticari sürücü belgesi, verilişinden sonraki beşinci yılda belge sahibinin doğum tarihinde sona erer ve bu, beş yıllık bir yenileme döngüsü oluşturur. Kaynak: NH RSA 263:93 (License Expiration and Renewal)."},"89":{"q":"Eyalet içi (yalnızca eyalet içinde) sürüş için bir New Hampshire CDL'si almak için asgari yaş nedir?","options":["18 yaşında","16 yaşında","21 yaşında","19 yaşında"],"explanation":"Bir başvuru sahibi, eyalet içi sürüş için bir New Hampshire CDL'sine sahip olmak için en az 18 yaşında olmalıdır. 21 yaşından küçük sürücüler yalnızca eyalet içi faaliyetle sınırlıdır. Kaynak: NH DMV, Commercial Driver Licenses sayfası."},"90":{"q":"Eyaletler arası (eyalet sınırları arasında) sürüş yapmak veya bir New Hampshire CDL'sine HAZMAT onayı almak için asgari yaş nedir?","options":["21 yaşında","18 yaşında","23 yaşında","25 yaşında"],"explanation":"Bir New Hampshire CDL sahibi, eyaletler arası ticarette sürüş yapmak veya bir HAZMAT onayı taşımak için en az 21 yaşında olmalıdır. 18-20 yaş arası sahipler eyalet içi sürüşle sınırlıdır. Kaynak: NH DMV, Commercial Driver Licenses sayfası; 49 CFR 383."},"91":{"q":"New Hampshire Commercial Driver License başvurusunun kendisi hangi formdur?","options":["DSMV 312","DSMV 612","MCSA-5875","DSMV 426"],"explanation":"New Hampshire CDL başvurusu DSMV 312 formudur. DSMV 612 ayrı öz beyan/sağlık kartı formudur. Kaynak: NH DMV CDL formları; Apply for a CDL."},"92":{"q":"Bilgi ve beceri testlerinin yanı sıra, her New Hampshire CDL başvuru sahibinin geçmesi gereken hangi tarama vardır?","options":["Bir görme muayenesi","Yazılı bir ilk yardım sınavı","DMV'de uygulanan bir uyuşturucu ve alkol kan testi","Bir fiziksel çeviklik engel parkuru"],"explanation":"Tüm New Hampshire CDL başvuru sahipleri, bilgi ve beceri testlerine ek olarak bir görme muayenesinden geçmelidir. Kaynak: NH DMV, Commercial Driver Licenses sayfası."},"93":{"q":"New Hampshire CDL yol testi için başvuru sahibi genellikle ne tür bir test aracı sağlamalıdır?","options":["Geçerli bir muayene etiketi olan, alınmak istenen CDL ile aynı sınıf/türde temsili bir araç","Güncel kaydı olan herhangi bir binek otomobil","NH DMV tarafından ücretsiz sağlanan bir araç","Sınıfı ne olursa olsun 26,001 lbs GVWR altında bir kiralık araç"],"explanation":"Başvuru sahibi, alınmak istenen CDL'nin sınıf/türüne uygun, usulüne uygun kayıtlı ve sigortalı ve geçerli bir New Hampshire muayene etiketi gösteren temsili bir test aracı sağlamalıdır. Kaynak: NH DMV, CDL Road Test sayfası."},"94":{"q":"Bir New Hampshire CDL sahibinin sağlık sertifikasyonu sona erer ve güncellenmiş bir sertifika veya muafiyet sunulmazsa, DMV CDL'yi ne kadar süre içinde düşürmelidir?","options":["60 gün","10 gün","30 gün","180 gün"],"explanation":"New Hampshire'in uyguladığı federal sağlık sertifikasyon kuralı uyarınca, güncel bir sağlık sertifikası veya muafiyet sunulmazsa (ya da sürücü izin verilen yerlerde istisnalı/eyalet içi bir kategoriye geçmezse) eyalet, bir sona ermeden itibaren 60 gün içinde bir CDL veya CLP'yi düşürmelidir. Kaynak: 49 CFR 383.73; NH DMV CDL Medical Card Update."},"95":{"q":"Hangi New Hampshire CDL sınıfı, GVWR'si 26,001 lbs veya daha fazla olan tek bir aracı (10,000 lbs üzerinde hiçbir şey çekmeden) kullanmaya yetki verir?","options":["Class B","Class A","Class C","Class D"],"explanation":"Bir Class B CDL, GVWR'si 26,001 lbs veya daha fazla olan herhangi bir tek aracı veya 10,000 lbs GVWR üzerinde olmayan bir birim çeken böyle bir aracı kapsar. Class A, 10,000 lbs üzerinde çekilen bir birimle 26,001 lbs üzerindeki kombinasyonları kapsar. Kaynak: NH DMV, License Classifications sayfası."},"96":{"q":"Bir New Hampshire CDL'sine HAZMAT onayı başvurmadan önce, başvuru sahibinin tamamlaması gereken ek federal adım nedir?","options":["Parmak izi tabanlı arka plan kontrolü içeren bir TSA güvenlik tehdit değerlendirmesi","40 saatlik bir OSHA tehlikeli madde işleme kursu","Bir EPA tehlikeli atık taşıyıcı kaydı","Bir tanker araçta ikinci bir yolda beceri testi"],"explanation":"Bir HAZMAT onayı için başvuranlar, HAZMAT bilgi testine ek olarak parmak izi alımı ve arka plan kontrolünü içeren bir TSA güvenlik tehdit değerlendirmesinden geçmelidir. Kaynak: NH DMV, Commercial Driver Licenses sayfası; 49 CFR Part 1572."},"97":{"q":"New Hampshire'in takip ettiği modernize edilmiş federal sağlık sertifikasyon sürecine göre (2025'te yürürlüğe giren), çoğu Medical Examiner's Certificate sonucu artık eyalete nasıl ulaşır?","options":["Sağlık muayenecileri sonuçları elektronik olarak FMCSA'ya iletir, FMCSA da bunları sürüş kaydını güncellemek için eyalete gönderir","Sürücüler kağıt sertifikayı her zaman bir DMV ofisine elden teslim etmelidir","İşverenler sertifikaları sürücü adına doğrudan FMCSA'ya postalar","Sertifikalar yalnızca sürücünün sigorta şirketine dosyalanır"],"explanation":"New Hampshire'in takip ettiği 23 Haziran 2025'te yürürlüğe giren federal süreç uyarınca, sertifikalı sağlık muayenecileri muayene sonuçlarını elektronik olarak FMCSA'ya bildirir, FMCSA da sağlık sertifikasyon durumunu CDL kaydını güncellemek için eyalete iletir; sürücüler yine de faaliyet kategorilerini öz beyan etmelidir (örneğin DSMV 612 aracılığıyla). Kaynak: FMCSA Medical Certification kuralı; NH DMV CDL Medical Card Update."},"98":{"q":"19 yaşındaki biri tüm New Hampshire CDL testlerini geçer ve bir CDL için nitelik kazanır. Hangi faaliyet kısıtlaması uygulanır?","options":["21 yaşına kadar eyalet içi (New Hampshire içinde) ticaretle sınırlıdır","Eyaletler arası sürüş yapabilir ancak yolcu taşıyamaz","Yalnızca bir HAZMAT onayı ile eyaletler arası sürüş yapabilir","Testler geçildikten sonra yaşa dayalı bir faaliyet kısıtlaması yoktur"],"explanation":"En az 18 ancak 21 yaşından küçük olan bir New Hampshire CDL sahibi yalnızca eyalet içi sürüşle sınırlıdır; eyaletler arası faaliyet ve HAZMAT 21 yaş gerektirir. Kaynak: NH DMV, Commercial Driver Licenses sayfası; 49 CFR 391.11."}},"es":{"0":{"q":"En las vías de New Hampshire, ¿cuál es el ancho máximo de un vehículo, incluida su carga, antes de que se requiera un permiso por exceso de dimensiones?","options":["96 inches","102 inches","108 inches","114 inches"],"explanation":"La RSA 266:12 de New Hampshire prohíbe conducir cualquier vehículo cuyo ancho, incluida la carga, exceda 102 inches (8 feet 6 inches). Esto coincide con el estándar federal para la National Network. Fuente: NH RSA 266:12 Width; NH CDL Manual."},"1":{"q":"¿Cuál es la altura máxima, incluida la carga, de un vehículo estándar (que no transporta viviendas prefabricadas) permitida en las vías de New Hampshire sin un permiso?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"explanation":"La RSA 266:10 de New Hampshire establece que ningún vehículo (salvo uno que transporte viviendas prefabricadas o edificios modulares) cuya altura total, incluida la carga, sea mayor que 13 feet 6 inches puede circular por las vías del estado. Fuente: NH RSA 266:10 Height."},"2":{"q":"En New Hampshire, ¿cuál es la longitud máxima de un semirremolque en una combinación de tractocamión/semirremolque que opera sin un permiso?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"La RSA 266:11 de New Hampshire permite un semirremolque de hasta 53 feet en una combinación de tractocamión y un solo semirremolque (los remolques de más de 48 feet tienen requisitos adicionales de pivote de enganche y de protección trasera). Fuente: NH RSA 266:11 Length."},"3":{"q":"Según la ley de New Hampshire, ¿cuál es el peso bruto vehicular máximo (incluidas todas las tolerancias de las fuerzas del orden) para un vehículo combinado con cinco o más ejes que opera sin un permiso de sobrepeso?","options":["73,280 pounds","80,000 pounds","84,000 pounds","90,000 pounds"],"explanation":"New Hampshire limita el peso bruto máximo para una combinación de 5 o más ejes a 80,000 pounds, incluidas todas las tolerancias de las fuerzas del orden, en consonancia con el límite federal. Fuente: NH RSA 266:18 / 266:18-a."},"4":{"q":"¿Cuál es el peso máximo de un solo eje permitido en el Interstate and Defense Highway System de New Hampshire sin un permiso?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"En el Interstate and Defense Highway System, la RSA 266:18 de New Hampshire limita un solo eje a 20,000 pounds, lo que coincide con el estándar federal para Interstate. (Cifras mayores como 22,400 lb se aplican solo a ciertas configuraciones que no son de Interstate). Fuente: NH RSA 266:18."},"5":{"q":"En el Interstate and Defense Highway System de New Hampshire, ¿cuál es el peso máximo permitido sobre un eje tándem?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"La RSA 266:18 de New Hampshire limita un eje tándem a 34,000 pounds en el Interstate and Defense Highway System, igual que el estándar federal. Fuente: NH RSA 266:18."},"6":{"q":"La fiscalización de sobrepeso de New Hampshire utiliza una fórmula de distribución de peso que relaciona el peso bruto con el espaciamiento de los ejes y el número de ejes. Esta fórmula se conoce comúnmente como:","options":["Fórmula del puente federal (federal bridge formula)","Fórmula de retroceso del pivote de enganche (kingpin setback formula)","Fórmula de clasificación de combinación bruta (gross combination rating formula)","Fórmula de peso en vacío (tare weight formula)"],"explanation":"La RSA 266:18 de New Hampshire incorpora la federal bridge formula W = 500[LN/(N-1) + 12N + 36], donde W es el peso bruto sobre un grupo de ejes, L es la distancia entre los ejes extremos y N es el número de ejes. Fuente: NH RSA 266:18."},"7":{"q":"En la fórmula del puente de New Hampshire W = 500[LN/(N-1) + 12N + 36], ¿qué representa la variable 'N'?","options":["El número de ejes del grupo","El peso neto de la carga","El número de remolques","El ancho nominal del neumático"],"explanation":"En la fórmula del puente adoptada por New Hampshire (RSA 266:18), N equivale al número de ejes del grupo considerado; L es la distancia en feet entre los ejes extremos, y W es el peso bruto permisible resultante. Fuente: NH RSA 266:18."},"8":{"q":"Las combinaciones de camión con triple remolque en las vías de New Hampshire están:","options":["Permitidas solo en Interstates","Permitidas con un permiso anual","Prohibidas","Permitidas solo de noche"],"explanation":"La RSA 266:11-b de New Hampshire prohíbe la operación de camiones con triple remolque en las vías del estado. Fuente: NH RSA 266:11-b Triple Trailer Trucks Prohibited."},"9":{"q":"Un transportista necesita mover una carga que excede los límites legales de tamaño o peso de New Hampshire. ¿Qué organismo emite el permiso requerido por exceso de tamaño/peso?","options":["El encargado de caminos del pueblo local","El New Hampshire Department of Transportation","La Federal Motor Carrier Safety Administration","La oficina del sheriff del condado"],"explanation":"Los permisos por exceso de tamaño/peso (OSOW) en New Hampshire son emitidos por el NH Department of Transportation a través de su oficina de permisos (solicitudes en línea, en persona en 7 Hazen Drive, Concord, o por teléfono). Fuente: NHDOT Permits / OSOW Permit Office."},"10":{"q":"Por lo general, ¿durante qué horario se permite que una carga de exceso de tamaño o peso circule en New Hampshire?","options":["24 horas al día, cualquier día","Desde media hora antes del amanecer hasta media hora después del atardecer, de lunes a viernes","Solo entre las 9:00 p. m. y las 5:00 a. m. todos los días","Solo los fines de semana, para evitar el tráfico de quienes viajan al trabajo"],"explanation":"Según las reglas de permisos OSOW del NHDOT, las cargas de exceso de tamaño/peso generalmente pueden circular desde media hora antes del amanecer hasta media hora después del atardecer, de lunes a viernes, sin permitirse la circulación de cargas sobredimensionadas los fines de semana ni días feriados. Fuente: NHDOT OSOW Permit travel restrictions."},"11":{"q":"¿Cuál es la longitud máxima, incluidos los parachoques delantero y trasero, de un vehículo de una sola unidad o autobús en las vías de New Hampshire sin un permiso?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"La RSA 266:11 de New Hampshire limita un vehículo de una sola unidad o autobús a 45 feet, incluidos los parachoques delantero y trasero. Fuente: NH RSA 266:11 Length."},"12":{"q":"Cuando un vehículo transporta viviendas prefabricadas o edificios modulares en New Hampshire, la altura máxima permitida es:","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"La RSA 266:10 de New Hampshire permite una altura máxima de 14 feet 6 inches para vehículos que transportan viviendas prefabricadas o edificios modulares; las cargas que excedan 13 feet 6 inches requieren una escolta no policial. Fuente: NH RSA 266:10 Height."},"13":{"q":"En el sistema de carreteras general (que no es Interstate) de New Hampshire, un solo eje en un vehículo de una sola unidad de 3 ejes puede transportar un máximo de:","options":["18,000 pounds","20,000 pounds","22,400 pounds","25,000 pounds"],"explanation":"La RSA 266:18-a de New Hampshire permite hasta 22,400 pounds por eje en vehículos de una sola unidad de 3 ejes (y otros vehículos con ejes separados 10 feet o más) en el sistema de carreteras general que no es Interstate, lo cual es superior al límite de 20,000 pounds para Interstate. Fuente: NH RSA 266:18-a."},"14":{"q":"Para una combinación de tractocamión y un solo semirremolque con cuatro o más ejes que transporta productos forestales sin procesar en New Hampshire, el peso máximo sobre un eje tándem se incrementa a:","options":["34,000 pounds","36,000 pounds","40,000 pounds","44,000 pounds"],"explanation":"La RSA 266:18-b de New Hampshire permite que un eje tándem transporte hasta 40,000 pounds en una combinación de tractocamión y un solo semirremolque de 4 o más ejes que transporta productos forestales sin procesar (troncos sin procesar y astillas de madera). Fuente: NH RSA 266:18-b."},"15":{"q":"La ley de New Hampshire autoriza a los oficiales de fiscalización a permitir qué tolerancia general por encima de los límites de peso establecidos por grupo de ejes y peso bruto antes de emitir una infracción?","options":["1 percent","2 percent","5 percent","15 percent"],"explanation":"Las RSA 266:18-a y 266:18-c de New Hampshire autorizan una tolerancia de 5 percent por encima de las limitaciones de peso establecidas (con hasta 10 percent permitido en ciertos pesos por eje bajo la 266:18-c). Fuente: NH RSA 266:18-a / 266:18-c."},"16":{"q":"En el sistema Interstate, dos conjuntos consecutivos de ejes tándem en New Hampshire pueden transportar cada uno 34,000 pounds solo si la distancia entre el primer y el último eje de esos conjuntos tándem es de al menos:","options":["28 feet","30 feet","36 feet","40 feet"],"explanation":"La RSA 266:18 de New Hampshire permite que dos conjuntos consecutivos de ejes tándem transporten 34,000 pounds cada uno solo si la distancia total entre el primer y el último eje es de 36 feet o más, y el peso bruto total no excede 80,000 pounds. Fuente: NH RSA 266:18."},"17":{"q":"En el sistema de carreteras general que no es Interstate de New Hampshire, ¿cuál es el peso máximo por eje tándem para una combinación de cinco o más ejes?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"La RSA 266:18-a de New Hampshire permite que un eje tándem en una combinación de 5 o más ejes en el sistema de carreteras general que no es Interstate transporte hasta 36,000 pounds, superior al límite tándem de 34,000 pounds para Interstate. Fuente: NH RSA 266:18-a."},"18":{"q":"Un transportista con base en New Hampshire quiere un permiso anual de exceso de tamaño para circulación en todo el estado de un vehículo de no más de 75 feet de largo, 10 feet 6 inches de ancho y 13 feet 6 inches de alto. ¿Cuál es la tarifa anual del permiso establecida para la circulación en todo el estado?","options":["$60.00","$115.00","$200.00","$300.00"],"explanation":"El NHDOT indica que la tarifa anual del permiso de exceso de tamaño es de $115.00 para circulación en todo el estado (o $60.00 para circulación dentro de un radio de 100 millas) para transportistas con base y registrados en NH, para vehículos dentro de los límites establecidos de 75 ft / 10 ft 6 in / 13 ft 6 in. Fuente: NHDOT OSOW Permit fees."},"19":{"q":"Según la RSA 266:16 de New Hampshire, la sanción por una primera infracción de operar un vehículo que excede los límites de tamaño permitidos es una multa de:","options":["No más de $100","No más de $250","No más de $500","No más de $1,000"],"explanation":"La RSA 266:16 de New Hampshire fija la sanción por exceder el tamaño permitido en una multa de no más de $100 por una primera infracción y de no más de $250 por una infracción posterior dentro del mismo año calendario. Fuente: NH RSA 266:16 Penalty for Exceeding Permitted Size."},"20":{"q":"Según las reglas de CDL de New Hampshire, ¿qué clase de licencia se requiere para conducir una combinación de vehículos con una clasificación de peso bruto combinado (GCWR) de 26,001 pounds o más, siempre que la unidad remolcada tenga un GVWR superior a 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"New Hampshire define una CDL Class A como cualquier combinación de vehículos con un GCWR de 26,001 lbs o más donde el GVWR de la unidad remolcada excede 10,000 lbs. Fuente: página NH DMV License Classifications, Restrictions and Endorsements; NH Commercial Driver's Manual."},"21":{"q":"En New Hampshire, ¿qué clase de CDL cubre cualquier vehículo INDIVIDUAL con un GVWR de 26,001 pounds o más, o tal vehículo remolcando una unidad que no exceda 10,000 pounds de GVWR?","options":["Class A","Class B","Class C","Class M"],"explanation":"NH define una CDL Class B como un vehículo individual con un GVWR de 26,001 lbs o más, o tal vehículo remolcando una unidad que no exceda 10,000 lbs de GVWR. Fuente: página NH DMV License Classifications; NH Commercial Driver's Manual."},"22":{"q":"Un conductor de New Hampshire opera un vehículo individual de menos de 26,001 lbs que está diseñado para transportar 18 pasajeros incluido el conductor. ¿Qué clase de CDL requiere esto?","options":["Class A","Class B","Class C","No se requiere CDL"],"explanation":"NH define una CDL Class C como un vehículo que no cumple con los requisitos de Class A o B y que transporta 16 o más pasajeros (incluido el conductor), tiene letreros (placards) por materiales peligrosos, o es un vehículo cisterna. Un vehículo de 18 pasajeros entra dentro de Class C. Fuente: página NH DMV License Classifications."},"23":{"q":"¿Cuál es la edad mínima para obtener una CDL de New Hampshire restringida a la operación INTRAESTATAL (solo dentro de New Hampshire)?","options":["16 años","18 años","21 años","25 años"],"explanation":"En New Hampshire debes tener al menos 18 años para operar un vehículo motor comercial de forma intraestatal (dentro de NH). Fuente: página NH DMV Commercial Driver Licenses; NH Commercial Driver's Manual."},"24":{"q":"¿Cuál es la edad mínima para obtener una CDL de New Hampshire válida para la conducción comercial INTERESTATAL (a través de las fronteras estatales)?","options":["18 años","19 años","21 años","23 años"],"explanation":"New Hampshire (siguiendo el estándar federal) exige que los conductores tengan al menos 21 años para operar un vehículo motor comercial en el comercio interestatal. Los conductores de 18 a 20 años están restringidos a la operación intraestatal. Fuente: página NH DMV Commercial Driver Licenses."},"25":{"q":"Según las reglas de New Hampshire y federales, ¿durante cuánto tiempo debe un solicitante tener un Commercial Learner Permit (CLP) antes de que se le permita tomar el examen de habilidades (de carretera) de la CDL?","options":["7 días","10 días","14 días","30 días"],"explanation":"Un solicitante debe tener el CLP durante al menos 14 días antes de tomar el examen de habilidades de la CDL. Este es un requisito federal aplicado por NH. Fuente: página NH DMV Commercial Driver Learner Permit; 49 CFR 383.25."},"26":{"q":"Cuando el titular de un Commercial Driver Learner Permit de New Hampshire conduce un vehículo motor comercial, ¿quién debe acompañarlo?","options":["Cualquier conductor con licencia de 18 años o más","Una persona de 25 años o más que tenga una CDL válida para ese tipo de vehículo, sentada inmediatamente al lado del titular del permiso","Cualquier titular de CDL sentado en cualquier parte del vehículo","Únicamente un examinador del New Hampshire DMV"],"explanation":"NH exige que el titular del CLP esté acompañado por una persona de 25 años de edad o más que tenga una CDL válida para el tipo de vehículo que se conduce y que ocupe el asiento inmediatamente contiguo al titular del permiso. Fuente: página NH DMV Commercial Driver Learner Permit."},"27":{"q":"¿Qué código de aval (endorsement) se requiere en una CDL de New Hampshire para transportar materiales peligrosos en cantidades que requieren letreros (placards)?","options":["Aval N","Aval H","Aval T","Aval X"],"explanation":"El aval H (HazMat) se requiere para conducir cualquier vehículo comercial que transporte materiales peligrosos que deban llevar letreros (placards) según las regulaciones estatales o federales. Fuente: página NH DMV HazMat Endorsement."},"28":{"q":"Antes de que se pueda emitir el aval de HazMat (H) a un conductor de New Hampshire, ¿qué evaluación adicional se requiere a nivel federal?","options":["Una evaluación de amenaza a la seguridad de la TSA (verificación de antecedentes basada en huellas dactilares)","Un examen de polígrafo del FBI","Una entrevista con la New Hampshire State Police","Únicamente una prueba de drogas del DOT"],"explanation":"Los solicitantes del aval H deben aprobar una evaluación de amenaza a la seguridad de la Transportation Security Administration (TSA), que incluye una verificación de antecedentes basada en huellas dactilares, además del examen de conocimientos de HazMat. Fuente: página NH DMV HazMat Endorsement; 49 CFR 1572."},"29":{"q":"En una CDL de New Hampshire, ¿qué aval se requiere para operar un vehículo cisterna (utilizado para transportar líquidos o gases a granel)?","options":["Aval H","Aval T","Aval N","Aval P"],"explanation":"El aval N (vehículo cisterna) se requiere para operar un vehículo cisterna diseñado para transportar líquidos o gases a granel. Fuente: página NH DMV License Classifications, Restrictions and Endorsements."},"30":{"q":"¿Qué aval de la CDL de New Hampshire se requiere para remolcar remolques dobles o triples?","options":["Aval T","Aval N","Aval D","Aval X"],"explanation":"El aval T (Dobles/Triples) se requiere para remolcar remolques dobles o triples. Se obtiene aprobando un examen de conocimientos; no se requiere un examen de habilidades por separado para ello. Fuente: página NH DMV License Classifications; NH Commercial Driver's Manual."},"31":{"q":"¿Qué aval requiere New Hampshire para conducir un vehículo comercial diseñado para transportar 16 o más pasajeros, incluido el conductor?","options":["Aval S","Aval P","Aval N","Aval T"],"explanation":"El aval P (pasajeros) se requiere para conducir cualquier vehículo comercial diseñado para transportar 16 o más pasajeros incluido el conductor. Fuente: página NH DMV Commercial Driver Licenses."},"32":{"q":"Para obtener el aval de autobús escolar (S) de New Hampshire, ¿qué necesita también generalmente el solicitante?","options":["Un aval de HazMat (H)","Un aval de cisterna (N)","Un aval de pasajeros (P)","Un aval de Dobles/Triples (T)"],"explanation":"Un autobús escolar transporta 16 o más ocupantes, por lo que NH exige el aval de pasajeros (P) además de aprobar el examen de conocimientos de autobús escolar (S) y un examen de habilidades de carretera para vehículos de pasajeros. Fuente: página NH DMV School Bus Drivers."},"33":{"q":"¿Qué puntaje mínimo de aprobación exige New Hampshire en el examen escrito de conocimientos generales de la CDL para calificar para un Commercial Learner Permit?","options":["70%","75%","80%","90%"],"explanation":"New Hampshire exige un puntaje de 80% o más en los exámenes de conocimientos de la CDL, incluido el examen de conocimientos generales. Fuente: página NH DMV Commercial Driver Learner Permit; NH Commercial Driver's Manual."},"34":{"q":"La Entry-Level Driver Training (ELDT) tomada antes de ciertos exámenes de habilidades/conocimientos de la CDL de New Hampshire debe completarse a través de qué?","options":["Cualquier colegio comunitario de New Hampshire","Un proveedor incluido en el FMCSA Training Provider Registry (TPR)","La propia división de capacitación del New Hampshire DMV","Cualquier programa administrado por un empleador, sin necesidad de registro"],"explanation":"La ELDT debe completarse a través de un proveedor incluido en el FMCSA Training Provider Registry (TPR); el proveedor se autocertifica y envía los registros de finalización a la FMCSA. Fuente: FMCSA ELDT / Training Provider Registry; páginas NH DMV CDL."},"35":{"q":"¿Cuál de los siguientes requiere ELDT (Entry-Level Driver Training) antes de que un solicitante de New Hampshire pueda tomar el examen correspondiente?","options":["Agregar un aval de Dobles/Triples (T)","Agregar un aval de cisterna (N)","Obtener una CDL Class A por primera vez","Renovar una CDL Class B existente sin cambio de clase"],"explanation":"Las reglas federales de ELDT (vigentes desde el 7 de febrero de 2022) se aplican a la obtención de una CDL Class A o B por primera vez, a la actualización de Class B a Class A, y a la obtención de un aval H, P o S por primera vez. Los avales N y T y las renovaciones simples no requieren ELDT. Fuente: regulaciones FMCSA ELDT; páginas NH DMV CDL."},"36":{"q":"Al solicitar una CDL de New Hampshire, ¿qué categoría de autocertificación indica a un conductor que opera a través de las fronteras estatales y que debe cumplir con el requisito federal del certificado médico del DOT?","options":["Interstate non-excepted","Intrastate excepted","Interstate excepted","Intrastate non-excepted"],"explanation":"NH usa las cuatro categorías federales de autocertificación. 'Interstate non-excepted' cubre a los conductores que operan a través de las fronteras estatales y que deben tener un certificado médico válido del DOT en sus archivos. Fuente: página NH DMV CDL Medical Card Update; 49 CFR 383.71."},"37":{"q":"Para solicitar una CDL o un Commercial Learner Permit de New Hampshire, un solicitante generalmente debe presentar prueba de qué combinación de documentos?","options":["Solo identidad","Solo identidad y número de Seguro Social","Identidad, número de Seguro Social y residencia/presencia legal en New Hampshire","Solo un pasaporte, que cubre todos los requisitos"],"explanation":"New Hampshire exige que los solicitantes prueben su identidad, proporcionen un documento que muestre el número de Seguro Social, y proporcionen documentos que establezcan la residencia en NH y la presencia legal. Fuente: páginas NH DMV Required Documents / Commercial Driver Learner Permit."},"38":{"q":"¿Por cuánto tiempo es válido un Commercial Driver Learner Permit (CLP) de New Hampshire antes de que deba renovarse?","options":["30 días","60 días","180 días","365 días"],"explanation":"Un CLP de New Hampshire es válido por 180 días y puede renovarse una vez, siempre que los exámenes de conocimientos requeridos se hayan aprobado dentro de un período de un año. Esto sigue el estándar federal de validez del CLP. Fuente: página NH DMV Commercial Driver Learner Permit; 49 CFR 383.25."},"39":{"q":"Un residente de New Hampshire de 19 años quiere una CDL. ¿Para qué privilegio NO es elegible hasta que cumpla 21 años?","options":["Tener una CDL Class B","Operar de forma intraestatal dentro de New Hampshire","Obtener un aval de HazMat (H)","Obtener un aval de cisterna (N)"],"explanation":"Los solicitantes de New Hampshire menores de 21 años están restringidos a la operación intraestatal y no pueden obtener los privilegios de HazMat (H) ni de pasajeros para interestatal; el aval H específicamente requiere que el solicitante tenga al menos 21 años. Fuente: páginas NH DMV Commercial Driver Licenses / HazMat Endorsement."},"40":{"q":"En New Hampshire, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) con la que una persona puede operar legalmente un vehículo motor comercial (CMV)?","options":["0.04","0.08","0.02","0.10"],"explanation":"New Hampshire fija el límite de BAC para operar un CMV en 0.04, la mitad del límite de 0.08 para conductores no comerciales. Fuente: NH CDL Manual (sección de alcohol/drogas); RSA 265-A:2."},"41":{"q":"Al conducir un vehículo motor comercial en las carreteras de New Hampshire, se considera legalmente que el titular de una CDL ha hecho qué con respecto a las pruebas químicas de alcohol o drogas?","options":["Dado su consentimiento implícito para someterse a pruebas si se solicitan legalmente","Renunciado a cualquier derecho futuro a una CDL","Aceptado pagar una tarifa fija de prueba de $500","Consentido únicamente a una prueba de aliento pero no de sangre"],"explanation":"Según la ley de consentimiento implícito de New Hampshire, se considera que cualquier persona que conduce en el estado ha consentido a someterse a pruebas químicas para determinar la concentración de alcohol cuando se solicitan legalmente. Fuente: RSA 265-A:4; NH CDL Manual."},"42":{"q":"Para una primera infracción mayor (como un DUI en un CMV), ¿cuál es el período mínimo de descalificación de la CDL en New Hampshire?","options":["1 año","60 días","6 meses","3 años"],"explanation":"Una primera infracción mayor descalifica a un conductor para operar un CMV por no menos de un año en New Hampshire. Fuente: RSA 263:94; 49 CFR 383.51; NH CDL Manual."},"43":{"q":"Si un conductor de New Hampshire comete una primera infracción mayor mientras opera un CMV con letreros (placards) por materiales peligrosos, la descalificación mínima es:","options":["3 años","1 año","120 días","De por vida"],"explanation":"Una primera infracción mayor cometida mientras se transportan materiales peligrosos con letreros (placards) eleva la descalificación mínima de un año a tres años. Fuente: RSA 263:94; 49 CFR 383.51."},"44":{"q":"¿Cuál es el período de descalificación en New Hampshire para una segunda infracción mayor (por ejemplo, un segundo DUI en un CMV) que surge de un incidente separado?","options":["De por vida","10 años","5 años","3 años"],"explanation":"Una segunda condena por una infracción mayor de un incidente separado resulta en la descalificación de por vida para operar un CMV. Fuente: RSA 263:94; 49 CFR 383.51."},"45":{"q":"El titular de una CDL de New Hampshire se niega a someterse a una prueba química mientras opera un CMV. Para una primera negativa, la descalificación mínima de la CDL es:","options":["1 año","90 días","6 meses","30 días"],"explanation":"Negarse a una prueba química solicitada legalmente se trata como una infracción mayor; una primera negativa conlleva una descalificación mínima de la CDL de un año (tres años si lleva letreros [placards] por materiales peligrosos). Fuente: RSA 263:94; RSA 265-A:4."},"46":{"q":"Si el titular de una CDL de New Hampshire se niega a una prueba química por segunda vez (un incidente separado), la descalificación de la CDL es:","options":["De por vida","5 años","2 años","1 año"],"explanation":"Una segunda instancia de negarse a una prueba química, como cualquier segunda infracción mayor, resulta en la descalificación de por vida de la CDL. Fuente: RSA 263:94; 49 CFR 383.51."},"47":{"q":"En New Hampshire, ser condenado por DOS infracciones graves de tránsito en un CMV que surgen de incidentes separados dentro de 3 años resulta en una descalificación de la CDL de al menos:","options":["60 días","30 días","120 días","1 año"],"explanation":"Dos infracciones graves de tránsito dentro de un período de 3 años descalifican a un conductor para operar un CMV por no menos de 60 días. Fuente: RSA 263:94; 49 CFR 383.51."},"48":{"q":"Ser condenado por TRES infracciones graves de tránsito en un CMV de incidentes separados dentro de 3 años resulta en una descalificación de la CDL de New Hampshire de al menos:","options":["120 días","60 días","90 días","1 año"],"explanation":"Tres infracciones graves de tránsito dentro de un período de 3 años descalifican a un conductor para operar un CMV por no menos de 120 días. Fuente: RSA 263:94; 49 CFR 383.51."},"49":{"q":"Según las reglas de la CDL de New Hampshire, ¿a qué velocidad por encima del límite establecido una sola infracción de exceso de velocidad se convierte en una 'infracción grave de tránsito'?","options":["15 mph o más por encima del límite","10 mph o más por encima del límite","20 mph o más por encima del límite","25 mph o más por encima del límite"],"explanation":"Exceder la velocidad en 15 mph o más por encima del límite establecido se define como una infracción grave de tránsito para efectos de la CDL en New Hampshire. Fuente: RSA 259:98-a; N.H. Admin. Code Saf-C 1809.02."},"50":{"q":"¿Cuál de los siguientes se clasifica como una 'infracción grave de tránsito' para el titular de una CDL de New Hampshire?","options":["Seguir demasiado cerca (manejar pegado al de adelante)","Estacionar en un carril de bomberos","Conducir 5 mph por encima del límite","Una calcomanía de registro vencida"],"explanation":"Seguir demasiado cerca es una de las infracciones graves de tránsito enumeradas para titulares de CDL, junto con la conducción imprudente, los cambios de carril erráticos y el exceso de velocidad excesivo. Fuente: RSA 259:98-a; Saf-C 1809.02."},"51":{"q":"Para una PRIMERA condena por una infracción en un cruce a nivel entre vía férrea y carretera mientras se opera un CMV en New Hampshire, la descalificación mínima es:","options":["60 días","30 días","120 días","1 año"],"explanation":"Una primera infracción en un cruce a nivel entre vía férrea y carretera en un CMV conlleva una descalificación mínima de 60 días. Fuente: 49 CFR 383.51 Table 3, adoptada por New Hampshire; NH CDL Manual."},"52":{"q":"Una SEGUNDA infracción en un cruce a nivel entre vía férrea y carretera en un CMV dentro de 3 años resulta en una descalificación de la CDL de New Hampshire de al menos:","options":["120 días","60 días","90 días","1 año"],"explanation":"Una segunda infracción en un cruce a nivel dentro de 3 años conlleva una descalificación mínima de 120 días. Fuente: 49 CFR 383.51 Table 3, adoptada por New Hampshire."},"53":{"q":"Una TERCERA infracción o posterior en un cruce a nivel entre vía férrea y carretera en un CMV dentro de 3 años resulta en una descalificación de la CDL de New Hampshire de al menos:","options":["1 año","120 días","180 días","60 días"],"explanation":"Una tercera infracción o posterior en un cruce a nivel dentro de 3 años conlleva una descalificación mínima de 1 año. Fuente: 49 CFR 383.51 Table 3, adoptada por New Hampshire."},"54":{"q":"En New Hampshire, la PRIMERA infracción de conducir un CMV mientras se está bajo una orden de fuera de servicio (OOS) (no hazmat) resulta en una descalificación de:","options":["No menos de 180 días y no más de 1 año","No menos de 60 días y no más de 120 días","No menos de 30 días y no más de 90 días","No menos de 2 años y no más de 5 años"],"explanation":"Una primera infracción de una orden de fuera de servicio descalifica al conductor por no menos de 180 días y no más de 1 año. Fuente: 49 CFR 383.51 Table 4, adoptada por New Hampshire; NH CDL Manual."},"55":{"q":"Una SEGUNDA infracción de una orden de fuera de servicio (OOS) en un CMV dentro de 10 años resulta en una descalificación en New Hampshire de:","options":["No menos de 2 años y no más de 5 años","No menos de 180 días y no más de 1 año","No menos de 1 año y no más de 3 años","De por vida"],"explanation":"Una segunda infracción de una orden OOS dentro de 10 años conlleva una descalificación de no menos de 2 años y no más de 5 años. Fuente: 49 CFR 383.51 Table 4, adoptada por New Hampshire."},"56":{"q":"Un conductor que transporta materiales peligrosos con letreros (placards) u opera un vehículo diseñado para 16+ pasajeros comete una PRIMERA infracción de una orden de fuera de servicio en New Hampshire. La descalificación es:","options":["No menos de 180 días y no más de 2 años","No menos de 180 días y no más de 1 año","No menos de 60 días y no más de 120 días","No menos de 3 años y no más de 5 años"],"explanation":"Una primera infracción OOS mientras se transportan materiales peligrosos con letreros (placards) o en un vehículo de 16+ pasajeros conlleva un período elevado de no menos de 180 días y no más de 2 años. Fuente: 49 CFR 383.51 Table 4, adoptada por New Hampshire."},"57":{"q":"Según la ley de manos libres de New Hampshire, ¿cuál es la multa por una PRIMERA infracción de usar un dispositivo electrónico móvil de mano mientras se conduce?","options":["$100","$50","$250","$500"],"explanation":"La ley de manos libres de New Hampshire multa una primera infracción con $100, una segunda con $250, y cualquier infracción posterior dentro de 24 meses con $500. El uso de dispositivos de mano está prohibido para todos los conductores, incluidos los operadores de CMV. Fuente: RSA 265:79-c."},"58":{"q":"Según la ley de manos libres de New Hampshire (RSA 265:79-c), ¿cuál es la multa por una SEGUNDA infracción de usar un dispositivo electrónico de mano mientras se conduce?","options":["$250","$100","$500","$150"],"explanation":"Una segunda infracción de la ley de manos libres de New Hampshire se multa con $250 (una primera infracción es $100 y una infracción posterior dentro de 24 meses es $500). Fuente: RSA 265:79-c."},"59":{"q":"Para contar las infracciones de descalificación de la CDL, primera y posteriores, en New Hampshire, ¿con base en qué regla se contabilizan las condenas?","options":["Cada condena de un incidente separado cuenta, ya sea que se haya cometido en un CMV o en un vehículo no comercial","Solo cuentan las condenas mientras se conduce un CMV","Solo cuentan las condenas de los últimos 12 meses","Solo cuentan las condenas que resultan en tiempo en la cárcel"],"explanation":"Para determinar las infracciones de descalificación, primera y posteriores, cada condena de un incidente separado cuenta, ya sea que la infracción haya ocurrido en un vehículo comercial o no comercial. Fuente: RSA 263:94; 49 CFR 383.51."},"60":{"q":"Según la ley \"Move Over\" (Cambia de Carril) de New Hampshire, ¿qué debe hacer un conductor con CDL al acercarse a un vehículo detenido en el acotamiento que muestra luces de advertencia azules, rojas o ámbar?","options":["Reducir la velocidad y, si es posible, cambiarse de carril para dar al vehículo un amplio margen","Mantener la velocidad pero tocar el claxon de forma continua al pasar","Detenerse por completo en el carril de circulación hasta que el vehículo se retire","Continuar a la velocidad indicada porque la ley solo aplica a las patrullas de policía"],"explanation":"La ley \"Move Over\" de New Hampshire (RSA 265:37-a) exige que el conductor mantenga una velocidad reducida y, si es posible, dé un amplio margen al personal de seguridad pública y a cualquier vehículo detenido que muestre luces de emergencia o de advertencia azules, rojas o ámbar, apartándose de un carril bloqueado cuando sea seguro hacerlo. Fuente: NH RSA 265:37-a; NH CDL Manual."},"61":{"q":"En New Hampshire, antes de cruzar las vías del tren, un vehículo con materiales peligrosos rotulado o un autobús escolar que transporta niños debe detenerse dentro de qué distancia del riel más cercano?","options":["No menos de 15 pies ni más de 50 pies","No menos de 5 pies ni más de 25 pies","No menos de 25 pies ni más de 75 pies","No menos de 50 pies ni más de 100 pies"],"explanation":"La RSA 265:50 exige que los conductores de autobuses que transportan pasajeros, autobuses escolares que transportan niños y vehículos que transportan sustancias explosivas o peligrosas se detengan a no más de 50 pies pero no menos de 15 pies del riel más cercano, y luego miren y escuchen antes de continuar. Fuente: NH RSA 265:50; NH CDL Manual."},"62":{"q":"En un camino de dos carriles de New Hampshire, un conductor que se cruza o rebasa a un autobús escolar detenido con sus luces rojas intermitentes debe detener el vehículo al menos a qué distancia del autobús?","options":["Al menos a 25 pies de distancia","Al menos a 10 pies de distancia","Al menos a 50 pies de distancia","Al menos a 100 pies de distancia"],"explanation":"La RSA 265:54 exige que un conductor que se cruza o rebasa a un autobús escolar detenido que está recibiendo o bajando niños se detenga al menos a 25 pies del autobús y permanezca detenido hasta que el autobús reanude la marcha o las luces dejen de parpadear. Fuente: NH RSA 265:54."},"63":{"q":"En una carretera dividida de New Hampshire con calzadas separadas, ¿cuándo NO tiene que detenerse un conductor con CDL ante un autobús escolar que está recogiendo niños?","options":["Cuando el autobús está en la otra mitad de la carretera dividida, circulando en sentido contrario","Nunca: siempre es obligatorio detenerse ante un autobús escolar con luces rojas intermitentes","Solo cuando el conductor opera un camión rígido vacío","Siempre que el conductor circule a más de 45 mph"],"explanation":"La RSA 265:54 establece que un conductor en una carretera dividida con calzadas separadas no necesita detenerse cuando se cruza o pasa a un autobús escolar que está en la otra mitad de la carretera dividida circulando en sentido contrario. En un camino no dividido, todas las direcciones deben detenerse. Fuente: NH RSA 265:54."},"64":{"q":"¿Cuál es el límite máximo de velocidad general en las autopistas interestatales y de peaje de New Hampshire que son carreteras divididas de cuatro carriles (fuera del tramo de I-93 con límite más alto)?","options":["65 mph","55 mph","70 mph","75 mph"],"explanation":"La RSA 265:60 establece un máximo de 65 mph en el sistema interestatal y en las autopistas de peaje del centro y este de New Hampshire donde son carreteras divididas de cuatro carriles. New Hampshire aplica los mismos límites indicados a los camiones que a los automóviles. Fuente: NH RSA 265:60."},"65":{"q":"¿En qué vía de New Hampshire el límite de velocidad indicado es de 70 mph, el más alto del estado?","options":["La I-93 desde el marcador de milla 45 hasta la frontera con Vermont","Toda la extensión de la I-95 (Blue Star Turnpike)","La Spaulding Turnpike desde Portsmouth hasta Milton","La I-89 desde Concord hasta la frontera con Vermont"],"explanation":"La RSA 265:60 fija el límite de velocidad en 70 mph en la I-93 desde el marcador de milla 45 hasta la frontera con Vermont. Este es el límite indicado más alto en New Hampshire y aplica también a los vehículos comerciales. Fuente: NH RSA 265:60."},"66":{"q":"¿New Hampshire establece un límite de velocidad más bajo para los camiones que para los automóviles de pasajeros en sus interestatales?","options":["No: los camiones deben obedecer el mismo límite indicado que todos los demás vehículos","Sí: los camiones están limitados a 55 mph donde los automóviles pueden ir a 65 mph","Sí: los camiones están limitados a 60 mph en todo el estado","Sí: los camiones están limitados a 45 mph en todas las carreteras divididas"],"explanation":"El estatuto de velocidad de New Hampshire (RSA 265:60) fija límites máximos que aplican a todos los vehículos y no establece un límite de velocidad separado y más bajo para camiones; los vehículos comerciales obedecen los mismos límites indicados que los automóviles. Fuente: NH RSA 265:60."},"67":{"q":"Según la ley de New Hampshire, ¿qué se le exige a un camión de marcha lenta en una calzada de varios carriles respecto a su posición en el carril?","options":["Debe mantenerse en el carril derecho y no ocupar de forma continua el carril izquierdo de manera que impida el tránsito","Puede permanecer en el carril izquierdo indefinidamente siempre que use las direccionales","Debe usar únicamente el carril central en cualquier carretera de tres carriles","Está exento de las reglas de mantenerse a la derecha debido a su tamaño"],"explanation":"La RSA 265:16 exige que un vehículo que circula más lento que el tránsito normal se mantenga en el carril derecho y prohíbe circular de forma continua en el carril izquierdo de una calzada de varios carriles cuando ello impide el flujo del tránsito. Fuente: NH RSA 265:16."},"68":{"q":"New Hampshire exige que todo camión o autobús de más de 10,000 libras lleve qué tipo de dispositivos de advertencia de emergencia para usar cuando está detenido en la carretera?","options":["Tres dispositivos de advertencia reflectantes bidireccionales (triángulos reflectantes)","Dos faroles de combustible líquido encendidos","Una sola baliza estroboscópica a pilas","Cuatro banderas rojas de tela en astas"],"explanation":"La RSA 265:113 exige que todo camión, autobús o tractocamión de más de 10,000 libras de GVW lleve tres dispositivos de advertencia reflectantes bidireccionales aprobados por el director, en concordancia con las regulaciones federales de seguridad de transportistas motorizados. Fuente: NH RSA 265:113; NH CDL Manual."},"69":{"q":"Cuando un vehículo comercial de New Hampshire de más de 10,000 libras está detenido en una carretera de dos carriles, ¿dónde deben colocarse generalmente los tres dispositivos de advertencia?","options":["Aproximadamente a 10 pies detrás del vehículo, a 100 pies hacia atrás y a 100 pies hacia adelante","Los tres dentro de los 10 pies de la defensa trasera","Uno a 25 pies adelante y dos a 25 pies atrás","A 200 pies adelante, 200 pies atrás y uno en el techo"],"explanation":"Según la RSA 265:113, en un camino común de doble sentido los dispositivos se colocan aproximadamente a 10 pies del vehículo del lado del tránsito, a 100 pies hacia atrás y a 100 pies hacia adelante. En un camino dividido o de un solo sentido, el espaciado es de 10, 100 y 200 pies hacia el tránsito que se aproxima. Fuente: NH RSA 265:113; NH CDL Manual."},"70":{"q":"Después de detenerse en un cruce ferroviario en New Hampshire, ¿qué exige la ley a un conductor de autobús o de materiales peligrosos mientras cruza efectivamente las vías?","options":["Cruzar en una marcha lo suficientemente baja como para que no haya necesidad de cambiar de marcha mientras está sobre las vías","Acelerar fuerte y cambiar a marchas altas rápidamente para despejar las vías lo más rápido posible","Poner el cambio en neutral y cruzar las vías por inercia","Aplicar brevemente el freno de estacionamiento en el punto medio del cruce"],"explanation":"La RSA 265:50 ordena que, después de detenerse y cuando sea seguro continuar, el conductor debe cruzar en una marcha tal que no haya necesidad de cambiar de marcha mientras cruza, y no deberá cambiar de marcha mientras está sobre las vías. Fuente: NH RSA 265:50."},"71":{"q":"¿Cuál es la estructura de sanciones de New Hampshire para una primera infracción por no obedecer la ley \"Move Over\" (RSA 265:37-a)?","options":["$75 más el recargo de penalización por una primera infracción","$250 más una suspensión de licencia de 30 días por una primera infracción","$500 más descalificación obligatoria de la CDL","Solo una advertencia por escrito en la primera infracción"],"explanation":"Según la RSA 265:37-a, una primera infracción de la ley \"Move Over\" de New Hampshire conlleva una multa de $75 más el recargo de penalización, que aumenta a $250 más el recargo por una infracción posterior dentro de 12 meses. Fuente: NH RSA 265:37-a."},"72":{"q":"Sin un permiso de sobredimensión, ¿cuál es el ancho legal máximo de un vehículo comercial en las carreteras de New Hampshire?","options":["8 pies 6 pulgadas","8 pies 0 pulgadas","9 pies 0 pulgadas","10 pies 6 pulgadas"],"explanation":"New Hampshire sigue el límite legal federal de ancho de 8 pies 6 pulgadas (102 inches); cualquier cosa más ancha requiere un permiso de sobredimensión del NHDOT. Fuente: reglas de permisos de sobredimensión/sobrepeso del NH DOT; guía para transportistas motorizados de la NH State Police Troop G."},"73":{"q":"Sin un permiso de sobrepeso, ¿cuál es el peso bruto vehicular legal máximo para un vehículo comercial en las carreteras de New Hampshire?","options":["80,000 libras","73,280 libras","90,000 libras","100,000 libras"],"explanation":"El peso bruto vehicular legal máximo de New Hampshire es de 80,000 libras tanto en las interestatales como en otras carreteras; excederlo requiere un permiso/certificación de sobrepeso a través del NHDOT. Fuente: reglas de permisos de sobredimensión/sobrepeso del NH DOT; NH State Police Troop G."},"74":{"q":"Sin un permiso, ¿cuál es la altura legal máxima de un vehículo comercial en los caminos de New Hampshire?","options":["13 pies 6 pulgadas","12 pies 6 pulgadas","14 pies 0 pulgadas","13 pies 0 pulgadas"],"explanation":"La altura legal máxima de un vehículo en New Hampshire es de 13 pies 6 pulgadas en todos los tipos de camino; una carga más alta requiere un permiso de sobredimensión del NHDOT. Fuente: reglas de permisos de sobredimensión/sobrepeso del NH DOT."},"75":{"q":"En la porción Franconia Notch Parkway de la I-93 en New Hampshire, ¿qué es distintivo para los conductores comerciales en comparación con el resto de la interestatal?","options":["Se reduce a un solo carril en cada sentido con un límite reducido de 45 mph","Tiene un carril exprés exclusivo para camiones en cada sentido","Permite un límite de 80 mph para los camiones de paso","Prohíbe todos los automóviles de pasajeros durante las horas de luz del día"],"explanation":"El tramo Franconia Notch Parkway de la I-93 se construyó bajo una excepción especial a los estándares interestatales y se reduce a un solo carril en cada sentido con un límite indicado de 45 mph, lo que exige precaución adicional de los CMV en la pendiente. Fuente: NH DOT; autoridad de zona reducida de la NH RSA 265:60."},"76":{"q":"¿Qué organismo emite los permisos de sobredimensión/sobrepeso para vehículos comerciales que exceden los límites legales en New Hampshire?","options":["El Departamento de Transporte de New Hampshire (NHDOT)","La oficina regional de la Federal Highway Administration","El departamento de policía local de cada pueblo que se cruza","La New Hampshire Liquor Commission"],"explanation":"Los permisos de sobredimensión y sobrepeso en New Hampshire son emitidos por la oficina de permisos del Departamento de Transporte de New Hampshire (NHDOT); las cargas que exceden el tamaño o peso legal deben contar con permiso y pueden tener restricciones de ruta. Fuente: oficina de permisos de sobredimensión/sobrepeso del NH DOT."},"77":{"q":"Según la ley de New Hampshire, cuando un autobús escolar está en movimiento y lo siguen cuántos vehículos o más, ¿debe el conductor del autobús orillarse para dejarlos pasar cuando las condiciones lo permitan?","options":["5 o más vehículos que lo siguen","3 o más vehículos que lo siguen","10 o más vehículos que lo siguen","2 o más vehículos que lo siguen"],"explanation":"La RSA 265:54 ordena que siempre que las condiciones del camino y el espacio lo permitan y el número de vehículos que siguen a un autobús escolar en movimiento sea de 5 o más, el conductor del autobús deberá orillarse para dejar pasar a los vehículos que lo siguen. Fuente: NH RSA 265:54."},"78":{"q":"En New Hampshire, ¿qué debe hacer un conductor al acercarse a un autobús de tránsito o de pasajeros que se ha detenido para que suban o bajen pasajeros (y que no es un autobús escolar mostrando luces rojas intermitentes)?","options":["Reducir la velocidad y, si es necesario para la seguridad pública, detenerse por completo","Pasar a toda velocidad porque solo los autobuses escolares requieren precaución","Detenerse al menos a 100 pies de distancia sin importar las condiciones","Tocar el claxon tres veces y continuar sin reducir la velocidad"],"explanation":"La RSA 265:55 exige que un conductor que se acerca o pasa a un autobús, tranvía u otro vehículo de pasajeros detenido para subir o bajar pasajeros reduzca la velocidad y, si es necesario para la seguridad del público, detenga el vehículo por completo. Fuente: NH RSA 265:55."},"79":{"q":"Un conductor con CDL se cruza con un autobús escolar detenido con luces rojas intermitentes en una carretera no dividida de New Hampshire. El conductor puede reanudar la marcha cuando:","options":["El autobús reanuda la marcha o las luces rojas intermitentes se apagan","Han transcurrido tres segundos desde que se detuvo, sin importar las luces","El conductor juzga que no hay niños a la vista, aunque las luces sigan parpadeando","El conductor del autobús hace una seña, aunque las luces rojas sigan encendidas"],"explanation":"Según la RSA 265:54, un conductor detenido ante un autobús escolar en un camino no dividido debe permanecer detenido hasta que el autobús reanude la marcha o las luces rojas intermitentes se apaguen; una primera infracción es una multa de $150 más el recargo, con posible suspensión de licencia. Fuente: NH RSA 265:54."},"80":{"q":"¿Qué organismo emite las Licencias de Conducir Comerciales (CDL) en New Hampshire?","options":["La División de Vehículos Motorizados de New Hampshire (DMV)","La Federal Motor Carrier Safety Administration (FMCSA)","El Departamento de Transporte de New Hampshire (NHDOT)","El Buró Comercial de la New Hampshire State Police"],"explanation":"En New Hampshire, las CDL son emitidas por la División de Vehículos Motorizados de New Hampshire (DMV), que administra las pruebas y el licenciamiento bajo los estándares federales de la FMCSA. El NHDOT se encarga de los caminos y de los permisos de sobredimensión/sobrepeso, no del licenciamiento. Fuente: NH DMV, página de Commercial Driver Licenses."},"81":{"q":"Antes de que un solicitante de New Hampshire pueda programar la prueba de destrezas (de manejo) de la CDL, ¿qué capacitación federal debe completar?","options":["Entry-Level Driver Training (ELDT) de un proveedor registrado","Un programa estatal de aprendizaje de 160 horas","Un curso de manejo defensivo aprobado por el NH DMV","Una certificación de seguridad en vehículos comerciales de OSHA"],"explanation":"New Hampshire sigue la regla federal de ELDT: los solicitantes deben completar el Entry-Level Driver Training de un proveedor del FMCSA Training Provider Registry antes de poder programar la prueba de destrezas de la CDL. Fuente: NH DMV, página de Commercial Driver Learner Permit; 49 CFR Part 380."},"82":{"q":"Después de que se emite un CLP de New Hampshire, ¿cuánto tiempo debe esperar el titular antes de poder programar la prueba de manejo (destrezas) de la CDL?","options":["Al menos 14 días","Al menos 10 días","Al menos 30 días","Al menos 7 días"],"explanation":"New Hampshire aplica la espera federal de 14 días: después de aprobar los exámenes de conocimientos y que se emita el CLP, la prueba de manejo puede programarse no antes de 14 días desde la fecha en que se emitió el CLP. Fuente: NH DMV, página de Commercial Driver Learner Permit; 49 CFR 383.25."},"83":{"q":"La prueba de destrezas de la CDL de New Hampshire consta de tres partes separadas. ¿Qué conjunto las enumera correctamente?","options":["Inspección previa al viaje, control básico del vehículo y manejo en carretera","Conocimientos por escrito, examen de la vista y manejo en carretera","Inspección previa al viaje, demostración de frenos de aire y manejo nocturno","Acoplamiento/desacoplamiento, reversa y un examen escrito de endoso"],"explanation":"La prueba de destrezas de la CDL de New Hampshire tiene tres partes: la inspección previa al viaje (del vehículo), la prueba de destrezas de control básico del vehículo y la prueba de manejo en carretera. Las pruebas de conocimientos y de la vista son requisitos previos separados, no parte de la prueba de destrezas. Fuente: NH DMV, página de CDL Road Test."},"84":{"q":"En la autocertificación de New Hampshire para solicitantes de CDL, ¿entre cuántas categorías de operación comercial debe elegir el conductor?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Los solicitantes de CDL de New Hampshire deben autocertificarse en una de cuatro categorías: interestatal no exceptuada, interestatal exceptuada, intraestatal no exceptuada e intraestatal exceptuada. Fuente: formulario de autocertificación DSMV 612 del NH DMV."},"85":{"q":"Un conductor de New Hampshire se autocertifica como 'interestatal no exceptuado'. ¿Qué requiere esta categoría?","options":["Un DOT Medical Examiner's Certificate válido en el expediente","Ningún certificado médico de ningún tipo","Solo una exención médica intraestatal emitida por el estado","Una Transportation Worker Identification Credential en lugar de una tarjeta médica"],"explanation":"Los conductores interestatales no exceptuados operan a través de líneas estatales en comercio no exceptuado y deben tener y mantener en el expediente un DOT Medical Examiner's Certificate válido. Las categorías exceptuadas no están obligadas a proporcionar una tarjeta médica. Fuente: formulario DSMV 612 del NH DMV; 49 CFR 383.71."},"86":{"q":"¿Qué formulario de New Hampshire usan los titulares de CDL para autocertificar su categoría de operación y enviar la información de la tarjeta médica al DMV?","options":["DSMV 612","DSMV 312","MCSA-5876","DSMV 500"],"explanation":"New Hampshire usa el formulario DSMV 612 para la autocertificación de la CDL y para enviar la información de tarjeta médica/certificación al DMV. El DSMV 312 es la solicitud de CDL; el MCSA-5876 es el federal Medical Examiner's Certificate que completa el examinador. Fuente: NH DMV, CDL Medical Card Update; formulario DSMV 612."},"87":{"q":"En la prueba escrita de conocimientos generales de la CDL de New Hampshire, ¿cuál es el puntaje mínimo requerido para aprobar?","options":["80%","70%","75%","90%"],"explanation":"New Hampshire requiere un puntaje mínimo de aprobación del 80% en la prueba de conocimientos generales de la CDL (40 de 50 preguntas correctas). Fuente: NH CDL Manual; requisitos de prueba de conocimientos del NH DMV."},"88":{"q":"Una CDL de New Hampshire vence en el cumpleaños del titular en qué año posterior a su emisión?","options":["El quinto año","El cuarto año","El sexto año","El décimo año"],"explanation":"Según la RSA 263:93, una licencia de conducir comercial de New Hampshire vence en la fecha de cumpleaños del titular en el quinto año posterior a su emisión, lo que la convierte en un ciclo de renovación de cinco años. Fuente: NH RSA 263:93 (License Expiration and Renewal)."},"89":{"q":"¿Cuál es la edad mínima para obtener una CDL de New Hampshire para manejo intraestatal (solo dentro del estado)?","options":["18 años","16 años","21 años","19 años"],"explanation":"Un solicitante debe tener al menos 18 años para tener una CDL de New Hampshire para manejo intraestatal. Los conductores menores de 21 años están restringidos únicamente a la operación intraestatal. Fuente: NH DMV, página de Commercial Driver Licenses."},"90":{"q":"¿Cuál es la edad mínima para manejar de forma interestatal (a través de líneas estatales) u obtener un endoso de HAZMAT en una CDL de New Hampshire?","options":["21 años","18 años","23 años","25 años"],"explanation":"Un titular de CDL de New Hampshire debe tener al menos 21 años para manejar en comercio interestatal o para portar un endoso de HAZMAT. Los titulares de 18 a 20 años están limitados al manejo intraestatal. Fuente: NH DMV, página de Commercial Driver Licenses; 49 CFR 383."},"91":{"q":"¿Cuál formulario es la solicitud de Licencia de Conducir Comercial de New Hampshire en sí?","options":["DSMV 312","DSMV 612","MCSA-5875","DSMV 426"],"explanation":"La solicitud de CDL de New Hampshire es el formulario DSMV 312. El DSMV 612 es el formulario separado de autocertificación/tarjeta médica. Fuente: formularios de CDL del NH DMV; Apply for a CDL."},"92":{"q":"Además de las pruebas de conocimientos y de destrezas, ¿qué examen de evaluación debe aprobar todo solicitante de CDL de New Hampshire?","options":["Un examen de la vista","Un examen escrito de primeros auxilios","Un análisis de sangre de drogas y alcohol administrado en el DMV","Una pista de obstáculos de agilidad física"],"explanation":"Todos los solicitantes de CDL de New Hampshire deben aprobar un examen de la vista además de las pruebas de conocimientos y de destrezas. Fuente: NH DMV, página de Commercial Driver Licenses."},"93":{"q":"Para la prueba de manejo de la CDL de New Hampshire, el solicitante generalmente debe proporcionar qué tipo de vehículo de prueba?","options":["Un vehículo representativo de la misma clase/tipo de la CDL que se busca, con una calcomanía de inspección válida","Cualquier automóvil de pasajeros con registro vigente","Un vehículo proporcionado sin costo por el NH DMV","Un vehículo rentado de menos de 26,001 lbs de GVWR sin importar la clase"],"explanation":"El solicitante debe proporcionar un vehículo de prueba representativo que coincida con la clase/tipo de CDL que se busca, debidamente registrado y asegurado, y que muestre una calcomanía de inspección de New Hampshire válida. Fuente: NH DMV, página de CDL Road Test."},"94":{"q":"Si la certificación médica de un titular de CDL de New Hampshire vence y no se presenta un certificado actualizado o una variación, ¿dentro de cuánto tiempo debe el DMV degradar la CDL?","options":["60 días","10 días","30 días","180 días"],"explanation":"Según la regla federal de certificación médica que New Hampshire hace cumplir, el estado debe degradar una CDL o CLP dentro de los 60 días de un vencimiento si no se presenta un certificado médico actual o una variación (o el conductor cambia a una categoría exceptuada/intraestatal donde se permita). Fuente: 49 CFR 383.73; NH DMV CDL Medical Card Update."},"95":{"q":"¿Qué clase de CDL de New Hampshire autoriza operar un solo vehículo con un GVWR de 26,001 lbs o más (sin remolcar nada de más de 10,000 lbs)?","options":["Clase B","Clase A","Clase C","Clase D"],"explanation":"Una CDL Clase B cubre cualquier vehículo individual con un GVWR de 26,001 lbs o más, o tal vehículo remolcando una unidad de no más de 10,000 lbs de GVWR. La Clase A cubre combinaciones de más de 26,001 lbs con una unidad remolcada de más de 10,000 lbs. Fuente: NH DMV, página de License Classifications."},"96":{"q":"Antes de solicitar un endoso de HAZMAT en una CDL de New Hampshire, ¿qué paso federal adicional debe completar el solicitante?","options":["Una evaluación de amenaza de seguridad de la TSA con verificación de antecedentes basada en huellas dactilares","Un curso de manejo de materiales peligrosos de OSHA de 40 horas","Un registro de transportista de residuos peligrosos de la EPA","Una segunda prueba de destrezas en carretera en un vehículo cisterna"],"explanation":"Los solicitantes de un endoso de HAZMAT deben aprobar una evaluación de amenaza de seguridad de la TSA, que incluye toma de huellas dactilares y una verificación de antecedentes, además de la prueba de conocimientos de HAZMAT. Fuente: NH DMV, página de Commercial Driver Licenses; 49 CFR Part 1572."},"97":{"q":"Bajo el proceso federal modernizado de certificación médica que New Hampshire sigue (vigente en 2025), ¿cómo llegan ahora la mayoría de los resultados del Medical Examiner's Certificate al estado?","options":["Los examinadores médicos transmiten los resultados electrónicamente a la FMCSA, que los envía al estado para actualizar el registro de manejo","Los conductores siempre deben entregar en persona el certificado en papel en una oficina del DMV","Los empleadores envían los certificados directamente a la FMCSA en nombre del conductor","Los certificados se archivan únicamente con la aseguradora del conductor"],"explanation":"Bajo el proceso federal vigente desde el 23 de junio de 2025 que New Hampshire sigue, los examinadores médicos certificados reportan los resultados del examen electrónicamente a la FMCSA, que transmite el estado de la certificación médica al estado para actualizar el registro de la CDL; los conductores aún deben autocertificar su categoría de operación (por ejemplo, mediante el DSMV 612). Fuente: regla de Certificación Médica de la FMCSA; NH DMV CDL Medical Card Update."},"98":{"q":"Una persona de 19 años aprueba todas las pruebas de CDL de New Hampshire y califica para una CDL. ¿Qué restricción de operación aplica?","options":["Está limitada al comercio intraestatal (dentro de New Hampshire) hasta los 21 años","Puede manejar de forma interestatal pero no transportar pasajeros","Puede manejar de forma interestatal solo con un endoso de HAZMAT","No hay restricción de operación basada en la edad una vez aprobadas las pruebas"],"explanation":"Un titular de CDL de New Hampshire que tiene al menos 18 años pero menos de 21 está restringido únicamente al manejo intraestatal; la operación interestatal y HAZMAT requieren tener 21 años. Fuente: NH DMV, página de Commercial Driver Licenses; 49 CFR 391.11."}},"hi":{"0":{"q":"न्यू हैम्पशायर की सड़कों पर, ओवर-डाइमेंशन परमिट की आवश्यकता होने से पहले किसी वाहन की, उसके भार सहित, अधिकतम चौड़ाई कितनी होती है?","options":["96 inches","102 inches","108 inches","114 inches"],"explanation":"न्यू हैम्पशायर RSA 266:12 किसी भी ऐसे वाहन को चलाने पर रोक लगाता है जिसकी चौड़ाई भार सहित 102 inches (8 feet 6 inches) से अधिक हो। यह National Network के लिए संघीय मानक से मेल खाता है। स्रोत: NH RSA 266:12 Width; NH CDL Manual."},"1":{"q":"बिना परमिट के न्यू हैम्पशायर की सड़कों पर अनुमत किसी मानक वाहन (जो निर्मित आवास का परिवहन नहीं कर रहा है) की, भार सहित, अधिकतम ऊँचाई कितनी होती है?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"explanation":"न्यू हैम्पशायर RSA 266:10 कहता है कि कोई भी वाहन (निर्मित आवास या मॉड्यूलर भवनों का परिवहन करने वाले वाहन को छोड़कर) जिसकी कुल ऊँचाई भार सहित 13 feet 6 inches से अधिक हो, राज्य की सड़कों पर नहीं चलाया जा सकता। स्रोत: NH RSA 266:10 Height."},"2":{"q":"न्यू हैम्पशायर में, बिना परमिट के संचालित ट्रक-ट्रैक्टर/सेमी-ट्रेलर संयोजन में सेमी-ट्रेलर की अधिकतम लंबाई कितनी होती है?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"न्यू हैम्पशायर RSA 266:11 एक ट्रक-ट्रैक्टर और एकल सेमी-ट्रेलर संयोजन में 53 feet तक के सेमी-ट्रेलर की अनुमति देता है (48 feet से अधिक के ट्रेलरों के लिए अतिरिक्त किंगपिन और रियर-प्रोटेक्शन आवश्यकताएँ होती हैं)। स्रोत: NH RSA 266:11 Length."},"3":{"q":"न्यू हैम्पशायर कानून के तहत, बिना ओवरवेट परमिट के संचालित होने वाले पाँच या अधिक एक्सल वाले संयोजन वाहन के लिए अधिकतम कुल वाहन भार (सभी कानून-प्रवर्तन सहनशीलताओं सहित) कितना होता है?","options":["73,280 pounds","80,000 pounds","84,000 pounds","90,000 pounds"],"explanation":"न्यू हैम्पशायर 5-या-अधिक-एक्सल संयोजन के लिए अधिकतम कुल भार को सभी कानून-प्रवर्तन सहनशीलताओं सहित 80,000 pounds तक सीमित करता है, जो संघीय सीमा के अनुरूप है। स्रोत: NH RSA 266:18 / 266:18-a."},"4":{"q":"बिना परमिट के न्यू हैम्पशायर की Interstate and Defense Highway System पर एकल-एक्सल पर अनुमत अधिकतम भार कितना होता है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Interstate and Defense Highway System पर, न्यू हैम्पशायर RSA 266:18 एकल एक्सल को 20,000 pounds तक सीमित करता है, जो संघीय Interstate मानक से मेल खाता है। (22,400 lb जैसे उच्च आँकड़े केवल कुछ गैर-Interstate विन्यासों पर लागू होते हैं।) स्रोत: NH RSA 266:18."},"5":{"q":"न्यू हैम्पशायर की Interstate and Defense Highway System पर, एक टैंडम एक्सल पर अनुमत अधिकतम भार कितना होता है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"न्यू हैम्पशायर RSA 266:18 Interstate and Defense Highway System पर एक टैंडम एक्सल को 34,000 pounds तक सीमित करता है, जो संघीय मानक के समान है। स्रोत: NH RSA 266:18."},"6":{"q":"न्यू हैम्पशायर का ओवरवेट प्रवर्तन एक भार-वितरण सूत्र का उपयोग करता है जो कुल भार को एक्सल अंतराल और एक्सल की संख्या से जोड़ता है। यह सूत्र आमतौर पर किस नाम से जाना जाता है:","options":["Federal bridge formula","Kingpin setback formula","Gross combination rating formula","Tare weight formula"],"explanation":"न्यू हैम्पशायर RSA 266:18 संघीय bridge formula W = 500[LN/(N-1) + 12N + 36] को शामिल करता है, जहाँ W एक्सल समूह पर कुल भार है, L चरम एक्सल के बीच की दूरी है, और N एक्सल की संख्या है। स्रोत: NH RSA 266:18."},"7":{"q":"न्यू हैम्पशायर bridge formula W = 500[LN/(N-1) + 12N + 36] में, चर 'N' किसका प्रतिनिधित्व करता है?","options":["समूह में एक्सल की संख्या","भार का शुद्ध वजन","ट्रेलरों की संख्या","नाममात्र टायर चौड़ाई"],"explanation":"न्यू हैम्पशायर (RSA 266:18) द्वारा अपनाए गए bridge formula में, N विचाराधीन समूह में एक्सल की संख्या के बराबर है; L चरम एक्सल के बीच की दूरी feet में है, और W परिणामी अनुमत कुल भार है। स्रोत: NH RSA 266:18."},"8":{"q":"न्यू हैम्पशायर की सड़कों पर ट्रिपल-ट्रेलर ट्रक संयोजन:","options":["केवल Interstates पर अनुमत हैं","वार्षिक परमिट के साथ अनुमत हैं","प्रतिबंधित हैं","केवल रात में अनुमत हैं"],"explanation":"न्यू हैम्पशायर RSA 266:11-b राज्य की सड़कों पर ट्रिपल-ट्रेलर ट्रकों के संचालन पर रोक लगाता है। स्रोत: NH RSA 266:11-b Triple Trailer Trucks Prohibited."},"9":{"q":"एक वाहक को ऐसा भार ले जाना है जो न्यू हैम्पशायर की कानूनी आकार या भार सीमाओं से अधिक है। आवश्यक ओवरसाइज़/ओवरवेट परमिट कौन सी एजेंसी जारी करती है?","options":["स्थानीय शहर का सड़क एजेंट","New Hampshire Department of Transportation","Federal Motor Carrier Safety Administration","काउंटी शेरिफ का कार्यालय"],"explanation":"न्यू हैम्पशायर में ओवरसाइज़/ओवरवेट (OSOW) परमिट NH Department of Transportation द्वारा उसके परमिट कार्यालय के माध्यम से जारी किए जाते हैं (आवेदन ऑनलाइन, व्यक्तिगत रूप से 7 Hazen Drive, Concord पर, या फोन द्वारा)। स्रोत: NHDOT Permits / OSOW Permit Office."},"10":{"q":"न्यू हैम्पशायर में एक ओवरसाइज़ या ओवरवेट भार को आमतौर पर किन घंटों के दौरान यात्रा करने की अनुमति होती है?","options":["दिन में 24 घंटे, किसी भी दिन","सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटे बाद तक, सोमवार से शुक्रवार","केवल प्रतिदिन रात 9:00 p.m. और सुबह 5:00 a.m. के बीच","केवल सप्ताहांत पर, यात्रियों के यातायात से बचने के लिए"],"explanation":"NHDOT OSOW परमिट नियमों के तहत, ओवरसाइज़/ओवरवेट भार आमतौर पर सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटे बाद तक, सोमवार से शुक्रवार यात्रा कर सकते हैं, और ओवरडाइमेंशनल भार की सप्ताहांत और छुट्टी की यात्रा की अनुमति नहीं है। स्रोत: NHDOT OSOW Permit travel restrictions."},"11":{"q":"बिना परमिट के न्यू हैम्पशायर की सड़कों पर किसी एकल-इकाई वाहन या बस की, आगे और पीछे के बम्पर सहित, अधिकतम लंबाई कितनी होती है?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"न्यू हैम्पशायर RSA 266:11 एक एकल-इकाई वाहन या बस को आगे और पीछे के बम्पर सहित 45 feet तक सीमित करता है। स्रोत: NH RSA 266:11 Length."},"12":{"q":"जब कोई वाहन न्यू हैम्पशायर में निर्मित आवास या मॉड्यूलर भवनों का परिवहन कर रहा हो, तो अधिकतम अनुमत ऊँचाई कितनी होती है:","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"न्यू हैम्पशायर RSA 266:10 निर्मित आवास या मॉड्यूलर भवनों का परिवहन करने वाले वाहनों के लिए अधिकतम 14 feet 6 inches की ऊँचाई की अनुमति देता है; 13 feet 6 inches से अधिक के भार के लिए एक गैर-पुलिस एस्कॉर्ट की आवश्यकता होती है। स्रोत: NH RSA 266:10 Height."},"13":{"q":"न्यू हैम्पशायर की गैर-Interstate (सामान्य) राजमार्ग प्रणाली पर, 3-एक्सल एकल-इकाई वाहन पर एक एकल एक्सल अधिकतम कितना भार ढो सकता है:","options":["18,000 pounds","20,000 pounds","22,400 pounds","25,000 pounds"],"explanation":"न्यू हैम्पशायर RSA 266:18-a गैर-Interstate सामान्य राजमार्ग प्रणाली पर 3-एक्सल एकल-इकाई वाहनों (और 10 feet या अधिक दूरी पर एक्सल वाले अन्य वाहनों) पर प्रति एक्सल 22,400 pounds तक की अनुमति देता है, जो 20,000-pound Interstate सीमा से अधिक है। स्रोत: NH RSA 266:18-a."},"14":{"q":"न्यू हैम्पशायर में कच्चे वानिकी उत्पादों को ढोने वाले चार या अधिक एक्सल वाले ट्रक-ट्रैक्टर और एकल सेमी-ट्रेलर संयोजन के लिए, एक टैंडम एक्सल पर अधिकतम भार बढ़ाकर कितना कर दिया जाता है:","options":["34,000 pounds","36,000 pounds","40,000 pounds","44,000 pounds"],"explanation":"न्यू हैम्पशायर RSA 266:18-b कच्चे वानिकी उत्पादों (असंसाधित लट्ठे और लकड़ी के चिप्स) को ढोने वाले 4 या अधिक एक्सल के ट्रक-ट्रैक्टर और एकल सेमी-ट्रेलर संयोजन के लिए एक टैंडम एक्सल को 40,000 pounds तक ढोने की अनुमति देता है। स्रोत: NH RSA 266:18-b."},"15":{"q":"न्यू हैम्पशायर कानून प्रवर्तन अधिकारियों को उल्लंघन जारी करने से पहले निर्धारित एक्सल-समूह और कुल भार सीमाओं से ऊपर कितनी सामान्य सहनशीलता की अनुमति देने के लिए अधिकृत करता है?","options":["1 percent","2 percent","5 percent","15 percent"],"explanation":"न्यू हैम्पशायर RSA 266:18-a और 266:18-c निर्धारित भार सीमाओं से ऊपर 5 percent की सहनशीलता को अधिकृत करते हैं (266:18-c के तहत कुछ एक्सल भारों पर 10 percent तक की अनुमति है)। स्रोत: NH RSA 266:18-a / 266:18-c."},"16":{"q":"Interstate प्रणाली पर, न्यू हैम्पशायर में टैंडम एक्सल के दो लगातार सेट प्रत्येक केवल तभी 34,000 pounds ढो सकते हैं जब उन टैंडम सेटों के पहले और अंतिम एक्सल के बीच की दूरी कम से कम कितनी हो:","options":["28 feet","30 feet","36 feet","40 feet"],"explanation":"न्यू हैम्पशायर RSA 266:18 दो लगातार टैंडम-एक्सल सेटों को प्रत्येक 34,000 pounds ढोने की अनुमति केवल तभी देता है जब पहले और अंतिम एक्सल के बीच की कुल दूरी 36 feet या अधिक हो, और कुल भार 80,000 pounds से अधिक न हो। स्रोत: NH RSA 266:18."},"17":{"q":"न्यू हैम्पशायर की गैर-Interstate सामान्य राजमार्ग प्रणाली पर, पाँच-या-अधिक-एक्सल संयोजन के लिए अधिकतम टैंडम-एक्सल भार कितना होता है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"न्यू हैम्पशायर RSA 266:18-a गैर-Interstate सामान्य राजमार्ग प्रणाली पर 5-या-अधिक-एक्सल संयोजन पर एक टैंडम एक्सल को 36,000 pounds तक ढोने की अनुमति देता है, जो 34,000-pound Interstate टैंडम सीमा से अधिक है। स्रोत: NH RSA 266:18-a."},"18":{"q":"एक न्यू हैम्पशायर-आधारित वाहक 75 feet से अधिक लंबे, 10 feet 6 inches से अधिक चौड़े, और 13 feet 6 inches से अधिक ऊँचे न होने वाले वाहन की राज्यव्यापी यात्रा के लिए एक वार्षिक ओवरसाइज़ परमिट चाहता है। राज्यव्यापी यात्रा के लिए निर्धारित वार्षिक परमिट शुल्क क्या है?","options":["$60.00","$115.00","$200.00","$300.00"],"explanation":"NHDOT वार्षिक ओवरसाइज़ परमिट शुल्क को NH-आधारित और पंजीकृत वाहकों के लिए राज्यव्यापी यात्रा हेतु $115.00 (या 100-mile दायरे के भीतर यात्रा के लिए $60.00) के रूप में सूचीबद्ध करता है, उन वाहनों के लिए जो निर्धारित 75 ft / 10 ft 6 in / 13 ft 6 in सीमाओं के भीतर हों। स्रोत: NHDOT OSOW Permit fees."},"19":{"q":"न्यू हैम्पशायर RSA 266:16 के तहत, अनुमत आकार सीमाओं से अधिक वाहन चलाने के पहले अपराध के लिए दंड कितने जुर्माने का होता है:","options":["$100 से अधिक नहीं","$250 से अधिक नहीं","$500 से अधिक नहीं","$1,000 से अधिक नहीं"],"explanation":"न्यू हैम्पशायर RSA 266:16 अनुमत आकार से अधिक होने के लिए दंड को पहले अपराध के लिए $100 से अधिक नहीं और उसी कैलेंडर वर्ष के भीतर बाद के अपराध के लिए $250 से अधिक नहीं के जुर्माने के रूप में निर्धारित करता है। स्रोत: NH RSA 266:16 Penalty for Exceeding Permitted Size."},"20":{"q":"न्यू हैम्पशायर CDL नियमों के तहत, 26,001 pounds या अधिक के कुल संयोजन भार रेटिंग (GCWR) वाले वाहनों के संयोजन को चलाने के लिए किस लाइसेंस वर्ग की आवश्यकता होती है, बशर्ते जिस इकाई को खींचा जा रहा है उसका GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"न्यू हैम्पशायर Class A CDL को वाहनों के किसी भी ऐसे संयोजन के रूप में परिभाषित करता है जिसका GCWR 26,001 lbs या अधिक हो जहाँ खींची गई इकाई का GVWR 10,000 lbs से अधिक हो। स्रोत: NH DMV License Classifications, Restrictions and Endorsements page; NH Commercial Driver's Manual."},"21":{"q":"न्यू हैम्पशायर में, कौन सा CDL वर्ग 26,001 pounds या अधिक के GVWR वाले किसी भी एकल वाहन को, या ऐसे वाहन को जो 10,000 pounds GVWR से अधिक न होने वाली इकाई को खींच रहा हो, कवर करता है?","options":["Class A","Class B","Class C","Class M"],"explanation":"NH Class B CDL को 26,001 lbs या अधिक के GVWR वाले एकल वाहन के रूप में, या ऐसे वाहन के रूप में परिभाषित करता है जो 10,000 lbs GVWR से अधिक न होने वाली इकाई को खींच रहा हो। स्रोत: NH DMV License Classifications page; NH Commercial Driver's Manual."},"22":{"q":"एक न्यू हैम्पशायर चालक 26,001 lbs से कम के एकल वाहन को चलाता है जो चालक सहित 18 यात्रियों को ले जाने के लिए डिज़ाइन किया गया है। इसके लिए किस CDL वर्ग की आवश्यकता होती है?","options":["Class A","Class B","Class C","किसी CDL की आवश्यकता नहीं है"],"explanation":"NH Class C CDL को ऐसे वाहन के रूप में परिभाषित करता है जो Class A या B को पूरा नहीं करता और जो 16 या अधिक यात्रियों (चालक सहित) को ले जाता है, खतरनाक सामग्री के लिए प्लेकार्ड किया गया है, या एक टैंक वाहन है। एक 18-यात्री वाहन Class C के अंतर्गत आता है। स्रोत: NH DMV License Classifications page."},"23":{"q":"INTRASTATE (केवल न्यू हैम्पशायर के भीतर) संचालन तक सीमित न्यू हैम्पशायर CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["16 वर्ष","18 वर्ष","21 वर्ष","25 वर्ष"],"explanation":"न्यू हैम्पशायर में आपको इंट्रास्टेट (NH के भीतर) वाणिज्यिक मोटर वाहन चलाने के लिए कम से कम 18 वर्ष का होना चाहिए। स्रोत: NH DMV Commercial Driver Licenses page; NH Commercial Driver's Manual."},"24":{"q":"INTERSTATE (राज्य की सीमाओं के पार) वाणिज्यिक ड्राइविंग के लिए मान्य न्यू हैम्पशायर CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","21 वर्ष","23 वर्ष"],"explanation":"न्यू हैम्पशायर (संघीय मानक का पालन करते हुए) चालकों को इंटरस्टेट वाणिज्य में वाणिज्यिक मोटर वाहन चलाने के लिए कम से कम 21 वर्ष का होने की आवश्यकता रखता है। 18-20 वर्ष के चालक इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: NH DMV Commercial Driver Licenses page."},"25":{"q":"न्यू हैम्पशायर और संघीय नियमों के तहत, CDL स्किल्स (रोड) टेस्ट देने की अनुमति मिलने से पहले एक आवेदक को कितने समय तक Commercial Learner Permit (CLP) रखना आवश्यक है?","options":["7 days","10 days","14 days","30 days"],"explanation":"एक आवेदक को CDL स्किल्स टेस्ट देने से पहले कम से कम 14 days तक CLP रखना आवश्यक है। यह NH द्वारा लागू एक संघीय आवश्यकता है। स्रोत: NH DMV Commercial Driver Learner Permit page; 49 CFR 383.25."},"26":{"q":"जब कोई न्यू हैम्पशायर Commercial Driver Learner Permit धारक एक वाणिज्यिक मोटर वाहन चलाता है, तो उसके साथ किसे होना चाहिए?","options":["18 वर्ष या उससे अधिक का कोई भी लाइसेंस प्राप्त चालक","25 वर्ष या उससे अधिक का व्यक्ति जो उस वाहन प्रकार के लिए मान्य CDL रखता हो, जो परमिट धारक के ठीक बगल में बैठा हो","कोई भी CDL धारक जो वाहन में कहीं भी बैठा हो","केवल एक New Hampshire DMV परीक्षक"],"explanation":"NH के लिए आवश्यक है कि CLP धारक के साथ 25 वर्ष या उससे अधिक आयु का व्यक्ति हो जो चलाए जा रहे वाहन के प्रकार के लिए मान्य CDL रखता हो और जो परमिट धारक के ठीक बगल वाली सीट पर बैठा हो। स्रोत: NH DMV Commercial Driver Learner Permit page."},"27":{"q":"प्लेकार्डिंग की आवश्यकता वाली मात्रा में खतरनाक सामग्री का परिवहन करने के लिए न्यू हैम्पशायर CDL पर कौन सा एंडोर्समेंट कोड आवश्यक है?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"explanation":"राज्य या संघीय विनियमों के तहत प्लेकार्ड किए जाने वाली खतरनाक सामग्री का परिवहन करने वाले किसी भी वाणिज्यिक वाहन को चलाने के लिए H (HazMat) एंडोर्समेंट आवश्यक है। स्रोत: NH DMV HazMat Endorsement page."},"28":{"q":"किसी न्यू हैम्पशायर चालक को HazMat (H) एंडोर्समेंट जारी किए जाने से पहले, संघीय रूप से कौन सी अतिरिक्त जाँच आवश्यक है?","options":["एक TSA सुरक्षा खतरा मूल्यांकन (फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच)","एक FBI पॉलीग्राफ परीक्षा","एक New Hampshire State Police साक्षात्कार","केवल एक DOT ड्रग टेस्ट"],"explanation":"H एंडोर्समेंट के आवेदकों को HazMat ज्ञान परीक्षा के अतिरिक्त एक Transportation Security Administration (TSA) सुरक्षा खतरा मूल्यांकन पास करना होगा, जिसमें फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच शामिल है। स्रोत: NH DMV HazMat Endorsement page; 49 CFR 1572."},"29":{"q":"न्यू हैम्पशायर CDL पर, थोक में तरल पदार्थ या गैस ले जाने के लिए उपयोग किए जाने वाले टैंक वाहन को चलाने के लिए कौन सा एंडोर्समेंट आवश्यक है?","options":["H endorsement","T endorsement","N endorsement","P endorsement"],"explanation":"थोक में तरल पदार्थ या गैस के परिवहन के लिए डिज़ाइन किए गए टैंक वाहन को चलाने के लिए N (Tank Vehicle) एंडोर्समेंट आवश्यक है। स्रोत: NH DMV License Classifications, Restrictions and Endorsements page."},"30":{"q":"डबल या ट्रिपल ट्रेलर खींचने के लिए कौन सा न्यू हैम्पशायर CDL एंडोर्समेंट आवश्यक है?","options":["T endorsement","N endorsement","D endorsement","X endorsement"],"explanation":"डबल या ट्रिपल ट्रेलर खींचने के लिए T एंडोर्समेंट (Doubles/Triples) आवश्यक है। यह एक ज्ञान परीक्षा पास करके प्राप्त किया जाता है; इसके लिए कोई अलग स्किल्स टेस्ट आवश्यक नहीं है। स्रोत: NH DMV License Classifications page; NH Commercial Driver's Manual."},"31":{"q":"चालक सहित 16 या अधिक यात्रियों के परिवहन के लिए डिज़ाइन किए गए वाणिज्यिक वाहन को चलाने के लिए न्यू हैम्पशायर किस एंडोर्समेंट की आवश्यकता रखता है?","options":["S endorsement","P endorsement","N endorsement","T endorsement"],"explanation":"चालक सहित 16 या अधिक यात्रियों के परिवहन के लिए डिज़ाइन किए गए किसी भी वाणिज्यिक वाहन को चलाने के लिए P (Passenger) एंडोर्समेंट आवश्यक है। स्रोत: NH DMV Commercial Driver Licenses page."},"32":{"q":"न्यू हैम्पशायर School Bus (S) एंडोर्समेंट प्राप्त करने के लिए, आवेदक को आम तौर पर और किसकी आवश्यकता होती है?","options":["एक HazMat (H) एंडोर्समेंट","एक Tank (N) एंडोर्समेंट","एक Passenger (P) एंडोर्समेंट","एक Doubles/Triples (T) एंडोर्समेंट"],"explanation":"एक स्कूल बस 16 या अधिक यात्रियों को ले जाती है, इसलिए NH के लिए School Bus (S) ज्ञान परीक्षा और एक यात्री-वाहन रोड स्किल्स टेस्ट पास करने के अतिरिक्त Passenger (P) एंडोर्समेंट की आवश्यकता होती है। स्रोत: NH DMV School Bus Drivers page."},"33":{"q":"Commercial Learner Permit के लिए योग्य होने हेतु न्यू हैम्पशायर CDL सामान्य ज्ञान लिखित परीक्षा पर न्यूनतम कितना उत्तीर्ण अंक आवश्यक है?","options":["70%","75%","80%","90%"],"explanation":"न्यू हैम्पशायर सामान्य ज्ञान परीक्षा सहित CDL ज्ञान परीक्षाओं पर 80% या उससे अधिक के अंक की आवश्यकता रखता है। स्रोत: NH DMV Commercial Driver Learner Permit page; NH Commercial Driver's Manual."},"34":{"q":"कुछ न्यू हैम्पशायर CDL स्किल्स/ज्ञान परीक्षाओं से पहले ली जाने वाली Entry-Level Driver Training (ELDT) किसके माध्यम से पूरी की जानी चाहिए?","options":["किसी भी न्यू हैम्पशायर सामुदायिक कॉलेज","FMCSA Training Provider Registry (TPR) पर सूचीबद्ध एक प्रदाता","New Hampshire DMV का अपना प्रशिक्षण प्रभाग","किसी भी नियोक्ता-संचालित कार्यक्रम, बिना पंजीकरण के"],"explanation":"ELDT को FMCSA Training Provider Registry (TPR) पर सूचीबद्ध एक प्रदाता के माध्यम से पूरा किया जाना चाहिए; प्रदाता स्वयं-प्रमाणित करता है और पूर्णता रिकॉर्ड FMCSA को प्रस्तुत करता है। स्रोत: FMCSA ELDT / Training Provider Registry; NH DMV CDL pages."},"35":{"q":"निम्नलिखित में से किसके लिए किसी न्यू हैम्पशायर आवेदक द्वारा संबंधित परीक्षा देने से पहले ELDT (Entry-Level Driver Training) आवश्यक है?","options":["एक Doubles/Triples (T) एंडोर्समेंट जोड़ना","एक Tank (N) एंडोर्समेंट जोड़ना","पहली बार Class A CDL प्राप्त करना","बिना वर्ग परिवर्तन के मौजूदा Class B CDL का नवीनीकरण"],"explanation":"संघीय ELDT नियम (7 फरवरी, 2022 से प्रभावी) पहली बार Class A या B CDL प्राप्त करने, Class B को Class A में अपग्रेड करने, और पहली बार H, P, या S एंडोर्समेंट प्राप्त करने पर लागू होते हैं। N और T एंडोर्समेंट और साधारण नवीनीकरण के लिए ELDT की आवश्यकता नहीं है। स्रोत: FMCSA ELDT regulations; NH DMV CDL pages."},"36":{"q":"न्यू हैम्पशायर CDL के लिए आवेदन करते समय, कौन सी स्व-प्रमाणन श्रेणी ऐसे चालक को इंगित करती है जो राज्य की सीमाओं के पार संचालन करता है और जिसे संघीय DOT मेडिकल प्रमाणपत्र आवश्यकता को पूरा करना होगा?","options":["Interstate non-excepted","Intrastate excepted","Interstate excepted","Intrastate non-excepted"],"explanation":"NH चार संघीय स्व-प्रमाणन श्रेणियों का उपयोग करता है। 'Interstate non-excepted' उन चालकों को कवर करता है जो राज्य की सीमाओं के पार संचालन करते हैं और जिन्हें फाइल पर एक मान्य DOT मेडिकल प्रमाणपत्र रखना होगा। स्रोत: NH DMV CDL Medical Card Update page; 49 CFR 383.71."},"37":{"q":"न्यू हैम्पशायर CDL या Commercial Learner Permit के लिए आवेदन करने हेतु, एक आवेदक को आम तौर पर दस्तावेजों के किस संयोजन का प्रमाण प्रस्तुत करना होगा?","options":["केवल पहचान","केवल पहचान और Social Security Number","पहचान, Social Security Number, और New Hampshire निवास/वैध उपस्थिति","केवल एक पासपोर्ट, जो सभी आवश्यकताओं को कवर करता है"],"explanation":"न्यू हैम्पशायर के लिए आवेदकों को पहचान साबित करनी होगी, Social Security Number दिखाने वाला एक दस्तावेज प्रदान करना होगा, और NH निवास तथा वैध उपस्थिति स्थापित करने वाले दस्तावेज प्रदान करने होंगे। स्रोत: NH DMV Required Documents / Commercial Driver Learner Permit pages."},"38":{"q":"नवीनीकरण आवश्यक होने से पहले एक न्यू हैम्पशायर Commercial Driver Learner Permit (CLP) कितने समय तक मान्य रहता है?","options":["30 days","60 days","180 days","365 days"],"explanation":"एक न्यू हैम्पशायर CLP 180 days के लिए मान्य है और इसे एक बार नवीनीकृत किया जा सकता है, बशर्ते आवश्यक ज्ञान परीक्षाएँ एक-वर्ष की अवधि के भीतर पास की गई हों। यह संघीय CLP वैधता मानक का पालन करता है। स्रोत: NH DMV Commercial Driver Learner Permit page; 49 CFR 383.25."},"39":{"q":"एक 19 वर्षीय न्यू हैम्पशायर निवासी CDL चाहता है। 21 वर्ष का होने तक वे किस विशेषाधिकार के लिए पात्र नहीं हैं?","options":["Class B CDL रखना","न्यू हैम्पशायर के भीतर इंट्रास्टेट संचालन करना","एक HazMat (H) एंडोर्समेंट प्राप्त करना","एक Tank (N) एंडोर्समेंट प्राप्त करना"],"explanation":"21 वर्ष से कम आयु के न्यू हैम्पशायर आवेदक इंट्रास्टेट संचालन तक सीमित हैं और HazMat (H) या इंटरस्टेट-के-लिए-Passenger विशेषाधिकार प्राप्त नहीं कर सकते; विशेष रूप से H एंडोर्समेंट के लिए आवेदक का कम से कम 21 वर्ष का होना आवश्यक है। स्रोत: NH DMV Commercial Driver Licenses / HazMat Endorsement pages."},"40":{"q":"न्यू हैम्पशायर में, अधिकतम रक्त अल्कोहल सांद्रता (BAC) कितनी होती है जिस पर कोई व्यक्ति कानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) चला सकता है?","options":["0.04","0.08","0.02","0.10"],"explanation":"न्यू हैम्पशायर एक CMV चलाने के लिए BAC सीमा को 0.04 निर्धारित करता है, जो गैर-वाणिज्यिक चालकों के लिए 0.08 सीमा का आधा है। स्रोत: NH CDL Manual (alcohol/drugs section); RSA 265-A:2."},"41":{"q":"न्यू हैम्पशायर की सड़कों पर एक वाणिज्यिक मोटर वाहन चलाने से, एक CDL धारक को अल्कोहल या ड्रग्स के रासायनिक परीक्षण के संबंध में कानूनी रूप से क्या कर चुका माना जाता है?","options":["कानूनी रूप से अनुरोध किए जाने पर परीक्षण कराने के लिए निहित सहमति दे चुका","किसी भी भविष्य के CDL के अधिकार का त्याग कर चुका","एक निश्चित $500 परीक्षण शुल्क का भुगतान करने के लिए सहमत","केवल एक श्वास परीक्षण के लिए सहमत लेकिन रक्त के लिए नहीं"],"explanation":"न्यू हैम्पशायर के निहित-सहमति कानून के तहत, राज्य में वाहन चलाने वाले किसी भी व्यक्ति को कानूनी रूप से अनुरोध किए जाने पर अल्कोहल सांद्रता निर्धारित करने हेतु रासायनिक परीक्षण के लिए सहमति दे चुका माना जाता है। स्रोत: RSA 265-A:4; NH CDL Manual."},"42":{"q":"किसी पहले बड़े अपराध (जैसे CMV में DUI) के लिए, न्यू हैम्पशायर में न्यूनतम CDL अयोग्यता अवधि क्या है?","options":["1 year","60 days","6 months","3 years"],"explanation":"न्यू हैम्पशायर में एक पहला बड़ा अपराध किसी चालक को एक CMV चलाने से एक वर्ष से कम नहीं की अवधि के लिए अयोग्य ठहराता है। स्रोत: RSA 263:94; 49 CFR 383.51; NH CDL Manual."},"43":{"q":"यदि कोई न्यू हैम्पशायर चालक खतरनाक सामग्री के लिए प्लेकार्ड किए गए CMV को चलाते समय पहला बड़ा अपराध करता है, तो न्यूनतम अयोग्यता कितनी होती है:","options":["3 years","1 year","120 days","आजीवन"],"explanation":"प्लेकार्ड की गई खतरनाक सामग्री का परिवहन करते समय किया गया पहला बड़ा अपराध न्यूनतम अयोग्यता को एक वर्ष से बढ़ाकर तीन वर्ष कर देता है। स्रोत: RSA 263:94; 49 CFR 383.51."},"44":{"q":"एक अलग घटना से उत्पन्न दूसरे बड़े अपराध (जैसे, CMV में दूसरा DUI) के लिए न्यू हैम्पशायर में अयोग्यता अवधि क्या है?","options":["आजीवन","10 years","5 years","3 years"],"explanation":"एक अलग घटना से किसी बड़े अपराध के लिए दूसरी दोषसिद्धि के परिणामस्वरूप एक CMV चलाने से आजीवन अयोग्यता होती है। स्रोत: RSA 263:94; 49 CFR 383.51."},"45":{"q":"एक न्यू हैम्पशायर CDL धारक एक CMV चलाते समय रासायनिक परीक्षण कराने से इनकार करता है। पहले इनकार के लिए, न्यूनतम CDL अयोग्यता कितनी होती है:","options":["1 year","90 days","6 months","30 days"],"explanation":"कानूनी रूप से अनुरोध किए गए रासायनिक परीक्षण से इनकार करना एक बड़े अपराध के रूप में माना जाता है; पहले इनकार के साथ न्यूनतम एक-वर्ष की CDL अयोग्यता होती है (यदि हैज़मैट के लिए प्लेकार्ड किया गया हो तो तीन वर्ष)। स्रोत: RSA 263:94; RSA 265-A:4."},"46":{"q":"यदि कोई न्यू हैम्पशायर CDL धारक दूसरी बार (एक अलग घटना) रासायनिक परीक्षण से इनकार करता है, तो CDL अयोग्यता कितनी होती है:","options":["आजीवन","5 years","2 years","1 year"],"explanation":"रासायनिक परीक्षण से इनकार करने का दूसरा उदाहरण, किसी भी दूसरे बड़े अपराध की तरह, आजीवन CDL अयोग्यता में परिणत होता है। स्रोत: RSA 263:94; 49 CFR 383.51."},"47":{"q":"न्यू हैम्पशायर में, 3 वर्षों के भीतर अलग घटनाओं से उत्पन्न एक CMV में दो गंभीर यातायात उल्लंघनों के लिए दोषी ठहराए जाने के परिणामस्वरूप कम से कम कितनी CDL अयोग्यता होती है:","options":["60 days","30 days","120 days","1 year"],"explanation":"3-वर्ष की अवधि के भीतर दो गंभीर यातायात उल्लंघन किसी चालक को एक CMV चलाने से 60 days से कम नहीं की अवधि के लिए अयोग्य ठहराते हैं। स्रोत: RSA 263:94; 49 CFR 383.51."},"48":{"q":"3 वर्षों के भीतर अलग घटनाओं से एक CMV में तीन गंभीर यातायात उल्लंघनों के लिए दोषी ठहराए जाने के परिणामस्वरूप कम से कम कितनी न्यू हैम्पशायर CDL अयोग्यता होती है:","options":["120 days","60 days","90 days","1 year"],"explanation":"3-वर्ष की अवधि के भीतर तीन गंभीर यातायात उल्लंघन किसी चालक को एक CMV चलाने से 120 days से कम नहीं की अवधि के लिए अयोग्य ठहराते हैं। स्रोत: RSA 263:94; 49 CFR 383.51."},"49":{"q":"न्यू हैम्पशायर के CDL नियमों के तहत, निर्धारित सीमा से कितनी गति पर एक एकल गति उल्लंघन एक 'गंभीर यातायात उल्लंघन' बन जाता है?","options":["सीमा से 15 mph या अधिक","सीमा से 10 mph या अधिक","सीमा से 20 mph या अधिक","सीमा से 25 mph या अधिक"],"explanation":"निर्धारित सीमा से 15 mph या अधिक गति को न्यू हैम्पशायर में CDL प्रयोजनों के लिए एक गंभीर यातायात उल्लंघन के रूप में परिभाषित किया गया है। स्रोत: RSA 259:98-a; N.H. Admin. Code Saf-C 1809.02."},"50":{"q":"निम्नलिखित में से कौन सा एक न्यू हैम्पशायर CDL धारक के लिए एक 'गंभीर यातायात उल्लंघन' के रूप में वर्गीकृत किया गया है?","options":["बहुत पास से अनुसरण करना (टेलगेटिंग)","एक फायर लेन में पार्किंग करना","सीमा से 5 mph अधिक गाड़ी चलाना","एक समाप्त पंजीकरण स्टिकर"],"explanation":"बहुत पास से अनुसरण करना CDL धारकों के लिए सूचीबद्ध गंभीर यातायात उल्लंघनों में से एक है, साथ ही लापरवाह ड्राइविंग, अनियमित लेन परिवर्तन, और अत्यधिक गति। स्रोत: RSA 259:98-a; Saf-C 1809.02."},"51":{"q":"न्यू हैम्पशायर में एक CMV चलाते समय रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन की पहली दोषसिद्धि के लिए, न्यूनतम अयोग्यता कितनी होती है:","options":["60 days","30 days","120 days","1 year"],"explanation":"एक CMV में पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 60-day अयोग्यता के साथ आता है। स्रोत: 49 CFR 383.51 Table 3, न्यू हैम्पशायर द्वारा अपनाया गया; NH CDL Manual."},"52":{"q":"3 वर्षों के भीतर एक CMV में दूसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप कम से कम कितनी न्यू हैम्पशायर CDL अयोग्यता होती है:","options":["120 days","60 days","90 days","1 year"],"explanation":"3 वर्षों के भीतर दूसरा ग्रेड-क्रॉसिंग उल्लंघन न्यूनतम 120-day अयोग्यता के साथ आता है। स्रोत: 49 CFR 383.51 Table 3, न्यू हैम्पशायर द्वारा अपनाया गया।"},"53":{"q":"3 वर्षों के भीतर एक CMV में तीसरा या उसके बाद का रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप कम से कम कितनी न्यू हैम्पशायर CDL अयोग्यता होती है:","options":["1 year","120 days","180 days","60 days"],"explanation":"3 वर्षों के भीतर तीसरा या उसके बाद का ग्रेड-क्रॉसिंग उल्लंघन न्यूनतम 1 year की अयोग्यता के साथ आता है। स्रोत: 49 CFR 383.51 Table 3, न्यू हैम्पशायर द्वारा अपनाया गया।"},"54":{"q":"न्यू हैम्पशायर में, एक आउट-ऑफ-सर्विस (OOS) आदेश के तहत एक CMV चलाने का पहला उल्लंघन (गैर-हैज़मैट) के परिणामस्वरूप कितनी अयोग्यता होती है:","options":["180 days से कम नहीं और 1 year से अधिक नहीं","60 days से कम नहीं और 120 days से अधिक नहीं","30 days से कम नहीं और 90 days से अधिक नहीं","2 years से कम नहीं और 5 years से अधिक नहीं"],"explanation":"एक पहला आउट-ऑफ-सर्विस आदेश उल्लंघन चालक को 180 days से कम नहीं और 1 year से अधिक नहीं के लिए अयोग्य ठहराता है। स्रोत: 49 CFR 383.51 Table 4, न्यू हैम्पशायर द्वारा अपनाया गया; NH CDL Manual."},"55":{"q":"10 वर्षों के भीतर एक CMV में दूसरा आउट-ऑफ-सर्विस (OOS) आदेश उल्लंघन के परिणामस्वरूप कितनी न्यू हैम्पशायर अयोग्यता होती है:","options":["2 years से कम नहीं और 5 years से अधिक नहीं","180 days से कम नहीं और 1 year से अधिक नहीं","1 year से कम नहीं और 3 years से अधिक नहीं","आजीवन"],"explanation":"10 वर्षों के भीतर दूसरा OOS आदेश उल्लंघन 2 years से कम नहीं और 5 years से अधिक नहीं की अयोग्यता के साथ आता है। स्रोत: 49 CFR 383.51 Table 4, न्यू हैम्पशायर द्वारा अपनाया गया।"},"56":{"q":"प्लेकार्ड की गई खतरनाक सामग्री ढोने वाला या 16+ यात्रियों के लिए डिज़ाइन किए गए वाहन को चलाने वाला एक चालक न्यू हैम्पशायर में पहला आउट-ऑफ-सर्विस आदेश उल्लंघन करता है। अयोग्यता कितनी होती है:","options":["180 days से कम नहीं और 2 years से अधिक नहीं","180 days से कम नहीं और 1 year से अधिक नहीं","60 days से कम नहीं और 120 days से अधिक नहीं","3 years से कम नहीं और 5 years से अधिक नहीं"],"explanation":"प्लेकार्ड की गई हैज़मैट का परिवहन करते समय या 16+ यात्री वाहन में पहला OOS उल्लंघन 180 days से कम नहीं और 2 years से अधिक नहीं की बढ़ी हुई अवधि के साथ आता है। स्रोत: 49 CFR 383.51 Table 4, न्यू हैम्पशायर द्वारा अपनाया गया।"},"57":{"q":"न्यू हैम्पशायर के हैंड्स-फ्री कानून के तहत, गाड़ी चलाते समय एक हैंडहेल्ड मोबाइल इलेक्ट्रॉनिक डिवाइस का उपयोग करने के पहले अपराध के लिए जुर्माना कितना है?","options":["$100","$50","$250","$500"],"explanation":"न्यू हैम्पशायर का हैंड्स-फ्री कानून पहले अपराध पर $100, दूसरे पर $250, और 24 months के भीतर किसी भी बाद के अपराध पर $500 का जुर्माना लगाता है। CMV संचालकों सहित सभी चालकों के लिए हैंडहेल्ड उपयोग प्रतिबंधित है। स्रोत: RSA 265:79-c."},"58":{"q":"न्यू हैम्पशायर के हैंड्स-फ्री कानून (RSA 265:79-c) के तहत, गाड़ी चलाते समय एक हैंडहेल्ड इलेक्ट्रॉनिक डिवाइस का उपयोग करने के दूसरे अपराध के लिए जुर्माना कितना है?","options":["$250","$100","$500","$150"],"explanation":"न्यू हैम्पशायर के हैंड्स-फ्री कानून के दूसरे अपराध पर $250 का जुर्माना लगाया जाता है (पहला अपराध $100 है और 24 months के भीतर बाद का अपराध $500 है)। स्रोत: RSA 265:79-c."},"59":{"q":"न्यू हैम्पशायर में पहले और बाद के CDL अयोग्यता अपराधों की गणना के लिए, दोषसिद्धियों की गिनती किस नियम के आधार पर की जाती है?","options":["एक अलग घटना से प्रत्येक दोषसिद्धि गिनी जाती है, चाहे वह एक CMV में की गई हो या एक गैर-CMV में","केवल एक CMV चलाते समय की गई दोषसिद्धियाँ गिनी जाती हैं","केवल पिछले 12 महीनों के भीतर की दोषसिद्धियाँ गिनी जाती हैं","केवल जेल की सजा वाली दोषसिद्धियाँ गिनी जाती हैं"],"explanation":"पहले और बाद के अयोग्यता उल्लंघनों को निर्धारित करने के लिए, एक अलग घटना से प्रत्येक दोषसिद्धि गिनी जाती है, चाहे अपराध एक वाणिज्यिक या गैर-वाणिज्यिक वाहन में हुआ हो। स्रोत: RSA 263:94; 49 CFR 383.51."},"60":{"q":"न्यू हैम्पशायर के मूव ओवर कानून के तहत, जब कोई CDL चालक नीली, लाल या एम्बर चेतावनी लाइट दिखा रहे किसी रुके हुए वाहन के पास से शोल्डर पर गुजर रहा हो, तो उसे क्या करना चाहिए?","options":["गति कम करें और, यदि व्यावहारिक हो, तो उस वाहन को पर्याप्त दूरी देने के लिए दूसरी लेन में चले जाएं","गति बनाए रखें लेकिन गुजरते समय लगातार हॉर्न बजाते रहें","वाहन के हटने तक यात्रा लेन में पूरी तरह रुक जाएं","निर्धारित गति से चलते रहें क्योंकि यह कानून केवल पुलिस क्रूज़र पर लागू होता है"],"explanation":"न्यू हैम्पशायर का मूव ओवर कानून (RSA 265:37-a) चालक से यह अपेक्षा करता है कि वह गति कम बनाए रखे और, यदि व्यावहारिक हो, तो सार्वजनिक सुरक्षा कर्मियों तथा नीली, लाल या एम्बर आपातकालीन या चेतावनी लाइट दिखा रहे किसी भी रुके हुए वाहन को पर्याप्त दूरी दे, और सुरक्षित होने पर अवरुद्ध लेन से बाहर चला जाए। स्रोत: NH RSA 265:37-a; NH CDL Manual।"},"61":{"q":"न्यू हैम्पशायर में, रेलमार्ग की पटरियों को पार करने से पहले प्लेकार्ड लगे खतरनाक-पदार्थ वाहन या बच्चों को ले जा रही स्कूल बस को निकटतम रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["15 feet से कम नहीं और 50 feet से अधिक नहीं","5 feet से कम नहीं और 25 feet से अधिक नहीं","25 feet से कम नहीं और 75 feet से अधिक नहीं","50 feet से कम नहीं और 100 feet से अधिक नहीं"],"explanation":"RSA 265:50 के अनुसार यात्रियों को ले जा रही बसों, बच्चों को ले जा रही स्कूल बसों, और विस्फोटक/खतरनाक पदार्थ ले जा रहे वाहनों के चालकों को निकटतम रेल से 50 feet के भीतर लेकिन 15 feet से कम नहीं रुकना चाहिए, फिर आगे बढ़ने से पहले देखना और सुनना चाहिए। स्रोत: NH RSA 265:50; NH CDL Manual।"},"62":{"q":"न्यू हैम्पशायर की एक दो-लेन सड़क पर, अपनी लाल लाइट चमका रही रुकी हुई स्कूल बस से मिलते या उसे ओवरटेक करते समय चालक को वाहन को बस से कम से कम कितनी दूर रोकना चाहिए?","options":["कम से कम 25 feet दूर","कम से कम 10 feet दूर","कम से कम 50 feet दूर","कम से कम 100 feet दूर"],"explanation":"RSA 265:54 के अनुसार बच्चों को चढ़ा या उतार रही रुकी हुई स्कूल बस से मिलते या उसे ओवरटेक करते समय चालक को बस से कम से कम 25 feet दूर रुकना चाहिए और तब तक रुके रहना चाहिए जब तक बस फिर से चलना शुरू न कर दे या लाइट चमकना बंद न कर दें। स्रोत: NH RSA 265:54।"},"63":{"q":"न्यू हैम्पशायर के अलग-अलग मार्गों वाले विभाजित राजमार्ग पर, किसी CDL चालक को बच्चों को चढ़ा रही स्कूल बस के लिए कब रुकने की आवश्यकता नहीं होती?","options":["जब बस विभाजित राजमार्ग के दूसरे आधे हिस्से पर विपरीत दिशा में चल रही हो","कभी नहीं — चमकती लाल लाइट वाली स्कूल बस के लिए हमेशा रुकना आवश्यक है","केवल तब जब चालक खाली स्ट्रेट ट्रक चला रहा हो","जब भी चालक 45 mph से तेज चल रहा हो"],"explanation":"RSA 265:54 यह प्रावधान करता है कि अलग-अलग मार्गों वाले विभाजित राजमार्ग पर चालक को उस स्कूल बस से मिलते या उसे पार करते समय रुकने की आवश्यकता नहीं होती जो विभाजित राजमार्ग के दूसरे आधे हिस्से पर विपरीत दिशा में चल रही हो। अविभाजित सड़क पर, सभी दिशाओं को रुकना चाहिए। स्रोत: NH RSA 265:54।"},"64":{"q":"न्यू हैम्पशायर के उन इंटरस्टेट राजमार्गों और टर्नपाइकों पर सामान्य अधिकतम गति सीमा क्या है जो चार-लेन विभाजित राजमार्ग हैं (उच्च-सीमा वाले I-93 खंड को छोड़कर)?","options":["65 mph","55 mph","70 mph","75 mph"],"explanation":"RSA 265:60 इंटरस्टेट प्रणाली तथा मध्य और पूर्वी न्यू हैम्पशायर टर्नपाइकों पर, जहां वे चार-लेन विभाजित राजमार्ग हैं, अधिकतम 65 mph निर्धारित करता है। न्यू हैम्पशायर ट्रकों पर वही निर्धारित सीमाएं लागू करता है जो कारों पर। स्रोत: NH RSA 265:60।"},"65":{"q":"न्यू हैम्पशायर के किस मार्ग पर निर्धारित गति सीमा 70 mph है, जो राज्य में सबसे अधिक है?","options":["मील मार्कर 45 से वर्मोंट सीमा तक I-93","I-95 (Blue Star Turnpike) की पूरी लंबाई","Portsmouth से Milton तक Spaulding Turnpike","Concord से वर्मोंट सीमा तक I-89"],"explanation":"RSA 265:60 मील मार्कर 45 से वर्मोंट सीमा तक I-93 पर गति सीमा 70 mph निर्धारित करता है। यह न्यू हैम्पशायर में सबसे अधिक निर्धारित सीमा है और यह वाणिज्यिक वाहनों पर भी लागू होती है। स्रोत: NH RSA 265:60।"},"66":{"q":"क्या न्यू हैम्पशायर अपने इंटरस्टेट पर ट्रकों के लिए यात्री कारों की तुलना में कम गति सीमा निर्धारित करता है?","options":["नहीं — ट्रकों को अन्य सभी वाहनों के समान ही निर्धारित सीमा का पालन करना चाहिए","हां — जहां कारें 65 mph तक जा सकती हैं वहां ट्रक 55 mph तक सीमित हैं","हां — ट्रक पूरे राज्य में 60 mph तक सीमित हैं","हां — ट्रक सभी विभाजित राजमार्गों पर 45 mph तक सीमित हैं"],"explanation":"न्यू हैम्पशायर का गति अधिनियम (RSA 265:60) अधिकतम सीमाएं निर्धारित करता है जो सभी वाहनों पर लागू होती हैं और यह कोई अलग, कम ट्रक गति सीमा स्थापित नहीं करता; वाणिज्यिक वाहन कारों के समान ही निर्धारित सीमाओं का पालन करते हैं। स्रोत: NH RSA 265:60।"},"67":{"q":"न्यू हैम्पशायर कानून के तहत, बहु-लेन मार्ग पर धीमे चल रहे ट्रक से लेन की स्थिति के संबंध में क्या अपेक्षित है?","options":["उसे दाहिनी ओर की लेन में रहना चाहिए और बाईं लेन को इस तरह लगातार नहीं घेरना चाहिए कि यातायात बाधित हो","जब तक वह संकेत देता रहे, वह बाईं लेन में अनिश्चित काल तक रह सकता है","किसी भी तीन-लेन राजमार्ग पर उसे केवल बीच वाली लेन का उपयोग करना चाहिए","अपने आकार के कारण वह दाएं रहने के नियमों से छूट प्राप्त है"],"explanation":"RSA 265:16 के अनुसार सामान्य यातायात से धीमे चल रहे वाहन को दाहिनी ओर की लेन में रहना चाहिए और बहु-लेन मार्ग की बाईं लेन में लगातार चलने पर रोक है जब यह यातायात के प्रवाह को बाधित करता है। स्रोत: NH RSA 265:16।"},"68":{"q":"न्यू हैम्पशायर के अनुसार 10,000 pounds से अधिक के हर ट्रक या बस को राजमार्ग पर रुके होने पर उपयोग के लिए किस प्रकार के आपातकालीन चेतावनी उपकरण रखने आवश्यक हैं?","options":["तीन द्विदिशात्मक परावर्तक चेतावनी उपकरण (परावर्तक त्रिकोण)","दो जलते हुए तरल-ईंधन लालटेन","एक बैटरी-चालित स्ट्रोब बीकन","खंभों पर चार लाल कपड़े के झंडे"],"explanation":"RSA 265:113 के अनुसार 10,000 pounds GVW से अधिक के हर ट्रक, बस या ट्रक-ट्रैक्टर को निदेशक द्वारा अनुमोदित तीन द्विदिशात्मक परावर्तक चेतावनी उपकरण रखने चाहिए, जो संघीय मोटर वाहक सुरक्षा विनियमों के अनुरूप हों। स्रोत: NH RSA 265:113; NH CDL Manual।"},"69":{"q":"जब न्यू हैम्पशायर का 10,000 pounds से अधिक का कोई वाणिज्यिक वाहन दो-लेन राजमार्ग पर रुका हो, तो तीनों चेतावनी उपकरण सामान्यतः कहां रखे जाने चाहिए?","options":["वाहन के लगभग 10 feet पीछे, 100 feet पीछे की ओर, और 100 feet आगे की ओर","तीनों रियर बंपर के 10 feet के भीतर","एक 25 feet आगे और दो 25 feet पीछे","200 feet आगे, 200 feet पीछे, और एक छत पर"],"explanation":"RSA 265:113 के तहत, सामान्य दो-तरफा सड़क पर उपकरण वाहन से यातायात वाली ओर लगभग 10 feet, 100 feet पीछे की ओर, और 100 feet आगे की ओर रखे जाते हैं। विभाजित या एक-तरफा सड़क पर आने वाले यातायात की ओर दूरी 10, 100, और 200 feet होती है। स्रोत: NH RSA 265:113; NH CDL Manual।"},"70":{"q":"न्यू हैम्पशायर में रेलमार्ग क्रॉसिंग पर रुकने के बाद, पटरियों को वास्तव में पार करते समय कानून बस या हैज़मैट चालक से क्या अपेक्षा करता है?","options":["इतने नीचे गियर में पार करें कि पटरियों पर रहते हुए गियर बदलने की आवश्यकता न पड़े","जोर से एक्सेलरेट करें और पटरियां सबसे तेजी से पार करने के लिए जल्दी से अपशिफ्ट करें","न्यूट्रल में शिफ्ट करें और पटरियों के पार कोस्ट करें","क्रॉसिंग के मध्य बिंदु पर थोड़ी देर के लिए पार्किंग ब्रेक लगाएं"],"explanation":"RSA 265:50 निर्देश देता है कि रुकने के बाद और जब आगे बढ़ना सुरक्षित हो, चालक को ऐसे गियर में पार करना चाहिए कि पार करते समय गियर बदलने की कोई आवश्यकता न हो, और पटरियों पर रहते हुए गियर नहीं बदलने चाहिए। स्रोत: NH RSA 265:50।"},"71":{"q":"मूव ओवर कानून (RSA 265:37-a) का पालन न करने के पहले अपराध के लिए न्यू हैम्पशायर की दंड संरचना क्या है?","options":["पहले अपराध के लिए $75 साथ ही penalty assessment","पहले अपराध के लिए $250 साथ ही 30-दिन का लाइसेंस निलंबन","$500 साथ ही अनिवार्य CDL अयोग्यता","पहले अपराध के लिए केवल एक लिखित चेतावनी"],"explanation":"RSA 265:37-a के तहत, न्यू हैम्पशायर के मूव ओवर कानून के पहले उल्लंघन पर $75 साथ ही penalty assessment का जुर्माना लगता है, जो 12 महीनों के भीतर बाद के अपराध के लिए बढ़कर $250 साथ ही assessment हो जाता है। स्रोत: NH RSA 265:37-a।"},"72":{"q":"बिना ओवरसाइज़ परमिट के, न्यू हैम्पशायर के राजमार्गों पर किसी वाणिज्यिक वाहन की अधिकतम कानूनी चौड़ाई क्या है?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 6 inches"],"explanation":"न्यू हैम्पशायर 8 feet 6 inches (102 inches) की संघीय कानूनी चौड़ाई सीमा का पालन करता है; इससे चौड़ी किसी भी चीज़ के लिए NHDOT से ओवरसाइज़ परमिट आवश्यक है। स्रोत: NH DOT oversize/overweight permit rules; NH State Police Troop G motor carrier guidance।"},"73":{"q":"बिना ओवरवेट परमिट के, न्यू हैम्पशायर के राजमार्गों पर किसी वाणिज्यिक वाहन का अधिकतम कानूनी सकल वाहन भार क्या है?","options":["80,000 pounds","73,280 pounds","90,000 pounds","100,000 pounds"],"explanation":"न्यू हैम्पशायर की कानूनी अधिकतम सकल वाहन भार सीमा इंटरस्टेट और अन्य दोनों राजमार्गों पर 80,000 pounds है; इससे अधिक होने पर NHDOT के माध्यम से ओवरवेट परमिट/प्रमाणन आवश्यक है। स्रोत: NH DOT oversize/overweight permit rules; NH State Police Troop G।"},"74":{"q":"बिना परमिट के, न्यू हैम्पशायर की सड़कों पर किसी वाणिज्यिक वाहन की अधिकतम कानूनी ऊंचाई क्या है?","options":["13 feet 6 inches","12 feet 6 inches","14 feet 0 inches","13 feet 0 inches"],"explanation":"न्यू हैम्पशायर की कानूनी अधिकतम वाहन ऊंचाई सभी प्रकार की सड़कों पर 13 feet 6 inches है; इससे ऊंचे लोड के लिए NHDOT से ओवरसाइज़ परमिट आवश्यक है। स्रोत: NH DOT oversize/overweight permit rules।"},"75":{"q":"न्यू हैम्पशायर में I-93 के Franconia Notch Parkway हिस्से पर, बाकी इंटरस्टेट की तुलना में वाणिज्यिक चालकों के लिए क्या विशिष्ट है?","options":["यह प्रत्येक दिशा में एक ही लेन तक सिमट जाता है और इसमें 45 mph की कम सीमा होती है","इसमें प्रत्येक दिशा में केवल ट्रकों के लिए एक समर्पित एक्सप्रेस लेन है","यह आर-पार जाने वाले ट्रकों के लिए 80 mph की सीमा की अनुमति देता है","यह दिन के उजाले के घंटों में सभी यात्री कारों पर प्रतिबंध लगाता है"],"explanation":"I-93 का Franconia Notch Parkway खंड इंटरस्टेट मानकों के एक विशेष अपवाद के तहत बनाया गया था और प्रत्येक दिशा में एक ही लेन तक सिमट जाता है जहां निर्धारित सीमा 45 mph है, जिसके लिए ढलान पर CMV से अतिरिक्त सावधानी की आवश्यकता होती है। स्रोत: NH DOT; NH RSA 265:60 reduced-zone authority।"},"76":{"q":"न्यू हैम्पशायर में कानूनी सीमाओं से अधिक वाले वाणिज्यिक वाहनों के लिए ओवरसाइज़/ओवरवेट परमिट कौन सी एजेंसी जारी करती है?","options":["न्यू हैम्पशायर परिवहन विभाग (NHDOT)","संघीय राजमार्ग प्रशासन का क्षेत्रीय कार्यालय","पार किए गए प्रत्येक शहर का स्थानीय पुलिस विभाग","न्यू हैम्पशायर शराब आयोग"],"explanation":"न्यू हैम्पशायर में ओवरसाइज़ और ओवरवेट परमिट न्यू हैम्पशायर परिवहन विभाग (NHDOT) के परमिट कार्यालय द्वारा जारी किए जाते हैं; कानूनी आकार या भार से अधिक के लोड के लिए परमिट आवश्यक है और उनके मार्ग प्रतिबंधित हो सकते हैं। स्रोत: NH DOT oversize/overweight permit office।"},"77":{"q":"न्यू हैम्पशायर कानून के तहत, जब कोई स्कूल बस चल रही हो और उसके पीछे कितने या उससे अधिक वाहन हों तो परिस्थितियां अनुमति देने पर बस चालक को उन्हें गुजरने देने के लिए किनारे हो जाना चाहिए?","options":["5 या अधिक पीछे चलने वाले वाहन","3 या अधिक पीछे चलने वाले वाहन","10 या अधिक पीछे चलने वाले वाहन","2 या अधिक पीछे चलने वाले वाहन"],"explanation":"RSA 265:54 निर्देश देता है कि जब भी सड़क की परिस्थितियां और जगह अनुमति दें और चल रही स्कूल बस के पीछे चलने वाले वाहनों की संख्या 5 या अधिक हो, तो बस चालक को पीछे चलने वाले वाहनों को गुजरने देने के लिए किनारे हो जाना चाहिए। स्रोत: NH RSA 265:54।"},"78":{"q":"न्यू हैम्पशायर में, जब कोई चालक ऐसी ट्रांज़िट या मोटरकोच बस के पास पहुंचे जो यात्रियों को चढ़ाने या उतारने के लिए रुकी हो (और जो लाल फ्लैशर दिखा रही स्कूल बस नहीं है), तो उसे क्या करना चाहिए?","options":["गति धीमी करें और, यदि सार्वजनिक सुरक्षा के लिए आवश्यक हो, तो पूरी तरह रुक जाएं","पूरी गति से गुजरें क्योंकि केवल स्कूल बसों के लिए ही सावधानी आवश्यक है","परिस्थितियों की परवाह किए बिना कम से कम 100 feet पीछे रुकें","हॉर्न तीन बार बजाएं और बिना गति धीमी किए आगे बढ़ें"],"explanation":"RSA 265:55 के अनुसार यात्रियों को चढ़ाने या उतारने के लिए रुकी हुई बस, स्ट्रीटकार या अन्य यात्री वाहन के पास पहुंच रहे या उसे पार कर रहे चालक को गति धीमी करनी चाहिए और, यदि जनता की सुरक्षा के लिए आवश्यक हो, तो वाहन को पूरी तरह रोक देना चाहिए। स्रोत: NH RSA 265:55।"},"79":{"q":"एक CDL चालक न्यू हैम्पशायर के एक अविभाजित राजमार्ग पर लाल लाइट चमका रही रुकी हुई स्कूल बस से मिल रहा है। चालक यात्रा फिर से कब शुरू कर सकता है:","options":["जब बस फिर से चलना शुरू कर दे या चमकती लाल लाइट बंद हो जाएं","रुकने के बाद तीन सेकंड बीत जाने पर, लाइट की परवाह किए बिना","जब चालक यह समझे कि कोई बच्चा दिखाई नहीं दे रहा, भले ही लाइट अभी भी चमक रही हों","जब बस चालक हाथ हिलाए, भले ही लाल लाइट जलती रहें"],"explanation":"RSA 265:54 के तहत, अविभाजित सड़क पर स्कूल बस के लिए रुके चालक को तब तक रुके रहना चाहिए जब तक बस फिर से चलना शुरू न कर दे या चमकती लाल लाइट बंद न हो जाएं; पहले उल्लंघन पर $150 का जुर्माना साथ ही assessment और संभावित लाइसेंस निलंबन है। स्रोत: NH RSA 265:54।"},"80":{"q":"न्यू हैम्पशायर में वाणिज्यिक चालक लाइसेंस (CDL) कौन सी एजेंसी जारी करती है?","options":["न्यू हैम्पशायर मोटर वाहन प्रभाग (DMV)","संघीय मोटर वाहक सुरक्षा प्रशासन (FMCSA)","न्यू हैम्पशायर परिवहन विभाग (NHDOT)","न्यू हैम्पशायर राज्य पुलिस वाणिज्यिक ब्यूरो"],"explanation":"न्यू हैम्पशायर में, CDL न्यू हैम्पशायर मोटर वाहन प्रभाग (DMV) द्वारा जारी किए जाते हैं, जो संघीय FMCSA मानकों के तहत परीक्षण और लाइसेंसिंग का संचालन करता है। NHDOT सड़कों और ओवरसाइज़/ओवरवेट परमिट को संभालता है, लाइसेंसिंग को नहीं। स्रोत: NH DMV, Commercial Driver Licenses page।"},"81":{"q":"इससे पहले कि कोई न्यू हैम्पशायर आवेदक CDL स्किल्स (रोड) टेस्ट शेड्यूल कर सके, उसे कौन सा संघीय प्रशिक्षण पूरा करना होगा?","options":["किसी पंजीकृत प्रदाता से Entry-Level Driver Training (ELDT)","एक 160-घंटे का राज्य अप्रेंटिसशिप कार्यक्रम","NH DMV द्वारा अनुमोदित एक रक्षात्मक-ड्राइविंग पाठ्यक्रम","एक OSHA वाणिज्यिक-वाहन सुरक्षा प्रमाणन"],"explanation":"न्यू हैम्पशायर संघीय ELDT नियम का पालन करता है: आवेदकों को CDL स्किल्स टेस्ट शेड्यूल करने से पहले किसी FMCSA Training Provider Registry प्रदाता से Entry-Level Driver Training पूरा करना होगा। स्रोत: NH DMV, Commercial Driver Learner Permit page; 49 CFR Part 380।"},"82":{"q":"न्यू हैम्पशायर CLP जारी होने के बाद, CDL रोड (स्किल्स) टेस्ट शेड्यूल किए जाने से पहले धारक को कितने समय तक प्रतीक्षा करनी होगी?","options":["कम से कम 14 days","कम से कम 10 days","कम से कम 30 days","कम से कम 7 days"],"explanation":"न्यू हैम्पशायर संघीय 14-day होल्ड लागू करता है: ज्ञान परीक्षाएं पास करने और CLP जारी होने के बाद, रोड परीक्षा CLP जारी होने की तारीख से 14 days से पहले शेड्यूल नहीं की जा सकती। स्रोत: NH DMV, Commercial Driver Learner Permit page; 49 CFR 383.25।"},"83":{"q":"न्यू हैम्पशायर CDL स्किल्स टेस्ट तीन अलग-अलग भागों से मिलकर बनता है। कौन सा समूह इन्हें सही ढंग से सूचीबद्ध करता है?","options":["प्री-ट्रिप निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग","लिखित ज्ञान, दृष्टि जांच, और सड़क पर ड्राइविंग","प्री-ट्रिप निरीक्षण, एयर-ब्रेक प्रदर्शन, और रात में ड्राइविंग","कपलिंग/अनकपलिंग, बैकिंग, और एक लिखित एंडोर्समेंट परीक्षा"],"explanation":"न्यू हैम्पशायर CDL स्किल्स टेस्ट के तीन भाग होते हैं: प्री-ट्रिप (वाहन) निरीक्षण, बुनियादी वाहन नियंत्रण स्किल्स टेस्ट, और सड़क पर ड्राइविंग टेस्ट। ज्ञान और दृष्टि टेस्ट अलग पूर्वापेक्षाएं हैं, स्किल्स टेस्ट का हिस्सा नहीं। स्रोत: NH DMV, CDL Road Test page।"},"84":{"q":"न्यू हैम्पशायर के CDL आवेदकों के लिए स्व-प्रमाणन पर, चालक को वाणिज्यिक संचालन की कितनी श्रेणियों में से चुनना होगा?","options":["चार","दो","तीन","पांच"],"explanation":"न्यू हैम्पशायर CDL आवेदकों को चार श्रेणियों में से एक में स्व-प्रमाणित होना चाहिए: interstate non-excepted, interstate excepted, intrastate non-excepted, और intrastate excepted। स्रोत: NH DMV self-certification form DSMV 612।"},"85":{"q":"एक न्यू हैम्पशायर चालक 'interstate non-excepted' के रूप में स्व-प्रमाणित होता है। इस श्रेणी के लिए क्या आवश्यक है?","options":["फाइल पर एक वैध DOT Medical Examiner's Certificate","किसी भी प्रकार का कोई मेडिकल प्रमाणपत्र नहीं","केवल एक राज्य-जारी इंट्रास्टेट मेडिकल छूट","मेडिकल कार्ड के बजाय एक Transportation Worker Identification Credential"],"explanation":"Interstate non-excepted चालक गैर-अपवादित वाणिज्य में राज्य की सीमाओं के पार संचालन करते हैं और उन्हें एक वैध DOT Medical Examiner's Certificate रखना और फाइल पर बनाए रखना चाहिए। अपवादित (excepted) श्रेणियों के लिए मेडिकल कार्ड प्रदान करना आवश्यक नहीं है। स्रोत: NH DMV form DSMV 612; 49 CFR 383.71।"},"86":{"q":"कौन सा न्यू हैम्पशायर फॉर्म CDL धारकों द्वारा अपनी संचालन श्रेणी को स्व-प्रमाणित करने और DMV को मेडिकल-कार्ड जानकारी जमा करने के लिए उपयोग किया जाता है?","options":["DSMV 612","DSMV 312","MCSA-5876","DSMV 500"],"explanation":"न्यू हैम्पशायर CDL स्व-प्रमाणन के लिए और DMV को मेडिकल-कार्ड/प्रमाणन जानकारी जमा करने के लिए फॉर्म DSMV 612 का उपयोग करता है। DSMV 312 CDL आवेदन है; MCSA-5876 परीक्षक द्वारा पूरा किया जाने वाला संघीय Medical Examiner's Certificate है। स्रोत: NH DMV, CDL Medical Card Update; form DSMV 612।"},"87":{"q":"न्यू हैम्पशायर के सामान्य ज्ञान CDL लिखित टेस्ट पर, पास होने के लिए न्यूनतम आवश्यक स्कोर क्या है?","options":["80%","70%","75%","90%"],"explanation":"न्यू हैम्पशायर CDL सामान्य ज्ञान टेस्ट पर न्यूनतम 80% पासिंग स्कोर की आवश्यकता रखता है (50 में से 40 प्रश्न सही)। स्रोत: NH CDL Manual; NH DMV knowledge testing requirements।"},"88":{"q":"एक न्यू हैम्पशायर CDL जारी होने के बाद किस वर्ष में लाइसेंसधारी के जन्मदिन पर समाप्त होता है?","options":["पांचवें वर्ष","चौथे वर्ष","छठे वर्ष","दसवें वर्ष"],"explanation":"RSA 263:93 के तहत, एक न्यू हैम्पशायर वाणिज्यिक चालक लाइसेंस जारी होने के बाद पांचवें वर्ष में लाइसेंसधारी के जन्मदिन पर समाप्त होता है, जिससे यह पांच-वर्षीय नवीनीकरण चक्र बन जाता है। स्रोत: NH RSA 263:93 (License Expiration and Renewal)।"},"89":{"q":"इंट्रास्टेट (केवल राज्य के भीतर) ड्राइविंग के लिए न्यू हैम्पशायर CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 years old","16 years old","21 years old","19 years old"],"explanation":"इंट्रास्टेट ड्राइविंग के लिए न्यू हैम्पशायर CDL रखने हेतु आवेदक की आयु कम से कम 18 होनी चाहिए। 21 से कम आयु के चालक केवल इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: NH DMV, Commercial Driver Licenses page।"},"90":{"q":"इंटरस्टेट (राज्य की सीमाओं के पार) ड्राइविंग करने या न्यू हैम्पशायर CDL पर HAZMAT एंडोर्समेंट प्राप्त करने की न्यूनतम आयु क्या है?","options":["21 years old","18 years old","23 years old","25 years old"],"explanation":"एक न्यू हैम्पशायर CDL धारक की आयु इंटरस्टेट वाणिज्य में ड्राइविंग करने या HAZMAT एंडोर्समेंट रखने के लिए कम से कम 21 होनी चाहिए। 18-20 आयु के धारक केवल इंट्रास्टेट ड्राइविंग तक सीमित हैं। स्रोत: NH DMV, Commercial Driver Licenses page; 49 CFR 383।"},"91":{"q":"कौन सा फॉर्म स्वयं न्यू हैम्पशायर वाणिज्यिक चालक लाइसेंस आवेदन है?","options":["DSMV 312","DSMV 612","MCSA-5875","DSMV 426"],"explanation":"न्यू हैम्पशायर CDL आवेदन फॉर्म DSMV 312 है। DSMV 612 अलग स्व-प्रमाणन/मेडिकल-कार्ड फॉर्म है। स्रोत: NH DMV CDL forms; Apply for a CDL।"},"92":{"q":"ज्ञान और स्किल्स टेस्ट के अलावा, हर न्यू हैम्पशायर CDL आवेदक को कौन सी जांच पास करनी होगी?","options":["एक दृष्टि परीक्षा","एक लिखित प्राथमिक-चिकित्सा परीक्षा","DMV में किया जाने वाला एक नशा-और-शराब रक्त परीक्षण","एक शारीरिक चपलता बाधा कोर्स"],"explanation":"सभी न्यू हैम्पशायर CDL आवेदकों को ज्ञान और स्किल्स टेस्ट के अलावा एक दृष्टि परीक्षा पास करनी होगी। स्रोत: NH DMV, Commercial Driver Licenses page।"},"93":{"q":"न्यू हैम्पशायर CDL रोड टेस्ट के लिए, आवेदक को सामान्यतः किस प्रकार का टेस्ट वाहन प्रदान करना होगा?","options":["मांगे गए CDL के समान वर्ग/प्रकार का एक प्रतिनिधि वाहन, वैध निरीक्षण स्टिकर के साथ","वर्तमान पंजीकरण वाली कोई भी यात्री कार","NH DMV द्वारा निःशुल्क प्रदान किया गया एक वाहन","वर्ग की परवाह किए बिना 26,001 lbs GVWR से कम का एक किराए का वाहन"],"explanation":"आवेदक को मांगे जा रहे CDL के वर्ग/प्रकार से मेल खाता एक प्रतिनिधि टेस्ट वाहन प्रदान करना होगा, जो उचित रूप से पंजीकृत और बीमित हो और जिस पर एक वैध न्यू हैम्पशायर निरीक्षण स्टिकर लगा हो। स्रोत: NH DMV, CDL Road Test page।"},"94":{"q":"यदि किसी न्यू हैम्पशायर CDL धारक का मेडिकल प्रमाणन समाप्त हो जाता है और एक अद्यतन प्रमाणपत्र या वेरिएंस जमा नहीं किया जाता, तो DMV को कितने समय के भीतर CDL को डाउनग्रेड करना होगा?","options":["60 days","10 days","30 days","180 days"],"explanation":"न्यू हैम्पशायर जिस संघीय मेडिकल-प्रमाणन नियम को लागू करता है, उसके तहत यदि वर्तमान मेडिकल प्रमाणपत्र या वेरिएंस जमा नहीं किया जाता (या चालक अनुमत होने पर excepted/intrastate श्रेणी में बदल जाता है) तो राज्य को समाप्ति के 60 days के भीतर CDL या CLP को डाउनग्रेड करना होगा। स्रोत: 49 CFR 383.73; NH DMV CDL Medical Card Update।"},"95":{"q":"कौन सा न्यू हैम्पशायर CDL वर्ग 26,001 lbs या अधिक के GVWR वाले एकल वाहन को संचालित करने का अधिकार देता है (10,000 lbs से अधिक कुछ भी न खींचते हुए)?","options":["Class B","Class A","Class C","Class D"],"explanation":"एक Class B CDL 26,001 lbs या अधिक के GVWR वाले किसी भी एकल वाहन, या ऐसे वाहन को कवर करता है जो 10,000 lbs GVWR से अधिक की इकाई नहीं खींच रहा हो। Class A 26,001 lbs से अधिक के संयोजनों को कवर करता है जिनमें खींची जाने वाली इकाई 10,000 lbs से अधिक हो। स्रोत: NH DMV, License Classifications page।"},"96":{"q":"न्यू हैम्पशायर CDL पर HAZMAT एंडोर्समेंट के लिए आवेदन करने से पहले, आवेदक को कौन सा अतिरिक्त संघीय कदम पूरा करना होगा?","options":["फिंगरप्रिंट-आधारित पृष्ठभूमि जांच के साथ एक TSA सुरक्षा खतरा मूल्यांकन","एक 40-घंटे का OSHA खतरनाक-पदार्थ हैंडलिंग पाठ्यक्रम","एक EPA खतरनाक-अपशिष्ट परिवहनकर्ता पंजीकरण","एक टैंक वाहन में दूसरा सड़क-स्किल्स टेस्ट"],"explanation":"HAZMAT एंडोर्समेंट के आवेदकों को HAZMAT ज्ञान टेस्ट के अलावा एक TSA सुरक्षा खतरा मूल्यांकन पास करना होगा, जिसमें फिंगरप्रिंटिंग और पृष्ठभूमि जांच शामिल है। स्रोत: NH DMV, Commercial Driver Licenses page; 49 CFR Part 1572।"},"97":{"q":"न्यू हैम्पशायर जिस आधुनिकीकृत संघीय मेडिकल-प्रमाणन प्रक्रिया का पालन करता है (2025 से प्रभावी), उसके तहत अब अधिकांश Medical Examiner's Certificate परिणाम राज्य तक कैसे पहुंचते हैं?","options":["मेडिकल परीक्षक परिणाम इलेक्ट्रॉनिक रूप से FMCSA को भेजते हैं, जो उन्हें ड्राइविंग रिकॉर्ड अद्यतन करने के लिए राज्य को भेजता है","चालकों को हमेशा कागजी प्रमाणपत्र DMV कार्यालय में स्वयं पहुंचाना होगा","नियोक्ता चालक की ओर से प्रमाणपत्र सीधे FMCSA को डाक से भेजते हैं","प्रमाणपत्र केवल चालक के बीमा वाहक के पास दाखिल किए जाते हैं"],"explanation":"न्यू हैम्पशायर जिस June 23, 2025 से प्रभावी संघीय प्रक्रिया का पालन करता है, उसके तहत प्रमाणित मेडिकल परीक्षक परीक्षा परिणाम इलेक्ट्रॉनिक रूप से FMCSA को रिपोर्ट करते हैं, जो मेडिकल-प्रमाणन स्थिति को CDL रिकॉर्ड अद्यतन करने के लिए राज्य को भेजता है; चालकों को अभी भी अपनी संचालन श्रेणी स्व-प्रमाणित करनी होगी (जैसे, DSMV 612 के माध्यम से)। स्रोत: FMCSA Medical Certification rule; NH DMV CDL Medical Card Update।"},"98":{"q":"एक 19-वर्षीय व्यक्ति सभी न्यू हैम्पशायर CDL टेस्ट पास कर लेता है और CDL के लिए योग्य हो जाता है। कौन सा संचालन प्रतिबंध लागू होता है?","options":["वे 21 वर्ष की आयु तक इंट्रास्टेट (न्यू हैम्पशायर के भीतर) वाणिज्य तक सीमित हैं","वे इंटरस्टेट ड्राइविंग कर सकते हैं लेकिन यात्रियों को नहीं ले जा सकते","वे इंटरस्टेट ड्राइविंग केवल HAZMAT एंडोर्समेंट के साथ कर सकते हैं","टेस्ट पास करने के बाद कोई आयु-आधारित संचालन प्रतिबंध नहीं है"],"explanation":"एक न्यू हैम्पशायर CDL धारक जिसकी आयु कम से कम 18 लेकिन 21 से कम है, केवल इंट्रास्टेट ड्राइविंग तक सीमित है; इंटरस्टेट संचालन और HAZMAT के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: NH DMV, Commercial Driver Licenses page; 49 CFR 391.11।"}},"ar":{"0":{"q":"على طرقات نيو هامبشاير، ما هو الحد الأقصى لعرض المركبة، بما في ذلك حمولتها، قبل أن يصبح تصريح تجاوز الأبعاد مطلوباً؟","options":["96 inches","102 inches","108 inches","114 inches"],"explanation":"تحظر المادة RSA 266:12 في نيو هامبشاير قيادة أي مركبة يتجاوز عرضها بما في ذلك الحمولة 102 inches (8 feet 6 inches). ويتوافق هذا مع المعيار الفيدرالي للشبكة الوطنية. المصدر: NH RSA 266:12 العرض؛ دليل CDL في نيو هامبشاير."},"1":{"q":"ما هو الحد الأقصى للارتفاع، بما في ذلك الحمولة، لمركبة قياسية (لا تنقل مساكن مصنّعة) مسموح بها على طرقات نيو هامبشاير دون تصريح؟","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"explanation":"تنص المادة RSA 266:10 في نيو هامبشاير على أنه لا يجوز قيادة أي مركبة (باستثناء تلك التي تنقل مساكن مصنّعة أو مباني معيارية) يتجاوز ارتفاعها الإجمالي بما في ذلك الحمولة 13 feet 6 inches على طرقات الولاية. المصدر: NH RSA 266:10 الارتفاع."},"2":{"q":"في نيو هامبشاير، ما هو الحد الأقصى لطول نصف المقطورة في تركيبة شاحنة جرّار/نصف مقطورة تعمل دون تصريح؟","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"تسمح المادة RSA 266:11 في نيو هامبشاير بنصف مقطورة يصل طولها إلى 53 feet في تركيبة شاحنة جرّار ونصف مقطورة واحدة (المقطورات التي يزيد طولها عن 48 feet تخضع لمتطلبات إضافية تتعلق بمسمار الارتكاز والحماية الخلفية). المصدر: NH RSA 266:11 الطول."},"3":{"q":"بموجب قانون نيو هامبشاير، ما هو الحد الأقصى لوزن المركبة الإجمالي (بما في ذلك جميع هوامش التسامح لإنفاذ القانون) لمركبة مركّبة بخمسة محاور أو أكثر تعمل دون تصريح وزن زائد؟","options":["73,280 pounds","80,000 pounds","84,000 pounds","90,000 pounds"],"explanation":"تحدد نيو هامبشاير الحد الأقصى للوزن الإجمالي لتركيبة من خمسة محاور أو أكثر بـ 80,000 pounds بما في ذلك جميع هوامش التسامح لإنفاذ القانون، بما يتسق مع الحد الفيدرالي. المصدر: NH RSA 266:18 / 266:18-a."},"4":{"q":"ما هو الحد الأقصى لوزن المحور الواحد المسموح به على نظام الطرق السريعة بين الولايات والدفاعية في نيو هامبشاير دون تصريح؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"على نظام الطرق السريعة بين الولايات والدفاعية، تحدد المادة RSA 266:18 في نيو هامبشاير وزن المحور الواحد بـ 20,000 pounds، بما يتطابق مع المعيار الفيدرالي للطرق بين الولايات. (الأرقام الأعلى مثل 22,400 lb تنطبق فقط على بعض التكوينات خارج الطرق بين الولايات.) المصدر: NH RSA 266:18."},"5":{"q":"على نظام الطرق السريعة بين الولايات والدفاعية في نيو هامبشاير، ما هو الحد الأقصى للوزن المسموح به على المحور المزدوج؟","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"تحدد المادة RSA 266:18 في نيو هامبشاير وزن المحور المزدوج بـ 34,000 pounds على نظام الطرق السريعة بين الولايات والدفاعية، وهو نفس المعيار الفيدرالي. المصدر: NH RSA 266:18."},"6":{"q":"يستخدم إنفاذ قوانين الوزن الزائد في نيو هامبشاير صيغة لتوزيع الوزن تربط الوزن الإجمالي بتباعد المحاور وعدد المحاور. وتُعرف هذه الصيغة عموماً باسم:","options":["الصيغة الفيدرالية للجسور","صيغة تراجع مسمار الارتكاز","صيغة تصنيف الوزن المركّب الإجمالي","صيغة الوزن الفارغ"],"explanation":"تتبنى المادة RSA 266:18 في نيو هامبشاير الصيغة الفيدرالية للجسور W = 500[LN/(N-1) + 12N + 36]، حيث W هو الوزن الإجمالي على مجموعة من المحاور، و L هو المسافة بين المحورين الأقصيين، و N هو عدد المحاور. المصدر: NH RSA 266:18."},"7":{"q":"في صيغة الجسور لنيو هامبشاير W = 500[LN/(N-1) + 12N + 36]، ماذا يمثل المتغير 'N'؟","options":["عدد المحاور في المجموعة","الوزن الصافي للحمولة","عدد المقطورات","عرض الإطار الاسمي"],"explanation":"في صيغة الجسور التي تبنّتها نيو هامبشاير (RSA 266:18)، يساوي N عدد المحاور في المجموعة قيد النظر؛ و L هو المسافة بالأقدام بين المحورين الأقصيين، و W هو الوزن الإجمالي المسموح به الناتج. المصدر: NH RSA 266:18."},"8":{"q":"تركيبات الشاحنات ثلاثية المقطورات على طرقات نيو هامبشاير هي:","options":["مسموح بها على الطرق بين الولايات فقط","مسموح بها بتصريح سنوي","محظورة","مسموح بها ليلاً فقط"],"explanation":"تحظر المادة RSA 266:11-b في نيو هامبشاير تشغيل الشاحنات ثلاثية المقطورات على طرقات الولاية. المصدر: NH RSA 266:11-b حظر الشاحنات ثلاثية المقطورات."},"9":{"q":"يحتاج الناقل إلى نقل حمولة تتجاوز حدود الحجم أو الوزن القانونية في نيو هامبشاير. أي جهة تصدر تصريح الحجم الزائد/الوزن الزائد المطلوب؟","options":["مسؤول الطرق المحلي في البلدة","وزارة النقل في نيو هامبشاير","الإدارة الفيدرالية لسلامة الناقلين بالشاحنات","مكتب مأمور المقاطعة"],"explanation":"تصاريح الحجم الزائد/الوزن الزائد (OSOW) في نيو هامبشاير تصدرها وزارة النقل في نيو هامبشاير من خلال مكتب التصاريح التابع لها (تقدَّم الطلبات عبر الإنترنت، أو شخصياً في 7 Hazen Drive, Concord، أو عبر الهاتف). المصدر: تصاريح NHDOT / مكتب تصاريح OSOW."},"10":{"q":"يُسمح عادةً للحمولة ذات الحجم الزائد أو الوزن الزائد في نيو هامبشاير بالتنقل خلال أي ساعات؟","options":["24 ساعة في اليوم، أي يوم","من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها، من الاثنين إلى الجمعة","فقط بين 9:00 p.m. و 5:00 a.m. يومياً","في عطلات نهاية الأسبوع فقط، لتجنب حركة المرور في أوقات الذروة"],"explanation":"بموجب قواعد تصاريح OSOW الصادرة عن NHDOT، يُسمح عموماً للحمولات ذات الحجم الزائد/الوزن الزائد بالتنقل من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها، من الاثنين إلى الجمعة، مع عدم السماح بتنقل الحمولات ذات الأبعاد الزائدة في عطلات نهاية الأسبوع والعطلات الرسمية. المصدر: قيود التنقل في تصريح OSOW الصادر عن NHDOT."},"11":{"q":"ما هو الحد الأقصى للطول، بما في ذلك المصدّات الأمامية والخلفية، لمركبة أحادية الوحدة أو حافلة على طرقات نيو هامبشاير دون تصريح؟","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"تحدد المادة RSA 266:11 في نيو هامبشاير طول المركبة أحادية الوحدة أو الحافلة بـ 45 feet بما في ذلك المصدّات الأمامية والخلفية. المصدر: NH RSA 266:11 الطول."},"12":{"q":"عندما تنقل مركبة مساكن مصنّعة أو مباني معيارية في نيو هامبشاير، يكون الحد الأقصى المسموح به للارتفاع هو:","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"تسمح المادة RSA 266:10 في نيو هامبشاير بارتفاع أقصى قدره 14 feet 6 inches للمركبات التي تنقل مساكن مصنّعة أو مباني معيارية؛ والحمولات التي تتجاوز 13 feet 6 inches تتطلب مرافقة مدنية (غير شرطية). المصدر: NH RSA 266:10 الارتفاع."},"13":{"q":"على نظام الطرق السريعة العام (غير بين الولايات) في نيو هامبشاير، يمكن للمحور الواحد على مركبة أحادية الوحدة بثلاثة محاور أن يحمل بحد أقصى:","options":["18,000 pounds","20,000 pounds","22,400 pounds","25,000 pounds"],"explanation":"تسمح المادة RSA 266:18-a في نيو هامبشاير بحد أقصى 22,400 pounds لكل محور على المركبات أحادية الوحدة بثلاثة محاور (والمركبات الأخرى التي تبعد محاورها 10 feet أو أكثر) على نظام الطرق السريعة العام غير بين الولايات، وهو أعلى من حد 20,000 pounds للطرق بين الولايات. المصدر: NH RSA 266:18-a."},"14":{"q":"بالنسبة لتركيبة شاحنة جرّار ونصف مقطورة واحدة بأربعة محاور أو أكثر تحمل منتجات حرجية خام في نيو هامبشاير، يُرفع الحد الأقصى للوزن على المحور المزدوج إلى:","options":["34,000 pounds","36,000 pounds","40,000 pounds","44,000 pounds"],"explanation":"تسمح المادة RSA 266:18-b في نيو هامبشاير للمحور المزدوج بحمل ما يصل إلى 40,000 pounds لتركيبة شاحنة جرّار ونصف مقطورة واحدة من 4 محاور أو أكثر تحمل منتجات حرجية خام (جذوع أشجار ورقائق خشب غير معالجة). المصدر: NH RSA 266:18-b."},"15":{"q":"يخوّل قانون نيو هامبشاير ضباط الإنفاذ بالسماح بأي هامش تسامح عام فوق الحدود المعلنة لمجموعة المحاور والوزن الإجمالي قبل إصدار مخالفة؟","options":["1 percent","2 percent","5 percent","15 percent"],"explanation":"تخوّل المادتان RSA 266:18-a و 266:18-c في نيو هامبشاير هامش تسامح قدره 5 percent فوق حدود الوزن المعلنة (مع السماح بما يصل إلى 10 percent على بعض أوزان المحاور بموجب 266:18-c). المصدر: NH RSA 266:18-a / 266:18-c."},"16":{"q":"على نظام الطرق بين الولايات، يمكن لمجموعتين متتاليتين من المحاور المزدوجة في نيو هامبشاير أن تحمل كل منهما 34,000 pounds فقط إذا كانت المسافة بين المحورين الأول والأخير من تلك المجموعات المزدوجة لا تقل عن:","options":["28 feet","30 feet","36 feet","40 feet"],"explanation":"تسمح المادة RSA 266:18 في نيو هامبشاير لمجموعتين متتاليتين من المحاور المزدوجة بحمل 34,000 pounds لكل منهما فقط إذا كانت المسافة الكلية بين المحورين الأول والأخير 36 feet أو أكثر، وألا يتجاوز الوزن الإجمالي الكلي 80,000 pounds. المصدر: NH RSA 266:18."},"17":{"q":"على نظام الطرق السريعة العام غير بين الولايات في نيو هامبشاير، ما هو الحد الأقصى لوزن المحور المزدوج لتركيبة بخمسة محاور أو أكثر؟","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"تسمح المادة RSA 266:18-a في نيو هامبشاير للمحور المزدوج على تركيبة بخمسة محاور أو أكثر على نظام الطرق السريعة العام غير بين الولايات بحمل ما يصل إلى 36,000 pounds، وهو أعلى من حد المحور المزدوج البالغ 34,000 pounds للطرق بين الولايات. المصدر: NH RSA 266:18-a."},"18":{"q":"يرغب ناقل مقرّه في نيو هامبشاير في الحصول على تصريح سنوي للحجم الزائد للتنقل على مستوى الولاية لمركبة لا يزيد طولها عن 75 feet ولا عرضها عن 10 feet 6 inches ولا ارتفاعها عن 13 feet 6 inches. ما هي رسوم التصريح السنوي المعلنة للتنقل على مستوى الولاية؟","options":["$60.00","$115.00","$200.00","$300.00"],"explanation":"تدرج NHDOT رسوم تصريح الحجم الزائد السنوي بمبلغ $115.00 للتنقل على مستوى الولاية (أو $60.00 للتنقل ضمن نطاق 100-mile) للناقلين المقيمين والمسجلين في نيو هامبشاير، للمركبات ضمن الحدود المعلنة 75 ft / 10 ft 6 in / 13 ft 6 in. المصدر: رسوم تصريح OSOW الصادرة عن NHDOT."},"19":{"q":"بموجب المادة RSA 266:16 في نيو هامبشاير، تكون عقوبة المخالفة الأولى لتشغيل مركبة تتجاوز حدود الحجم المسموح بها غرامة قدرها:","options":["لا تزيد عن $100","لا تزيد عن $250","لا تزيد عن $500","لا تزيد عن $1,000"],"explanation":"تحدد المادة RSA 266:16 في نيو هامبشاير عقوبة تجاوز الحجم المسموح به بغرامة لا تزيد عن $100 للمخالفة الأولى ولا تزيد عن $250 للمخالفة اللاحقة ضمن السنة التقويمية نفسها. المصدر: NH RSA 266:16 عقوبة تجاوز الحجم المسموح به."},"20":{"q":"بموجب قواعد CDL في نيو هامبشاير، أي فئة رخصة مطلوبة لقيادة تركيبة من المركبات بتصنيف وزن مركّب إجمالي (GCWR) قدره 26,001 pounds أو أكثر، شريطة أن يكون للوحدة المقطورة تصنيف وزن إجمالي (GVWR) يزيد عن 10,000 pounds؟","options":["Class A","Class B","Class C","Class D"],"explanation":"تُعرّف نيو هامبشاير رخصة CDL من Class A بأنها أي تركيبة من المركبات بتصنيف GCWR قدره 26,001 lbs أو أكثر حيث يتجاوز تصنيف GVWR للوحدة المقطورة 10,000 lbs. المصدر: صفحة تصنيفات الرخص والقيود والتظهيرات في NH DMV؛ دليل السائق التجاري في نيو هامبشاير."},"21":{"q":"في نيو هامبشاير، أي فئة CDL تشمل أي مركبة واحدة بتصنيف GVWR قدره 26,001 pounds أو أكثر، أو مركبة كهذه تقطر وحدة لا تزيد عن 10,000 pounds GVWR؟","options":["Class A","Class B","Class C","Class M"],"explanation":"تُعرّف نيو هامبشاير رخصة CDL من Class B بأنها مركبة واحدة بتصنيف GVWR قدره 26,001 lbs أو أكثر، أو مركبة كهذه تقطر وحدة لا تزيد عن 10,000 lbs GVWR. المصدر: صفحة تصنيفات الرخص في NH DMV؛ دليل السائق التجاري في نيو هامبشاير."},"22":{"q":"يشغّل سائق في نيو هامبشاير مركبة واحدة وزنها أقل من 26,001 lbs مصممة لنقل 18 راكباً بما في ذلك السائق. أي فئة CDL يتطلبها هذا؟","options":["Class A","Class B","Class C","لا حاجة إلى CDL"],"explanation":"تُعرّف نيو هامبشاير رخصة CDL من Class C بأنها مركبة لا تستوفي شروط Class A أو B وتنقل 16 راكباً أو أكثر (بما في ذلك السائق)، أو مزودة بلوحات تحذيرية للمواد الخطرة، أو مركبة صهريجية. والمركبة التي تتسع لـ 18 راكباً تندرج تحت Class C. المصدر: صفحة تصنيفات الرخص في NH DMV."},"23":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في نيو هامبشاير مقيّدة بالتشغيل داخل الولاية (داخل نيو هامبشاير فقط)؟","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"في نيو هامبشاير يجب أن يكون عمرك 18 على الأقل لتشغيل مركبة آلية تجارية داخل الولاية (داخل نيو هامبشاير). المصدر: صفحة رخص السائقين التجاريين في NH DMV؛ دليل السائق التجاري في نيو هامبشاير."},"24":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في نيو هامبشاير صالحة للقيادة التجارية بين الولايات (عبر حدود الولايات)؟","options":["18 years old","19 years old","21 years old","23 years old"],"explanation":"تشترط نيو هامبشاير (متّبعةً المعيار الفيدرالي) أن يكون عمر السائقين 21 على الأقل لتشغيل مركبة آلية تجارية في التجارة بين الولايات. والسائقون من 18-20 مقيّدون بالتشغيل داخل الولاية. المصدر: صفحة رخص السائقين التجاريين في NH DMV."},"25":{"q":"بموجب قواعد نيو هامبشاير والقواعد الفيدرالية، كم يجب على المتقدم أن يحمل تصريح المتعلّم التجاري (CLP) قبل السماح له بإجراء اختبار مهارات CDL (اختبار الطريق)؟","options":["7 days","10 days","14 days","30 days"],"explanation":"يجب على المتقدم أن يحمل تصريح CLP لمدة 14 days على الأقل قبل إجراء اختبار مهارات CDL. وهذا متطلب فيدرالي تنفذه نيو هامبشاير. المصدر: صفحة تصريح المتعلّم للسائق التجاري في NH DMV؛ 49 CFR 383.25."},"26":{"q":"عندما يقود حامل تصريح المتعلّم للسائق التجاري في نيو هامبشاير مركبة آلية تجارية، من يجب أن يرافقه؟","options":["أي سائق مرخّص عمره 18 أو أكثر","شخص عمره 25 أو أكثر يحمل رخصة CDL صالحة لذلك النوع من المركبات، ويجلس مباشرة بجوار حامل التصريح","أي حامل CDL يجلس في أي مكان في المركبة","فاحص من NH DMV فقط"],"explanation":"تشترط نيو هامبشاير أن يكون حامل تصريح CLP مرافَقاً بشخص عمره 25 سنة أو أكثر يحمل رخصة CDL صالحة لنوع المركبة المقادة ويشغل المقعد الملاصق مباشرة لحامل التصريح. المصدر: صفحة تصريح المتعلّم للسائق التجاري في NH DMV."},"27":{"q":"أي رمز تظهير مطلوب على رخصة CDL في نيو هامبشاير لنقل المواد الخطرة بكميات تتطلب لوحات تحذيرية؟","options":["تظهير N","تظهير H","تظهير T","تظهير X"],"explanation":"يُشترط تظهير H (المواد الخطرة HazMat) لقيادة أي مركبة تجارية تنقل مواد خطرة يجب وضع لوحات تحذيرية لها بموجب اللوائح الولائية أو الفيدرالية. المصدر: صفحة تظهير HazMat في NH DMV."},"28":{"q":"قبل أن يُمنح سائق في نيو هامبشاير تظهير المواد الخطرة (H)، أي فحص إضافي مطلوب فيدرالياً؟","options":["تقييم تهديد أمني من إدارة أمن النقل TSA (فحص خلفية قائم على البصمات)","اختبار كشف الكذب من مكتب التحقيقات الفيدرالي FBI","مقابلة مع شرطة ولاية نيو هامبشاير","اختبار مخدرات DOT فقط"],"explanation":"يجب على المتقدمين لتظهير H اجتياز تقييم تهديد أمني من إدارة أمن النقل (TSA)، والذي يتضمن فحص خلفية قائماً على البصمات، بالإضافة إلى اختبار معرفة المواد الخطرة. المصدر: صفحة تظهير HazMat في NH DMV؛ 49 CFR 1572."},"29":{"q":"على رخصة CDL في نيو هامبشاير، أي تظهير مطلوب لتشغيل مركبة صهريجية (تُستخدم لنقل السوائل أو الغازات بكميات كبيرة)؟","options":["تظهير H","تظهير T","تظهير N","تظهير P"],"explanation":"يُشترط تظهير N (المركبة الصهريجية) لتشغيل مركبة صهريجية مصممة لنقل السوائل أو الغازات بكميات كبيرة. المصدر: صفحة تصنيفات الرخص والقيود والتظهيرات في NH DMV."},"30":{"q":"أي تظهير CDL في نيو هامبشاير مطلوب لسحب مقطورات مزدوجة أو ثلاثية؟","options":["تظهير T","تظهير N","تظهير D","تظهير X"],"explanation":"يُشترط تظهير T (المزدوجة/الثلاثية) لقطر مقطورات مزدوجة أو ثلاثية. ويُحصل عليه باجتياز اختبار معرفة؛ ولا يُشترط له اختبار مهارات منفصل. المصدر: صفحة تصنيفات الرخص في NH DMV؛ دليل السائق التجاري في نيو هامبشاير."},"31":{"q":"أي تظهير تشترطه نيو هامبشاير لقيادة مركبة تجارية مصممة لنقل 16 راكباً أو أكثر، بما في ذلك السائق؟","options":["تظهير S","تظهير P","تظهير N","تظهير T"],"explanation":"يُشترط تظهير P (الركاب) لقيادة أي مركبة تجارية مصممة لنقل 16 راكباً أو أكثر بما في ذلك السائق. المصدر: صفحة رخص السائقين التجاريين في NH DMV."},"32":{"q":"للحصول على تظهير الحافلة المدرسية (S) في نيو هامبشاير، ماذا يحتاج المتقدم عموماً أيضاً؟","options":["تظهير المواد الخطرة (H)","تظهير المركبة الصهريجية (N)","تظهير الركاب (P)","تظهير المزدوجة/الثلاثية (T)"],"explanation":"تنقل الحافلة المدرسية 16 شخصاً أو أكثر، لذا تشترط نيو هامبشاير تظهير الركاب (P) بالإضافة إلى اجتياز اختبار معرفة الحافلة المدرسية (S) واختبار مهارات الطريق لمركبة الركاب. المصدر: صفحة سائقي الحافلات المدرسية في NH DMV."},"33":{"q":"ما هو الحد الأدنى لدرجة النجاح التي تشترطها نيو هامبشاير في اختبار CDL التحريري للمعرفة العامة للتأهل للحصول على تصريح المتعلّم التجاري؟","options":["70%","75%","80%","90%"],"explanation":"تشترط نيو هامبشاير درجة 80% أو أعلى في اختبارات معرفة CDL، بما في ذلك اختبار المعرفة العامة. المصدر: صفحة تصريح المتعلّم للسائق التجاري في NH DMV؛ دليل السائق التجاري في نيو هامبشاير."},"34":{"q":"تدريب السائقين المبتدئين (ELDT) المأخوذ قبل بعض اختبارات مهارات/معرفة CDL في نيو هامبشاير يجب أن يُستكمل من خلال ماذا؟","options":["أي كلية مجتمع في نيو هامبشاير","مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA (TPR)","قسم التدريب الخاص بـ NH DMV","أي برنامج يديره صاحب عمل، دون حاجة إلى تسجيل"],"explanation":"يجب استكمال ELDT من خلال مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA (TPR)؛ ويقوم المزوّد بالمصادقة الذاتية وتقديم سجلات الإتمام إلى FMCSA. المصدر: ELDT / سجل مزوّدي التدريب التابع لـ FMCSA؛ صفحات CDL في NH DMV."},"35":{"q":"أي مما يلي يتطلب ELDT (تدريب السائقين المبتدئين) قبل أن يتمكن المتقدم في نيو هامبشاير من إجراء الاختبار المقابل؟","options":["إضافة تظهير المزدوجة/الثلاثية (T)","إضافة تظهير المركبة الصهريجية (N)","الحصول على رخصة CDL من Class A لأول مرة","تجديد رخصة CDL قائمة من Class B دون تغيير الفئة"],"explanation":"تنطبق قواعد ELDT الفيدرالية (السارية في Feb. 7, 2022) على الحصول على رخصة CDL من Class A أو B لأول مرة، وترقية Class B إلى Class A، والحصول على تظهير H أو P أو S لأول مرة. ولا تتطلب تظهيرات N و T والتجديدات البسيطة ELDT. المصدر: لوائح ELDT التابعة لـ FMCSA؛ صفحات CDL في NH DMV."},"36":{"q":"عند التقدم للحصول على رخصة CDL في نيو هامبشاير، أي فئة من فئات المصادقة الذاتية تشير إلى سائق يعمل عبر حدود الولايات ويجب أن يستوفي متطلب الشهادة الطبية الفيدرالية من DOT؟","options":["بين الولايات غير مستثنى","داخل الولاية مستثنى","بين الولايات مستثنى","داخل الولاية غير مستثنى"],"explanation":"تستخدم نيو هامبشاير فئات المصادقة الذاتية الفيدرالية الأربع. وتشمل فئة 'بين الولايات غير مستثنى' السائقين الذين يعملون عبر حدود الولايات والذين يجب أن يحملوا شهادة طبية صالحة من DOT مودعة في الملف. المصدر: صفحة تحديث البطاقة الطبية لـ CDL في NH DMV؛ 49 CFR 383.71."},"37":{"q":"للتقدم بطلب للحصول على رخصة CDL أو تصريح المتعلّم التجاري في نيو هامبشاير، يجب على المتقدم عموماً تقديم إثبات لأي مجموعة من المستندات؟","options":["الهوية فقط","الهوية ورقم الضمان الاجتماعي فقط","الهوية ورقم الضمان الاجتماعي والإقامة/الوجود القانوني في نيو هامبشاير","جواز سفر فقط، يغطي جميع المتطلبات"],"explanation":"تشترط نيو هامبشاير على المتقدمين إثبات الهوية، وتقديم مستند يبيّن رقم الضمان الاجتماعي، وتقديم مستندات تثبت الإقامة في نيو هامبشاير والوجود القانوني. المصدر: صفحات المستندات المطلوبة / تصريح المتعلّم للسائق التجاري في NH DMV."},"38":{"q":"كم تبلغ مدة صلاحية تصريح المتعلّم للسائق التجاري (CLP) في نيو هامبشاير قبل أن يجب تجديده؟","options":["30 days","60 days","180 days","365 days"],"explanation":"يكون تصريح CLP في نيو هامبشاير صالحاً لمدة 180 days ويمكن تجديده مرة واحدة، شريطة اجتياز اختبارات المعرفة المطلوبة خلال فترة سنة واحدة. ويتبع هذا معيار صلاحية CLP الفيدرالي. المصدر: صفحة تصريح المتعلّم للسائق التجاري في NH DMV؛ 49 CFR 383.25."},"39":{"q":"يرغب مقيم في نيو هامبشاير عمره 19 عاماً في الحصول على رخصة CDL. أي امتياز لا يكون مؤهلاً له حتى يبلغ 21 عاماً؟","options":["حمل رخصة CDL من Class B","التشغيل داخل الولاية ضمن نيو هامبشاير","الحصول على تظهير المواد الخطرة (H)","الحصول على تظهير المركبة الصهريجية (N)"],"explanation":"المتقدمون في نيو هامبشاير دون سن 21 مقيّدون بالتشغيل داخل الولاية ولا يمكنهم الحصول على تظهير المواد الخطرة (H) أو امتيازات الركاب للعمل بين الولايات؛ ويشترط تظهير H تحديداً أن يكون عمر المتقدم 21 على الأقل. المصدر: صفحات رخص السائقين التجاريين / تظهير HazMat في NH DMV."},"40":{"q":"في نيو هامبشاير، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده للشخص قانونياً تشغيل مركبة آلية تجارية (CMV)؟","options":["0.04","0.08","0.02","0.10"],"explanation":"تحدد نيو هامبشاير حد BAC لتشغيل مركبة CMV عند 0.04، أي نصف حد 0.08 للسائقين غير التجاريين. المصدر: دليل CDL في نيو هامبشاير (قسم الكحول/المخدرات)؛ RSA 265-A:2."},"41":{"q":"بقيادة مركبة آلية تجارية على طرق نيو هامبشاير، يُعتبر حامل رخصة CDL قانونياً قد فعل ماذا فيما يتعلق بالفحص الكيميائي للكحول أو المخدرات؟","options":["منح موافقة ضمنية للخضوع للفحص إذا طُلب منه ذلك بشكل قانوني","تنازل عن أي حق مستقبلي في رخصة CDL","وافق على دفع رسوم فحص ثابتة قدرها $500","وافق فقط على فحص النفَس وليس فحص الدم"],"explanation":"بموجب قانون الموافقة الضمنية في نيو هامبشاير، يُعتبر أي شخص يقود في الولاية قد وافق على الخضوع للفحص الكيميائي لتحديد تركيز الكحول عندما يُطلب منه ذلك بشكل قانوني. المصدر: RSA 265-A:4؛ دليل CDL في نيو هامبشاير."},"42":{"q":"بالنسبة لأول مخالفة كبرى (مثل القيادة تحت تأثير الكحول DUI في مركبة CMV)، ما هي الحد الأدنى لفترة إسقاط أهلية CDL في نيو هامبشاير؟","options":["1 year","60 days","6 months","3 years"],"explanation":"تؤدي أول مخالفة كبرى إلى إسقاط أهلية السائق لتشغيل مركبة CMV لمدة لا تقل عن سنة واحدة في نيو هامبشاير. المصدر: RSA 263:94؛ 49 CFR 383.51؛ دليل CDL في نيو هامبشاير."},"43":{"q":"إذا ارتكب سائق في نيو هامبشاير أول مخالفة كبرى أثناء تشغيل مركبة CMV مزودة بلوحات تحذيرية للمواد الخطرة، يكون الحد الأدنى لإسقاط الأهلية:","options":["3 years","1 year","120 days","مدى الحياة"],"explanation":"ترفع أول مخالفة كبرى تُرتكب أثناء نقل مواد خطرة مزودة بلوحات تحذيرية الحد الأدنى لإسقاط الأهلية من سنة واحدة إلى ثلاث سنوات. المصدر: RSA 263:94؛ 49 CFR 383.51."},"44":{"q":"ما هي فترة إسقاط الأهلية في نيو هامبشاير لثاني مخالفة كبرى (مثل ثاني قيادة تحت تأثير الكحول DUI في مركبة CMV) ناشئة عن حادثة منفصلة؟","options":["مدى الحياة","10 years","5 years","3 years"],"explanation":"تؤدي الإدانة الثانية بمخالفة كبرى من حادثة منفصلة إلى إسقاط الأهلية مدى الحياة لتشغيل مركبة CMV. المصدر: RSA 263:94؛ 49 CFR 383.51."},"45":{"q":"يرفض حامل رخصة CDL في نيو هامبشاير الخضوع للفحص الكيميائي أثناء تشغيل مركبة CMV. بالنسبة لأول رفض، يكون الحد الأدنى لإسقاط أهلية CDL:","options":["1 year","90 days","6 months","30 days"],"explanation":"يُعامل رفض فحص كيميائي مطلوب بشكل قانوني كمخالفة كبرى؛ ويحمل أول رفض حداً أدنى لإسقاط أهلية CDL قدره سنة واحدة (ثلاث سنوات إذا كانت المركبة مزودة بلوحات تحذيرية للمواد الخطرة). المصدر: RSA 263:94؛ RSA 265-A:4."},"46":{"q":"إذا رفض حامل رخصة CDL في نيو هامبشاير الفحص الكيميائي للمرة الثانية (حادثة منفصلة)، يكون إسقاط أهلية CDL:","options":["مدى الحياة","5 years","2 years","1 year"],"explanation":"تؤدي الحالة الثانية من رفض الفحص الكيميائي، كأي مخالفة كبرى ثانية، إلى إسقاط أهلية CDL مدى الحياة. المصدر: RSA 263:94؛ 49 CFR 383.51."},"47":{"q":"في نيو هامبشاير، تؤدي الإدانة بمخالفتين مروريتين جسيمتين في مركبة CMV ناشئتين عن حادثتين منفصلتين خلال 3 years إلى إسقاط أهلية CDL لمدة لا تقل عن:","options":["60 days","30 days","120 days","1 year"],"explanation":"تؤدي مخالفتان مروريتان جسيمتان خلال فترة 3 years إلى إسقاط أهلية السائق لتشغيل مركبة CMV لمدة لا تقل عن 60 days. المصدر: RSA 263:94؛ 49 CFR 383.51."},"48":{"q":"تؤدي الإدانة بثلاث مخالفات مرورية جسيمة في مركبة CMV من حوادث منفصلة خلال 3 years إلى إسقاط أهلية CDL في نيو هامبشاير لمدة لا تقل عن:","options":["120 days","60 days","90 days","1 year"],"explanation":"تؤدي ثلاث مخالفات مرورية جسيمة خلال فترة 3 years إلى إسقاط أهلية السائق لتشغيل مركبة CMV لمدة لا تقل عن 120 days. المصدر: RSA 263:94؛ 49 CFR 383.51."},"49":{"q":"بموجب قواعد CDL في نيو هامبشاير، عند أي سرعة فوق الحد المعلن تصبح مخالفة سرعة واحدة 'مخالفة مرورية جسيمة'؟","options":["15 mph أو أكثر فوق الحد","10 mph أو أكثر فوق الحد","20 mph أو أكثر فوق الحد","25 mph أو أكثر فوق الحد"],"explanation":"تُعرَّف القيادة بسرعة 15 mph أو أكثر فوق الحد المعلن بأنها مخالفة مرورية جسيمة لأغراض CDL في نيو هامبشاير. المصدر: RSA 259:98-a؛ N.H. Admin. Code Saf-C 1809.02."},"50":{"q":"أي مما يلي يُصنّف على أنه 'مخالفة مرورية جسيمة' لحامل رخصة CDL في نيو هامبشاير؟","options":["الاقتراب الشديد من المركبة الأمامية (القيادة اللصيقة)","الوقوف في ممر الحريق","القيادة بسرعة 5 mph فوق الحد","ملصق تسجيل منتهي الصلاحية"],"explanation":"الاقتراب الشديد من المركبة الأمامية هو إحدى المخالفات المرورية الجسيمة المحددة لحاملي رخص CDL، إلى جانب القيادة المتهورة وتغيير المسارات بشكل غير منتظم والإفراط في السرعة. المصدر: RSA 259:98-a؛ Saf-C 1809.02."},"51":{"q":"بالنسبة لأول إدانة بمخالفة عبور مزلقان السكة الحديدية مع الطريق أثناء تشغيل مركبة CMV في نيو هامبشاير، يكون الحد الأدنى لإسقاط الأهلية:","options":["60 days","30 days","120 days","1 year"],"explanation":"تحمل أول مخالفة عبور لمزلقان السكة الحديدية مع الطريق في مركبة CMV حداً أدنى لإسقاط الأهلية قدره 60 days. المصدر: 49 CFR 383.51 Table 3، المعتمد من نيو هامبشاير؛ دليل CDL في نيو هامبشاير."},"52":{"q":"تؤدي ثاني مخالفة عبور لمزلقان السكة الحديدية مع الطريق في مركبة CMV خلال 3 years إلى إسقاط أهلية CDL في نيو هامبشاير لمدة لا تقل عن:","options":["120 days","60 days","90 days","1 year"],"explanation":"تحمل ثاني مخالفة عبور للمزلقان خلال 3 years حداً أدنى لإسقاط الأهلية قدره 120 days. المصدر: 49 CFR 383.51 Table 3، المعتمد من نيو هامبشاير."},"53":{"q":"تؤدي ثالث مخالفة عبور لمزلقان السكة الحديدية مع الطريق أو ما بعدها في مركبة CMV خلال 3 years إلى إسقاط أهلية CDL في نيو هامبشاير لمدة لا تقل عن:","options":["1 year","120 days","180 days","60 days"],"explanation":"تحمل ثالث مخالفة عبور للمزلقان أو ما بعدها خلال 3 years حداً أدنى لإسقاط الأهلية قدره 1 year. المصدر: 49 CFR 383.51 Table 3، المعتمد من نيو هامبشاير."},"54":{"q":"في نيو هامبشاير، تؤدي أول مخالفة لقيادة مركبة CMV تحت أمر إيقاف عن الخدمة (OOS) (غير المواد الخطرة) إلى إسقاط الأهلية لمدة:","options":["لا تقل عن 180 days ولا تزيد عن 1 year","لا تقل عن 60 days ولا تزيد عن 120 days","لا تقل عن 30 days ولا تزيد عن 90 days","لا تقل عن 2 years ولا تزيد عن 5 years"],"explanation":"تؤدي أول مخالفة لأمر الإيقاف عن الخدمة إلى إسقاط أهلية السائق لمدة لا تقل عن 180 days ولا تزيد عن 1 year. المصدر: 49 CFR 383.51 Table 4، المعتمد من نيو هامبشاير؛ دليل CDL في نيو هامبشاير."},"55":{"q":"تؤدي ثاني مخالفة لأمر الإيقاف عن الخدمة (OOS) في مركبة CMV خلال 10 years إلى إسقاط الأهلية في نيو هامبشاير لمدة:","options":["لا تقل عن 2 years ولا تزيد عن 5 years","لا تقل عن 180 days ولا تزيد عن 1 year","لا تقل عن 1 year ولا تزيد عن 3 years","مدى الحياة"],"explanation":"تحمل ثاني مخالفة لأمر الإيقاف عن الخدمة خلال 10 years إسقاطاً للأهلية لمدة لا تقل عن 2 years ولا تزيد عن 5 years. المصدر: 49 CFR 383.51 Table 4، المعتمد من نيو هامبشاير."},"56":{"q":"يرتكب سائق ينقل مواد خطرة مزودة بلوحات تحذيرية أو يشغّل مركبة مصممة لـ 16+ راكباً أول مخالفة لأمر الإيقاف عن الخدمة في نيو هامبشاير. يكون إسقاط الأهلية:","options":["لا تقل عن 180 days ولا تزيد عن 2 years","لا تقل عن 180 days ولا تزيد عن 1 year","لا تقل عن 60 days ولا تزيد عن 120 days","لا تقل عن 3 years ولا تزيد عن 5 years"],"explanation":"تحمل أول مخالفة لأمر الإيقاف عن الخدمة أثناء نقل مواد خطرة مزودة بلوحات تحذيرية أو في مركبة بـ 16+ راكباً فترة مرتفعة لا تقل عن 180 days ولا تزيد عن 2 years. المصدر: 49 CFR 383.51 Table 4، المعتمد من نيو هامبشاير."},"57":{"q":"بموجب قانون استخدام اليدين الحرّتين في نيو هامبشاير، ما هي غرامة أول مخالفة لاستخدام جهاز إلكتروني محمول باليد أثناء القيادة؟","options":["$100","$50","$250","$500"],"explanation":"يفرض قانون استخدام اليدين الحرّتين في نيو هامبشاير غرامة قدرها $100 على المخالفة الأولى، و $250 على الثانية، و $500 على أي مخالفة لاحقة خلال 24 months. ويُحظر الاستخدام المحمول باليد على جميع السائقين، بما في ذلك مشغلي مركبات CMV. المصدر: RSA 265:79-c."},"58":{"q":"بموجب قانون استخدام اليدين الحرّتين في نيو هامبشاير (RSA 265:79-c)، ما هي غرامة المخالفة الثانية لاستخدام جهاز إلكتروني محمول باليد أثناء القيادة؟","options":["$250","$100","$500","$150"],"explanation":"تُفرض على المخالفة الثانية لقانون استخدام اليدين الحرّتين في نيو هامبشاير غرامة قدرها $250 (المخالفة الأولى $100 والمخالفة اللاحقة خلال 24 months هي $500). المصدر: RSA 265:79-c."},"59":{"q":"لحساب المخالفات الأولى واللاحقة المسقطة لأهلية CDL في نيو هامبشاير، تُحتسب الإدانات بناءً على أي قاعدة؟","options":["تُحتسب كل إدانة من حادثة منفصلة، سواء ارتُكبت في مركبة CMV أو في مركبة غير CMV","تُحتسب فقط الإدانات أثناء قيادة مركبة CMV","تُحتسب فقط الإدانات خلال الـ 12 شهراً الماضية","تُحتسب فقط الإدانات التي تؤدي إلى السجن"],"explanation":"لتحديد المخالفات المسقطة للأهلية الأولى واللاحقة، تُحتسب كل إدانة من حادثة منفصلة، سواء وقعت المخالفة في مركبة تجارية أو غير تجارية. المصدر: RSA 263:94؛ 49 CFR 383.51."},"60":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في نيو هامبشاير، ماذا يجب على سائق CDL أن يفعل عند الاقتراب من مركبة متوقفة على الكتف تعرض أضواء تحذير زرقاء أو حمراء أو كهرمانية؟","options":["تخفيض السرعة، وإذا كان ذلك عملياً، الانتقال إلى الجانب الآخر لإفساح مساحة واسعة للمركبة","الحفاظ على السرعة مع إطلاق البوق باستمرار أثناء المرور","التوقف توقفاً تاماً في مسار السير حتى تغادر المركبة","المتابعة بالسرعة المحددة لأن القانون ينطبق فقط على سيارات الشرطة"],"explanation":"يتطلب قانون \"أفسح الطريق\" في نيو هامبشاير (RSA 265:37-a) من السائق الحفاظ على سرعة مخفضة، وإذا كان ذلك عملياً، إفساح مساحة واسعة لأفراد السلامة العامة ولأي مركبة متوقفة تعرض أضواء طوارئ أو تحذير زرقاء أو حمراء أو كهرمانية، مع الانتقال خارج المسار المسدود عند توفر الأمان. المصدر: NH RSA 265:37-a؛ دليل NH CDL."},"61":{"q":"في نيو هامبشاير، قبل عبور سكة الحديد، يجب على مركبة تحمل مواد خطرة بلوحات تحذيرية أو حافلة مدرسية تقل أطفالاً أن تتوقف ضمن أي مسافة من أقرب قضيب؟","options":["ليس أقل من 15 قدماً ولا أكثر من 50 قدماً","ليس أقل من 5 أقدام ولا أكثر من 25 قدماً","ليس أقل من 25 قدماً ولا أكثر من 75 قدماً","ليس أقل من 50 قدماً ولا أكثر من 100 قدم"],"explanation":"يتطلب RSA 265:50 من سائقي الحافلات التي تقل ركاباً، والحافلات المدرسية التي تقل أطفالاً، والمركبات التي تحمل مواد متفجرة/خطرة التوقف ضمن 50 قدماً ولكن ليس أقل من 15 قدماً من أقرب قضيب، ثم النظر والإصغاء قبل المتابعة. المصدر: NH RSA 265:50؛ دليل NH CDL."},"62":{"q":"على طريق ذي مسارين في نيو هامبشاير، يجب على السائق الذي يقابل أو يتجاوز حافلة مدرسية متوقفة وأضواؤها الحمراء تومض أن يوقف المركبة على مسافة لا تقل عن كم من الحافلة؟","options":["على مسافة لا تقل عن 25 قدماً","على مسافة لا تقل عن 10 أقدام","على مسافة لا تقل عن 50 قدماً","على مسافة لا تقل عن 100 قدم"],"explanation":"يتطلب RSA 265:54 من السائق الذي يقابل أو يتجاوز حافلة مدرسية متوقفة تستقبل أو تنزل أطفالاً أن يتوقف على مسافة لا تقل عن 25 قدماً من الحافلة وأن يبقى متوقفاً حتى تستأنف الحافلة الحركة أو تتوقف الأضواء عن الوميض. المصدر: NH RSA 265:54."},"63":{"q":"على طريق سريع مقسوم بمسارات منفصلة في نيو هامبشاير، متى لا يكون على سائق CDL التوقف لحافلة مدرسية تقوم بتحميل أطفال؟","options":["عندما تكون الحافلة على النصف الآخر من الطريق المقسوم وتسير في الاتجاه المعاكس","أبداً — التوقف مطلوب دائماً لحافلة مدرسية بأضواء حمراء وامضة","فقط عندما يقود السائق شاحنة مستقيمة فارغة","كلما كان السائق يسير بسرعة أكبر من 45 ميلاً في الساعة"],"explanation":"ينص RSA 265:54 على أن السائق على طريق سريع مقسوم بمسارات منفصلة لا يلزمه التوقف عند مقابلة أو تجاوز حافلة مدرسية موجودة على النصف الآخر من الطريق المقسوم وتسير في الاتجاه المعاكس. أما على طريق غير مقسوم، فيجب على كل الاتجاهات التوقف. المصدر: NH RSA 265:54."},"64":{"q":"ما هو الحد الأقصى العام للسرعة على الطرق السريعة بين الولايات والطرق ذات الرسوم في نيو هامبشاير التي تكون طرقاً مقسومة بأربعة مسارات (خارج مقطع I-93 ذي الحد الأعلى)؟","options":["65 ميلاً في الساعة","55 ميلاً في الساعة","70 ميلاً في الساعة","75 ميلاً في الساعة"],"explanation":"يحدد RSA 265:60 حداً أقصى قدره 65 ميلاً في الساعة على نظام الطرق بين الولايات والطرق ذات الرسوم في وسط وشرق نيو هامبشاير حيث تكون طرقاً مقسومة بأربعة مسارات. تطبق نيو هامبشاير الحدود المحددة نفسها على الشاحنات كما على السيارات. المصدر: NH RSA 265:60."},"65":{"q":"على أي طريق في نيو هامبشاير يكون حد السرعة المحدد 70 ميلاً في الساعة، وهو الأعلى في الولاية؟","options":["I-93 من علامة الميل 45 إلى حدود فيرمونت","كامل طول I-95 (طريق Blue Star Turnpike ذي الرسوم)","طريق Spaulding Turnpike من بورتسموث إلى ميلتون","I-89 من كونكورد إلى حدود فيرمونت"],"explanation":"يحدد RSA 265:60 حد السرعة عند 70 ميلاً في الساعة على I-93 من علامة الميل 45 إلى حدود فيرمونت. وهذا هو أعلى حد محدد في نيو هامبشاير وينطبق على المركبات التجارية أيضاً. المصدر: NH RSA 265:60."},"66":{"q":"هل تحدد نيو هامبشاير حد سرعة أقل للشاحنات منه لسيارات الركاب على طرقها بين الولايات؟","options":["لا — يجب على الشاحنات الالتزام بالحد المحدد نفسه كجميع المركبات الأخرى","نعم — تقتصر الشاحنات على 55 ميلاً في الساعة حيث يمكن للسيارات السير بسرعة 65 ميلاً في الساعة","نعم — تقتصر الشاحنات على 60 ميلاً في الساعة على مستوى الولاية","نعم — تقتصر الشاحنات على 45 ميلاً في الساعة على جميع الطرق المقسومة"],"explanation":"يحدد قانون السرعة في نيو هامبشاير (RSA 265:60) حدوداً قصوى تنطبق على جميع المركبات ولا يضع حد سرعة منفصلاً أقل للشاحنات؛ تلتزم المركبات التجارية بالحدود المحددة نفسها كالسيارات. المصدر: NH RSA 265:60."},"67":{"q":"بموجب قانون نيو هامبشاير، ما المطلوب من شاحنة بطيئة الحركة على طريق متعدد المسارات فيما يتعلق بموضع المسار؟","options":["يجب أن تبقى في المسار الأيمن وألا تشغل المسار الأيسر باستمرار بطريقة تعيق حركة المرور","يجوز لها البقاء في المسار الأيسر إلى أجل غير مسمى طالما أنها تشير","يجب أن تستخدم المسار الأوسط فقط على أي طريق سريع بثلاثة مسارات","تُعفى من قواعد البقاء على اليمين بسبب حجمها"],"explanation":"يتطلب RSA 265:16 من المركبة التي تسير أبطأ من حركة المرور العادية البقاء في المسار الأيمن، ويحظر التشغيل المستمر في المسار الأيسر من طريق متعدد المسارات عندما يعيق ذلك انسيابية حركة المرور. المصدر: NH RSA 265:16."},"68":{"q":"تشترط نيو هامبشاير على كل شاحنة أو حافلة يزيد وزنها عن 10,000 رطل حمل أي نوع من أجهزة التحذير في حالات الطوارئ لاستخدامها عند التوقف على الطريق السريع؟","options":["ثلاثة أجهزة تحذير عاكسة ثنائية الاتجاه (مثلثات عاكسة)","فانوسان يعملان بالوقود السائل المشتعل","منارة وامضة واحدة تعمل بالبطارية","أربعة أعلام قماشية حمراء على أعمدة"],"explanation":"يتطلب RSA 265:113 من كل شاحنة أو حافلة أو جرار شاحنة يزيد وزنه الإجمالي عن 10,000 رطل حمل ثلاثة أجهزة تحذير عاكسة ثنائية الاتجاه معتمدة من المدير، بما يتوافق مع لوائح سلامة الناقلات الآلية الفيدرالية. المصدر: NH RSA 265:113؛ دليل NH CDL."},"69":{"q":"عندما تتوقف مركبة تجارية في نيو هامبشاير يزيد وزنها عن 10,000 رطل على طريق سريع ذي مسارين، أين يجب عموماً وضع أجهزة التحذير الثلاثة؟","options":["على بعد نحو 10 أقدام خلف المركبة، و100 قدم إلى الخلف، و100 قدم إلى الأمام","الثلاثة جميعها ضمن 10 أقدام من المصد الخلفي","واحد على بعد 25 قدماً أماماً واثنان على بعد 25 قدماً خلفاً","200 قدم أماماً، و200 قدم خلفاً، وواحد على السقف"],"explanation":"بموجب RSA 265:113، على طريق عادي ثنائي الاتجاه تُوضع الأجهزة على بعد نحو 10 أقدام من المركبة في جهة حركة المرور، و100 قدم إلى الخلف، و100 قدم إلى الأمام. وعلى طريق مقسوم أو أحادي الاتجاه يكون التباعد 10 و100 و200 قدم باتجاه حركة المرور المقتربة. المصدر: NH RSA 265:113؛ دليل NH CDL."},"70":{"q":"بعد التوقف عند معبر سكة حديد في نيو هامبشاير، ماذا يتطلب القانون من سائق حافلة أو مواد خطرة أثناء عبور القضبان فعلياً؟","options":["العبور بسرعة منخفضة (غيار منخفض) بما يكفي بحيث لا تكون هناك حاجة لتبديل الغيارات أثناء وجوده على القضبان","التسارع بقوة وتبديل الغيار للأعلى بسرعة لتجاوز القضبان بأسرع وقت","التحويل إلى الوضع المحايد والانزلاق عبر القضبان","تفعيل فرامل الانتظار لفترة وجيزة عند منتصف المعبر"],"explanation":"يوجه RSA 265:50 بأنه، بعد التوقف وعندما يكون من الآمن المتابعة، يجب على السائق العبور بغيار منخفض بحيث لا تكون هناك ضرورة لتبديل الغيارات أثناء العبور، ولا يجوز له تبديل الغيارات أثناء وجوده على القضبان. المصدر: NH RSA 265:50."},"71":{"q":"ما هو هيكل العقوبات في نيو هامبشاير لمخالفة أولى لعدم الالتزام بقانون \"أفسح الطريق\" (RSA 265:37-a)؟","options":["$75 بالإضافة إلى رسم الجزاء للمخالفة الأولى","$250 بالإضافة إلى تعليق الرخصة لمدة 30 يوماً للمخالفة الأولى","$500 بالإضافة إلى إلغاء أهلية CDL الإلزامي","تحذير خطي فقط للمخالفة الأولى"],"explanation":"بموجب RSA 265:37-a، تحمل المخالفة الأولى لقانون \"أفسح الطريق\" في نيو هامبشاير غرامة قدرها $75 بالإضافة إلى رسم الجزاء، ترتفع إلى $250 بالإضافة إلى الرسم لمخالفة لاحقة خلال 12 شهراً. المصدر: NH RSA 265:37-a."},"72":{"q":"بدون تصريح للحجم الزائد، ما هو الحد الأقصى القانوني لعرض مركبة تجارية على الطرق السريعة في نيو هامبشاير؟","options":["8 أقدام و6 بوصات","8 أقدام و0 بوصة","9 أقدام و0 بوصة","10 أقدام و6 بوصات"],"explanation":"تتبع نيو هامبشاير حد العرض القانوني الفيدرالي البالغ 8 أقدام و6 بوصات (102 inches)؛ وأي عرض يزيد عن ذلك يتطلب تصريح حجم زائد من NHDOT. المصدر: قواعد تصاريح الحجم/الوزن الزائد في NH DOT؛ إرشادات الناقلات الآلية في NH State Police Troop G."},"73":{"q":"بدون تصريح للوزن الزائد، ما هو الحد الأقصى القانوني للوزن الإجمالي لمركبة تجارية على الطرق السريعة في نيو هامبشاير؟","options":["80,000 رطل","73,280 رطلاً","90,000 رطل","100,000 رطل"],"explanation":"الحد الأقصى القانوني للوزن الإجمالي للمركبة في نيو هامبشاير هو 80,000 رطل على الطرق بين الولايات والطرق الأخرى على حد سواء؛ ويتطلب تجاوزه تصريح/شهادة وزن زائد عبر NHDOT. المصدر: قواعد تصاريح الحجم/الوزن الزائد في NH DOT؛ NH State Police Troop G."},"74":{"q":"بدون تصريح، ما هو الحد الأقصى القانوني لارتفاع مركبة تجارية على طرق نيو هامبشاير؟","options":["13 قدماً و6 بوصات","12 قدماً و6 بوصات","14 قدماً و0 بوصة","13 قدماً و0 بوصة"],"explanation":"الحد الأقصى القانوني لارتفاع المركبة في نيو هامبشاير هو 13 قدماً و6 بوصات على جميع أنواع الطرق؛ والحمولة الأطول تتطلب تصريح حجم زائد من NHDOT. المصدر: قواعد تصاريح الحجم/الوزن الزائد في NH DOT."},"75":{"q":"على جزء طريق Franconia Notch Parkway من I-93 في نيو هامبشاير، ما الذي يميزه للسائقين التجاريين مقارنة ببقية الطريق بين الولايات؟","options":["يضيق ليصبح مساراً واحداً في كل اتجاه بحد مخفض قدره 45 ميلاً في الساعة","يحتوي على مسار سريع مخصص للشاحنات فقط في كل اتجاه","يسمح بحد قدره 80 ميلاً في الساعة للشاحنات العابرة","يمنع جميع سيارات الركاب خلال ساعات النهار"],"explanation":"بُني مقطع طريق Franconia Notch Parkway من I-93 بموجب استثناء خاص لمعايير الطرق بين الولايات، وهو يضيق ليصبح مساراً واحداً في كل اتجاه بحد محدد قدره 45 ميلاً في الساعة، مما يتطلب حذراً إضافياً من المركبات التجارية على المنحدر. المصدر: NH DOT؛ صلاحية المنطقة المخفضة في NH RSA 265:60."},"76":{"q":"أي جهة تصدر تصاريح الحجم/الوزن الزائد للمركبات التجارية التي تتجاوز الحدود القانونية في نيو هامبشاير؟","options":["وزارة النقل في نيو هامبشاير (NHDOT)","المكتب الإقليمي للإدارة الفيدرالية للطرق السريعة","قسم الشرطة المحلي لكل بلدة يتم عبورها","لجنة المشروبات الكحولية في نيو هامبشاير"],"explanation":"تصدر تصاريح الحجم والوزن الزائد في نيو هامبشاير عن مكتب التصاريح في وزارة النقل بنيو هامبشاير (NHDOT)؛ والحمولات التي تتجاوز الحجم أو الوزن القانوني يجب أن تكون مصرحاً بها وقد تكون مقيدة المسار. المصدر: مكتب تصاريح الحجم/الوزن الزائد في NH DOT."},"77":{"q":"بموجب قانون نيو هامبشاير، عندما تكون حافلة مدرسية متحركة ويتبعها كم مركبة أو أكثر يجب على سائق الحافلة الانعطاف جانباً للسماح لها بالمرور عندما تسمح الظروف؟","options":["5 مركبات تابعة أو أكثر","3 مركبات تابعة أو أكثر","10 مركبات تابعة أو أكثر","مركبتان تابعتان أو أكثر"],"explanation":"يوجه RSA 265:54 بأنه كلما سمحت ظروف الطريق والمساحة، وكان عدد المركبات التي تتبع حافلة مدرسية متحركة 5 أو أكثر، يجب على سائق الحافلة الانعطاف جانباً للسماح للمركبات التابعة بالمرور. المصدر: NH RSA 265:54."},"78":{"q":"في نيو هامبشاير، ماذا يجب على السائق فعله عند الاقتراب من حافلة نقل عام أو حافلة سياحية توقفت لتحميل أو إنزال ركاب (وليست حافلة مدرسية تعرض أضواء حمراء وامضة)؟","options":["إبطاء السرعة، وإذا لزم الأمر لسلامة الجمهور، التوقف توقفاً تاماً","المرور بالسرعة الكاملة لأن الحافلات المدرسية فقط تتطلب الحذر","التوقف على بعد 100 قدم على الأقل بصرف النظر عن الظروف","إطلاق البوق ثلاث مرات والمتابعة دون إبطاء"],"explanation":"يتطلب RSA 265:55 من السائق الذي يقترب من حافلة أو ترام أو مركبة ركاب أخرى متوقفة لتحميل أو إنزال ركاب، أو يتجاوزها، أن يبطئ السرعة، وإذا لزم الأمر لسلامة الجمهور، أن يوقف المركبة توقفاً تاماً. المصدر: NH RSA 265:55."},"79":{"q":"سائق CDL يقابل حافلة مدرسية متوقفة وأضواؤها الحمراء تومض على طريق سريع غير مقسوم في نيو هامبشاير. يجوز للسائق استئناف السير عندما:","options":["تستأنف الحافلة الحركة أو تُطفأ الأضواء الحمراء الوامضة","تمر ثلاث ثوانٍ منذ التوقف، بصرف النظر عن الأضواء","يرى السائق أنه لا يوجد أطفال ظاهرون، حتى لو كانت الأضواء لا تزال تومض","يلوّح سائق الحافلة، رغم بقاء الأضواء الحمراء مضاءة"],"explanation":"بموجب RSA 265:54، يجب على السائق المتوقف لحافلة مدرسية على طريق غير مقسوم أن يبقى متوقفاً حتى تستأنف الحافلة الحركة أو تُطفأ الأضواء الحمراء الوامضة؛ المخالفة الأولى غرامتها $150 بالإضافة إلى الرسم مع احتمال تعليق الرخصة. المصدر: NH RSA 265:54."},"80":{"q":"أي جهة تصدر رخص القيادة التجارية (CDLs) في نيو هامبشاير؟","options":["قسم المركبات الآلية في نيو هامبشاير (DMV)","الإدارة الفيدرالية لسلامة الناقلات الآلية (FMCSA)","وزارة النقل في نيو هامبشاير (NHDOT)","المكتب التجاري لشرطة ولاية نيو هامبشاير"],"explanation":"في نيو هامبشاير، تُصدر رخص CDL عن قسم المركبات الآلية في نيو هامبشاير (DMV)، الذي يدير الاختبارات والترخيص بموجب معايير FMCSA الفيدرالية. تتولى NHDOT الطرق وتصاريح الحجم/الوزن الزائد، وليس الترخيص. المصدر: NH DMV، صفحة رخص القيادة التجارية."},"81":{"q":"قبل أن يتمكن مقدم الطلب في نيو هامبشاير من تحديد موعد اختبار مهارات CDL (اختبار الطريق)، ما التدريب الفيدرالي الذي يجب أن يكمله؟","options":["تدريب السائق المبتدئ (ELDT) من مزود مسجل","برنامج تدريب مهني للولاية مدته 160 ساعة","دورة قيادة دفاعية معتمدة من NH DMV","شهادة سلامة المركبات التجارية من OSHA"],"explanation":"تتبع نيو هامبشاير قاعدة ELDT الفيدرالية: يجب على مقدمي الطلبات إكمال تدريب السائق المبتدئ من مزود مدرج في سجل مزودي التدريب لدى FMCSA قبل أن يتمكنوا من تحديد موعد اختبار مهارات CDL. المصدر: NH DMV، صفحة تصريح متعلم القيادة التجارية؛ 49 CFR Part 380."},"82":{"q":"بعد إصدار تصريح CLP في نيو هامبشاير، كم يجب على حامله الانتظار قبل إمكانية تحديد موعد اختبار طريق (مهارات) CDL؟","options":["14 يوماً على الأقل","10 أيام على الأقل","30 يوماً على الأقل","7 أيام على الأقل"],"explanation":"تطبق نيو هامبشاير فترة الانتظار الفيدرالية البالغة 14 يوماً: بعد اجتياز اختبارات المعرفة وإصدار تصريح CLP، لا يمكن تحديد موعد اختبار الطريق قبل مرور 14 يوماً من تاريخ إصدار تصريح CLP. المصدر: NH DMV، صفحة تصريح متعلم القيادة التجارية؛ 49 CFR 383.25."},"83":{"q":"يتكون اختبار مهارات CDL في نيو هامبشاير من ثلاثة أجزاء منفصلة. أي مجموعة تسردها بشكل صحيح؟","options":["الفحص قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","اختبار المعرفة الكتابي، وفحص البصر، والقيادة على الطريق","الفحص قبل الرحلة، وعرض فرامل الهواء، والقيادة الليلية","الوصل/الفصل، والرجوع للخلف، واختبار تظهير كتابي"],"explanation":"يتكون اختبار مهارات CDL في نيو هامبشاير من ثلاثة أجزاء: الفحص (فحص المركبة) قبل الرحلة، واختبار مهارات التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. أما اختبارا المعرفة والبصر فهما متطلبان مسبقان منفصلان، وليسا جزءاً من اختبار المهارات. المصدر: NH DMV، صفحة اختبار طريق CDL."},"84":{"q":"في إقرار التصنيف الذاتي لمقدمي طلبات CDL في نيو هامبشاير، من كم فئة من فئات التشغيل التجاري يجب على السائق الاختيار؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"يجب على مقدمي طلبات CDL في نيو هامبشاير التصنيف الذاتي ضمن واحدة من أربع فئات: بين الولايات غير مستثناة، وبين الولايات مستثناة، وداخل الولاية غير مستثناة، وداخل الولاية مستثناة. المصدر: نموذج التصنيف الذاتي DSMV 612 لدى NH DMV."},"85":{"q":"صنّف سائق في نيو هامبشاير نفسه ذاتياً على أنه \"بين الولايات غير مستثنى\". ماذا تتطلب هذه الفئة؟","options":["شهادة فاحص طبي معتمد من DOT صالحة ومحفوظة في الملف","عدم وجود أي شهادة طبية على الإطلاق","إعفاء طبي داخل الولاية صادر عن الولاية فقط","بطاقة هوية عامل النقل (TWIC) بدلاً من البطاقة الطبية"],"explanation":"يقود السائقون من فئة \"بين الولايات غير مستثنى\" عبر حدود الولايات في تجارة غير مستثناة، ويجب أن يحملوا ويحفظوا في الملف شهادة فاحص طبي صالحة من DOT. الفئات المستثناة غير ملزمة بتقديم بطاقة طبية. المصدر: نموذج NH DMV DSMV 612؛ 49 CFR 383.71."},"86":{"q":"أي نموذج في نيو هامبشاير يستخدمه حاملو CDL للتصنيف الذاتي لفئة تشغيلهم وتقديم معلومات البطاقة الطبية إلى DMV؟","options":["DSMV 612","DSMV 312","MCSA-5876","DSMV 500"],"explanation":"تستخدم نيو هامبشاير النموذج DSMV 612 للتصنيف الذاتي لـ CDL ولتقديم معلومات البطاقة/الشهادة الطبية إلى DMV. أما DSMV 312 فهو طلب CDL؛ وMCSA-5876 هو شهادة الفاحص الطبي الفيدرالية التي يكملها الفاحص. المصدر: NH DMV، تحديث البطاقة الطبية لـ CDL؛ النموذج DSMV 612."},"87":{"q":"في اختبار المعرفة العامة الكتابي لـ CDL في نيو هامبشاير، ما هو الحد الأدنى للدرجة المطلوبة للنجاح؟","options":["80%","70%","75%","90%"],"explanation":"تشترط نيو هامبشاير حداً أدنى للنجاح قدره 80% في اختبار المعرفة العامة لـ CDL (40 من 50 سؤالاً بشكل صحيح). المصدر: دليل NH CDL؛ متطلبات اختبار المعرفة لدى NH DMV."},"88":{"q":"تنتهي صلاحية رخصة CDL في نيو هامبشاير في عيد ميلاد المرخّص له في أي سنة بعد الإصدار؟","options":["السنة الخامسة","السنة الرابعة","السنة السادسة","السنة العاشرة"],"explanation":"بموجب RSA 263:93، تنتهي صلاحية رخصة القيادة التجارية في نيو هامبشاير في تاريخ ميلاد المرخّص له في السنة الخامسة بعد الإصدار، مما يجعلها دورة تجديد مدتها خمس سنوات. المصدر: NH RSA 263:93 (انتهاء صلاحية الرخصة وتجديدها)."},"89":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في نيو هامبشاير للقيادة داخل الولاية (داخل الولاية فقط)؟","options":["18 عاماً","16 عاماً","21 عاماً","19 عاماً"],"explanation":"يجب أن يكون عمر مقدم الطلب 18 عاماً على الأقل لحمل رخصة CDL في نيو هامبشاير للقيادة داخل الولاية. ويقتصر السائقون دون سن 21 على التشغيل داخل الولاية فقط. المصدر: NH DMV، صفحة رخص القيادة التجارية."},"90":{"q":"ما هو الحد الأدنى للعمر للقيادة بين الولايات (عبر حدود الولايات) أو للحصول على تظهير HAZMAT على رخصة CDL في نيو هامبشاير؟","options":["21 عاماً","18 عاماً","23 عاماً","25 عاماً"],"explanation":"يجب أن يكون حامل رخصة CDL في نيو هامبشاير 21 عاماً على الأقل للقيادة في التجارة بين الولايات أو لحمل تظهير HAZMAT. ويقتصر الحاملون الذين تتراوح أعمارهم بين 18 و20 عاماً على القيادة داخل الولاية. المصدر: NH DMV، صفحة رخص القيادة التجارية؛ 49 CFR 383."},"91":{"q":"أي نموذج هو طلب رخصة القيادة التجارية في نيو هامبشاير نفسه؟","options":["DSMV 312","DSMV 612","MCSA-5875","DSMV 426"],"explanation":"طلب CDL في نيو هامبشاير هو النموذج DSMV 312. أما DSMV 612 فهو نموذج التصنيف الذاتي/البطاقة الطبية المنفصل. المصدر: نماذج CDL لدى NH DMV؛ التقدم بطلب للحصول على CDL."},"92":{"q":"إلى جانب اختباري المعرفة والمهارات، أي فحص يجب على كل مقدم طلب CDL في نيو هامبشاير اجتيازه؟","options":["فحص بصر","اختبار إسعافات أولية كتابي","اختبار دم للمخدرات والكحول يُجرى في DMV","مسار حواجز للياقة البدنية"],"explanation":"يجب على جميع مقدمي طلبات CDL في نيو هامبشاير اجتياز فحص بصر بالإضافة إلى اختباري المعرفة والمهارات. المصدر: NH DMV، صفحة رخص القيادة التجارية."},"93":{"q":"بالنسبة لاختبار طريق CDL في نيو هامبشاير، يجب على مقدم الطلب عموماً توفير أي نوع من مركبات الاختبار؟","options":["مركبة ممثلة من الفئة/النوع نفسه لرخصة CDL المطلوبة، مع ملصق فحص صالح","أي سيارة ركاب بتسجيل ساري المفعول","مركبة تقدمها NH DMV مجاناً","مركبة مستأجرة أقل من 26,001 رطل وزن إجمالي بصرف النظر عن الفئة"],"explanation":"يجب على مقدم الطلب توفير مركبة اختبار ممثلة تطابق فئة/نوع رخصة CDL المطلوبة، مسجلة ومؤمّنة بشكل صحيح وتعرض ملصق فحص نيو هامبشاير صالحاً. المصدر: NH DMV، صفحة اختبار طريق CDL."},"94":{"q":"إذا انتهت صلاحية الشهادة الطبية لحامل CDL في نيو هامبشاير ولم تُقدَّم شهادة محدثة أو إعفاء، يجب على DMV خفض درجة CDL خلال أي مدة؟","options":["60 يوماً","10 أيام","30 يوماً","180 يوماً"],"explanation":"بموجب القاعدة الفيدرالية للشهادة الطبية التي تطبقها نيو هامبشاير، يجب على الولاية خفض درجة رخصة CDL أو CLP خلال 60 يوماً من انتهاء الصلاحية إذا لم تُقدَّم شهادة طبية حالية أو إعفاء (أو لم يغيّر السائق إلى فئة مستثناة/داخل الولاية حيثما يُسمح بذلك). المصدر: 49 CFR 383.73؛ NH DMV تحديث البطاقة الطبية لـ CDL."},"95":{"q":"أي فئة CDL في نيو هامبشاير تخوّل تشغيل مركبة واحدة بوزن إجمالي 26,001 رطل أو أكثر (دون قطر ما يزيد عن 10,000 رطل)؟","options":["الفئة B","الفئة A","الفئة C","الفئة D"],"explanation":"تغطي رخصة CDL من الفئة B أي مركبة واحدة بوزن إجمالي 26,001 رطل أو أكثر، أو مركبة كهذه تقطر وحدة لا تزيد عن 10,000 رطل من الوزن الإجمالي. أما الفئة A فتغطي التركيبات التي تزيد عن 26,001 رطل مع وحدة مقطورة تزيد عن 10,000 رطل. المصدر: NH DMV، صفحة تصنيفات الرخص."},"96":{"q":"قبل التقدم بطلب للحصول على تظهير HAZMAT على رخصة CDL في نيو هامبشاير، ما الخطوة الفيدرالية الإضافية التي يجب على مقدم الطلب إكمالها؟","options":["تقييم تهديد أمني من TSA مع فحص خلفية مبني على البصمات","دورة مناولة مواد خطرة من OSHA مدتها 40 ساعة","تسجيل ناقل نفايات خطرة لدى EPA","اختبار مهارات ثانٍ على الطريق في مركبة صهريج"],"explanation":"يجب على مقدمي طلبات تظهير HAZMAT اجتياز تقييم تهديد أمني من TSA، يشمل أخذ البصمات وفحص الخلفية، بالإضافة إلى اختبار معرفة HAZMAT. المصدر: NH DMV، صفحة رخص القيادة التجارية؛ 49 CFR Part 1572."},"97":{"q":"بموجب العملية الفيدرالية المحدّثة للشهادة الطبية التي تتبعها نيو هامبشاير (سارية اعتباراً من 2025)، كيف تصل معظم نتائج شهادة الفاحص الطبي الآن إلى الولاية؟","options":["يرسل الفاحصون الطبيون النتائج إلكترونياً إلى FMCSA، التي ترسلها إلى الولاية لتحديث سجل القيادة","يجب على السائقين دائماً تسليم الشهادة الورقية يدوياً إلى مكتب DMV","يرسل أصحاب العمل الشهادات مباشرة إلى FMCSA نيابة عن السائق","تُحفظ الشهادات فقط لدى شركة تأمين السائق"],"explanation":"بموجب العملية الفيدرالية السارية اعتباراً من 23 يونيو 2025 التي تتبعها نيو هامبشاير، يبلّغ الفاحصون الطبيون المعتمدون نتائج الفحص إلكترونياً إلى FMCSA، التي تنقل حالة الشهادة الطبية إلى الولاية لتحديث سجل CDL؛ ولا يزال على السائقين التصنيف الذاتي لفئة تشغيلهم (مثلاً عبر DSMV 612). المصدر: قاعدة الشهادة الطبية لـ FMCSA؛ NH DMV تحديث البطاقة الطبية لـ CDL."},"98":{"q":"اجتاز شاب عمره 19 عاماً جميع اختبارات CDL في نيو هامبشاير وأصبح مؤهلاً لرخصة CDL. ما قيد التشغيل الذي ينطبق؟","options":["يقتصر على التجارة داخل الولاية (داخل نيو هامبشاير) حتى سن 21","يجوز له القيادة بين الولايات ولكن دون نقل ركاب","يجوز له القيادة بين الولايات فقط مع تظهير HAZMAT","لا يوجد قيد تشغيل قائم على العمر بمجرد اجتياز الاختبارات"],"explanation":"يقتصر حامل رخصة CDL في نيو هامبشاير الذي يبلغ من العمر 18 عاماً على الأقل ولكن دون 21 على القيادة داخل الولاية فقط؛ ويتطلب التشغيل بين الولايات وHAZMAT بلوغ سن 21. المصدر: NH DMV، صفحة رخص القيادة التجارية؛ 49 CFR 391.11."}}};
